// === docs/site/docs/data-and-logs/replay/lib/replay/dataMarks.js ===
// DataMark detection for OnSpeed SD logs.
//
// The DataMark CSV column is an integer 0..99 that wraps. Pilots
// bump it from the panel during flight to flag interesting moments
// ("nailed an OnSpeed approach", "stall warn just chirped", ...).
// Each bump is a transition in the column — we don't care about
// the absolute value, only the rising edge from the previous row's
// value to a new value.
//
// Returns an array of:
//   { rowIdx, logTimeMs, value, label }
//
// where label is a 1-based ordinal ("01", "02", ...) so the panel
// can show a stable identifier the pilot can talk about even after
// the absolute DataMark value wraps.

// DataMark per firmware (Switch.cpp:61) is `g_iDataMark = g_iDataMark + 1`,
// a monotonically-incrementing `int`. The M5 wire and panel display
// mod-100 (`%02d`) so two digits of room is fine on screen, but the
// underlying counter can go much higher on long flights. Cap at a
// generous integer ceiling to filter the misaligned-CSV signature
// (values like 8158, 17:55:19.87, 285.40 observed on the RV-4
// 2026-05-11 flight) without rejecting legitimate ≥ 100 presses.
// 9999 is a safe upper limit: well above any realistic press count,
// well below the torn-row values we've seen.
function isValidMark(v) {
  return Number.isInteger(v) && v >= 0 && v <= 9999;
}

// Firmware writes DataMark as a monotonically incrementing counter:
// 0 → 1 → 2 → 3 → ... Each pilot press bumps the column by one. The
// real-world write pattern observed on RV-4 2026-05-11:
//   0 (boot) → 1 (first press) → 2 → 3 → ... → 20 → ...
// with occasional resets to 0 after a long idle period (then the
// counter continues from where it left off, e.g. 0 → 20 → 21 → ...).
//
// Garbage rows from misaligned CSV either (a) hold a value outside
// [0..99] (filtered by isValidMark), or (b) hold a valid-by-luck
// integer but have ts = 0 / ts going backwards. The ts sanity check
// catches the second class.
//
// A "press" is a row where the column transitions from a smaller
// non-negative value to a strictly-larger one (1..99). The previous
// value can be 0 (cold start / re-arm) OR a smaller non-zero (the
// counter continuing). Resets (N → 0) and same-value rows are not
// presses.
//
// Reject chatter: the firmware occasionally writes brief single-row
// blips of "0" between two stable "N" runs (torn-row signature or
// per-frame write race). A real pilot press has the column stable
// at the prior value for at least PRIOR_VALUE_HOLD_MS before the
// transition, and the new value stable for at least NEW_VALUE_HOLD_MS
// after. Anything shorter is a flicker. On the RV-4 log, the real
// 0→20 press held 20 for 928 seconds; the noise ones held 2 seconds
// AFTER a previous-value-0 that lasted only ~10 ms.
const PRIOR_VALUE_HOLD_MS = 200;
const NEW_VALUE_HOLD_MS   = 200;

function findDataMarks(log) {
  if (!log || !log.DataMark || !log.timeStamp) return [];
  const N = log.Length;
  if (N < 2) return [];

  // Compress the (filtered) rows into runs of consecutive same-value
  // entries: [{ value, startTs, endTs, startRow }, ...]. Skips rows
  // with invalid DataMark or invalid timeStamp at parse boundary.
  // A run's "duration" is endTs - startTs.
  const runs = [];
  for (let i = 0; i < N; i++) {
    const v = log.DataMark[i];
    const ts = log.timeStamp[i];
    if (!isValidMark(v) || !Number.isFinite(ts) || ts <= 0) continue;
    const last = runs[runs.length - 1];
    if (last && last.value === v) {
      last.endTs = ts;
    } else {
      runs.push({ value: v, startTs: ts, endTs: ts, startRow: i });
    }
  }
  // A real press is a forward-going transition between two runs that
  // each persist long enough to be a true state — not single-row
  // blips. The 200ms thresholds are well above the firmware's log
  // cadence (5-50ms) and well below any real pilot's press interval.
  const out = [];
  for (let r = 1; r < runs.length; r++) {
    const cur  = runs[r];
    const prev = runs[r - 1];
    const isForward = cur.value > 0 && (prev.value === 0 || cur.value > prev.value);
    if (!isForward) continue;
    const prevHeld = prev.endTs - prev.startTs;
    const curHeld  = cur.endTs  - cur.startTs;
    if (prevHeld < PRIOR_VALUE_HOLD_MS) continue;
    if (curHeld  < NEW_VALUE_HOLD_MS)   continue;
    out.push({
      rowIdx:    cur.startRow,
      logTimeMs: cur.startTs,
      value:     cur.value,
      // `label` is what the panel shows. Always the firmware-written
      // DataMark value — same number the pilot saw on their device
      // and the same number the burned-in overlay renders. Multiple
      // panel rows may share the same value when the firmware counter
      // resets and the pilot bumps back to the same number minutes
      // later; distinguish them by their log/video times.
      label:     String(cur.value).padStart(2, '0'),
    });
  }
  // Sort by log time ascending. With the run-compression above the
  // output is already in time order; the explicit sort guards against
  // any future torn-row recovery that might re-introduce reordering.
  out.sort((a, b) => a.logTimeMs - b.logTimeMs);
  return out;
}

// Map a log timestamp (ms) to a video time (seconds) using the
// current sync. Returns null if sync is incomplete.
function logMsToVideoSec(logMs, sync) {
  if (!sync) return null;
  if (!Number.isFinite(sync.logTakeoffMs) || !Number.isFinite(sync.videoTakeoffSec)) return null;
  return sync.videoTakeoffSec + (logMs - sync.logTakeoffMs) / 1000;
}

// === docs/site/docs/data-and-logs/replay/lib/replay/journal.js ===
// journal.js — per-log annotation store for the replay tool.
//
// IDB store `journal-v1` keyed by the log's content hash (the same
// SHA-256-prefix-of-first-10KB digest persistence.js uses for sync +
// clip persistence). One record per log:
//
//   {
//     logHash:    string,
//     logName:    string,
//     videoName?: string,
//     lastUsed:   number,
//     marks: [{ value, logTimeMs, name?, notes?, createdAt, updatedAt }, ...],
//     clips: [{ id, startLogMs, endLogMs, label?, notes?, createdAt, updatedAt }, ...],
//   }
//
// Marks are addressed by the (value, logTimeMs) tuple via
// `markKey(value, logTimeMs) === value + ':' + logTimeMs`. The marks
// the parser surfaces are the source of truth for which keys exist;
// the journal layer only carries pilot-authored overlay fields.
//
// All operations are best-effort: caller errors are caught and logged
// to console, never propagated. Mirrors the storeHandles / loadHandles
// pattern in fileHandles.js.


const JOURNAL_DB_NAME = 'replay-journal';
const JOURNAL_STORE_NAME = 'journal-v1';
const JOURNAL_DB_VERSION = 1;

// ---------------------------------------------------------------------
// Pure helpers
// ---------------------------------------------------------------------

function markKey(value, logTimeMs) {
  return String(value) + ':' + String(logTimeMs);
}

// ---------------------------------------------------------------------
// IndexedDB plumbing — mirrors fileHandles.js's pattern.
// ---------------------------------------------------------------------

function _openJournalDbFresh() {
  return new Promise((resolve, reject) => {
    const req = indexedDB.open(JOURNAL_DB_NAME, JOURNAL_DB_VERSION);
    req.onupgradeneeded = () => {
      const db = req.result;
      if (!db.objectStoreNames.contains(JOURNAL_STORE_NAME)) {
        db.createObjectStore(JOURNAL_STORE_NAME, { keyPath: 'logHash' });
      }
    };
    req.onsuccess = () => resolve(req.result);
    req.onerror = () => reject(req.error || new Error('IDB open failed'));
  });
}

function _openJournalDb() {
  return new Promise((resolve, reject) => {
    if (typeof indexedDB === 'undefined') {
      reject(new Error('IndexedDB not available'));
      return;
    }
    _openJournalDbFresh().then(db => {
      // Defensive recovery: if the DB exists but the store doesn't
      // (a stale dev-build state from before this fix), nuke the DB
      // and recreate. The data we'd be wiping was never reachable
      // anyway — no upsert ever succeeded if the store was missing.
      if (db.objectStoreNames.contains(JOURNAL_STORE_NAME)) {
        resolve(db);
        return;
      }
      db.close();
      const del = indexedDB.deleteDatabase(JOURNAL_DB_NAME);
      del.onsuccess = () => _openJournalDbFresh().then(resolve, reject);
      del.onerror = () => reject(del.error || new Error('IDB delete failed'));
      del.onblocked = () => reject(new Error('IDB delete blocked — close other tabs'));
    }, reject);
  });
}

function _withJournalStore(mode, fn) {
  return _openJournalDb().then(db => new Promise((resolve, reject) => {
    let result;
    const tx = db.transaction(JOURNAL_STORE_NAME, mode);
    const store = tx.objectStore(JOURNAL_STORE_NAME);
    Promise.resolve(fn(store)).then(r => { result = r; }, reject);
    tx.oncomplete = () => { db.close(); resolve(result); };
    tx.onabort = () => { db.close(); reject(tx.error || new Error('IDB tx aborted')); };
    tx.onerror = () => { db.close(); reject(tx.error || new Error('IDB tx error')); };
  }));
}

// Variant of _withJournalStore for read-modify-write callbacks that must chain
// multiple IDB requests inside one transaction. The callback returns a
// Promise that resolves when ALL requests have settled — but it must
// chain those requests via IDB event callbacks (NOT `await`), because
// `await` allows a microtask to drain, which auto-commits the IDB
// transaction. See upsertMark / upsertClipAnnotation for the pattern.
function _withJournalStoreCallback(mode, fn) {
  return _openJournalDb().then(db => new Promise((resolve, reject) => {
    const tx = db.transaction(JOURNAL_STORE_NAME, mode);
    const store = tx.objectStore(JOURNAL_STORE_NAME);
    let callbackError = null;
    fn(store).then(() => {}, (err) => { callbackError = err; });
    tx.oncomplete = () => {
      db.close();
      if (callbackError) reject(callbackError);
      else resolve();
    };
    tx.onabort = () => { db.close(); reject(callbackError || tx.error || new Error('IDB tx aborted')); };
    tx.onerror = () => { db.close(); reject(callbackError || tx.error || new Error('IDB tx error')); };
  }));
}

function _journalReqToPromise(req) {
  return new Promise((resolve, reject) => {
    req.onsuccess = () => resolve(req.result);
    req.onerror = () => reject(req.error || new Error('IDB request failed'));
  });
}

function emptyRecord(logHash) {
  return {
    logHash,
    logName: '',
    lastUsed: Date.now(),
    marks: [],
    clips: [],
  };
}

// ---------------------------------------------------------------------
// Public API
// ---------------------------------------------------------------------

// Load the full journal record for a log hash. Returns null if none
// exists or IDB is unavailable.
async function loadJournal(logHash) {
  if (!logHash || typeof logHash !== 'string') return null;
  try {
    const record = await _withJournalStore('readonly', store =>
      _journalReqToPromise(store.get(logHash)));
    return record || null;
  } catch (err) {
    console.warn('journal: loadJournal failed', err);
    return null;
  }
}

// Upsert a mark by (value, logTimeMs). Patch is { name?, notes? };
// fields not present in patch are left unchanged. Creates the record
// + the mark row if either is missing.
//
// IDB-transaction note: the read-modify-write happens inside a single
// `readwrite` transaction. We must NOT `await` between the get's
// success and the put's request — IDB transactions auto-commit (and
// close) as soon as the microtask queue is empty between operations.
// Chaining via the get's onsuccess callback keeps the same transaction
// alive across both requests.
async function upsertMark(logHash, key, patch) {
  if (!logHash || !key || typeof key !== 'object') return;
  const { value, logTimeMs } = key;
  if (!Number.isFinite(value) || !Number.isFinite(logTimeMs)) return;
  const now = Date.now();
  try {
    await _withJournalStoreCallback('readwrite', (store) => new Promise((resolve, reject) => {
      const getReq = store.get(logHash);
      getReq.onerror = () => reject(getReq.error);
      getReq.onsuccess = () => {
        // Wrap the body so a synchronous throw (corrupt record shape,
        // unstructured-cloneable value, etc.) doesn't leak as an
        // unhandled exception while the transaction silently auto-
        // commits with no pending requests. The outer try/catch on the
        // await wouldn't see the throw without this — the Promise
        // would just never resolve or reject and tx.oncomplete would
        // fire with success.
        try {
          const existing = getReq.result;
          const record = existing || emptyRecord(logHash);
          record.lastUsed = now;
          if (!Array.isArray(record.marks)) record.marks = [];
          const target = markKey(value, logTimeMs);
          const idx = record.marks.findIndex(
            m => markKey(m.value, m.logTimeMs) === target);
          if (idx >= 0) {
            const prior = record.marks[idx];
            record.marks[idx] = {
              ...prior,
              ...patch,
              value, logTimeMs,
              updatedAt: now,
            };
          } else {
            record.marks.push({
              value, logTimeMs,
              ...patch,
              createdAt: now,
              updatedAt: now,
            });
          }
          const putReq = store.put(record);
          putReq.onerror = () => reject(putReq.error);
          putReq.onsuccess = () => resolve();
        } catch (err) {
          reject(err);
        }
      };
    }));
  } catch (err) {
    console.warn('journal: upsertMark failed', err);
  }
}

// Upsert a clip annotation by id. Patch is { label?, notes?,
// startLogMs?, endLogMs? }; missing fields are left unchanged. Creates
// the record + clip row if either is missing.
async function upsertClipAnnotation(logHash, id, patch) {
  if (!logHash || !id || typeof id !== 'string') return;
  const now = Date.now();
  try {
    await _withJournalStoreCallback('readwrite', (store) => new Promise((resolve, reject) => {
      const getReq = store.get(logHash);
      getReq.onerror = () => reject(getReq.error);
      getReq.onsuccess = () => {
        // See upsertMark for the rationale on this try/catch.
        try {
          const existing = getReq.result;
          const record = existing || emptyRecord(logHash);
          record.lastUsed = now;
          if (!Array.isArray(record.clips)) record.clips = [];
          const idx = record.clips.findIndex(c => c.id === id);
          if (idx >= 0) {
            record.clips[idx] = {
              ...record.clips[idx],
              ...patch,
              id,
              updatedAt: now,
            };
          } else {
            record.clips.push({
              id,
              ...patch,
              createdAt: now,
              updatedAt: now,
            });
          }
          const putReq = store.put(record);
          putReq.onerror = () => reject(putReq.error);
          putReq.onsuccess = () => resolve();
        } catch (err) {
          reject(err);
        }
      };
    }));
  } catch (err) {
    console.warn('journal: upsertClipAnnotation failed', err);
  }
}

// Return the mark-annotation overlay map keyed by `value:logTimeMs`,
// with payload `{ name, notes, updatedAt }`. Empty object if the
// record doesn't exist or has no marks.
async function loadMarkAnnotations(logHash) {
  const record = await loadJournal(logHash);
  if (!record || !Array.isArray(record.marks)) return {};
  const out = {};
  for (const m of record.marks) {
    if (!Number.isFinite(m.value) || !Number.isFinite(m.logTimeMs)) continue;
    out[markKey(m.value, m.logTimeMs)] = {
      name: m.name || '',
      notes: m.notes || '',
      updatedAt: m.updatedAt || 0,
    };
  }
  return out;
}

// Return the clip-annotation overlay map keyed by clip `id`, with
// payload `{ label, notes, updatedAt }`. Empty object if the record
// doesn't exist or has no clips. Mirrors loadMarkAnnotations.
async function loadClipAnnotations(logHash) {
  const record = await loadJournal(logHash);
  if (!record || !Array.isArray(record.clips)) return {};
  const out = {};
  for (const c of record.clips) {
    if (!c || typeof c.id !== 'string' || !c.id) continue;
    out[c.id] = {
      label: c.label || '',
      notes: c.notes || '',
      updatedAt: c.updatedAt || 0,
    };
  }
  return out;
}

// ---------------------------------------------------------------------
// Preact hook: useReplayJournal
//
// Watches the current log digest (computed externally — pass it in
// from useReplayPersistence). On hash change, loads the mark- and
// clip-annotation overlays into state. Returns
//   { markAnnotations, upsertMarkAnnotation,
//     clipAnnotations, upsertClipAnnotation }
// for the rest of the page to consume.
//
// The local-state mirror is what the UI renders. IDB writes happen in
// the background; the callbacks update local state synchronously so
// keystrokes feel instant.
// ---------------------------------------------------------------------

function useReplayJournal({ logHash }) {
  const [markAnnotations, setMarkAnnotations] = useState({});
  const [clipAnnotations, setClipAnnotations] = useState({});
  // Synchronous mirror of logHash so the updater callbacks write to
  // the correct record even when called between an IDB-load promise
  // resolving and Preact committing the new state.
  //
  // Known narrow race (deferred): if a pilot edits a mark's name, then
  // swaps logs before the 500ms debounce fires, AND the new log
  // happens to contain a mark with the same (value, logTimeMs) key,
  // the stale debounced write lands under the new log's record. The
  // unmount path on DataMarkPanel cancels the timer but doesn't flush
  // it. Real-world hit rate is vanishingly small (mark keys collide
  // across separate flights only by coincidence); proper fix is to
  // capture the logHash at edit-time into the debounce closure rather
  // than reading the ref at flush-time. Clip IDs are UUIDs so the
  // analogous collision is essentially impossible for clips.
  const logHashRef = useRef(null);

  useEffect(() => {
    logHashRef.current = logHash || null;
    setMarkAnnotations({});
    setClipAnnotations({});
    if (!logHash) return;
    let cancelled = false;
    loadMarkAnnotations(logHash).then(ann => {
      if (!cancelled) setMarkAnnotations(ann);
    });
    loadClipAnnotations(logHash).then(ann => {
      if (!cancelled) setClipAnnotations(ann);
    });
    return () => { cancelled = true; };
  }, [logHash]);

  const upsertMarkAnnotation = useCallback((mark, patch) => {
    const hash = logHashRef.current;
    if (!hash || !mark) return;
    const key = markKey(mark.value, mark.logTimeMs);
    setMarkAnnotations(prev => ({
      ...prev,
      [key]: {
        name:  patch.name  != null ? patch.name  : (prev[key]?.name  || ''),
        notes: patch.notes != null ? patch.notes : (prev[key]?.notes || ''),
        updatedAt: Date.now(),
      },
    }));
    upsertMark(hash, { value: mark.value, logTimeMs: mark.logTimeMs }, patch);
  }, []);

  const upsertClipAnnotationCb = useCallback((id, patch) => {
    const hash = logHashRef.current;
    if (!hash || !id || typeof id !== 'string') return;
    setClipAnnotations(prev => ({
      ...prev,
      [id]: {
        label: patch.label != null ? patch.label : (prev[id]?.label || ''),
        notes: patch.notes != null ? patch.notes : (prev[id]?.notes || ''),
        updatedAt: Date.now(),
      },
    }));
    upsertClipAnnotation(hash, id, patch);
  }, []);

  return {
    markAnnotations, upsertMarkAnnotation,
    clipAnnotations, upsertClipAnnotation: upsertClipAnnotationCb,
  };
}

// === docs/site/docs/data-and-logs/replay/lib/components/DataMarkPanel.js ===
// DataMarkPanel — the per-flight Data Marks list.
//
// Each row corresponds to one DataMark transition the parser found in
// the log. The pilot can:
//   - Jump the video to the mark
//   - Spin up a 30 s / 60 s clip starting at the mark
//   - Expand the row to add a name + notes (persisted to IDB via the
//     journal layer)
//
// The annotation overlay is supplied by `markAnnotations` (map keyed
// by `value:logTimeMs`) and patched via `upsertMarkAnnotation(mark,
// patch)`. The parent (ReplayPage) owns the journal hook; this
// component is dumb about persistence — it just emits patches.




// Debounce window for IDB writes: long enough that a normal typing
// burst flushes only once, short enough that a glance away and back
// finds the row saved.
const SAVE_DEBOUNCE_MS = 500;

const COLLAPSE_KEY = 'replay-marks-collapsed-v1';

function readCollapsed() {
  try { return localStorage.getItem(COLLAPSE_KEY) === '1'; }
  catch { return false; }
}
function writeCollapsed(v) {
  try { localStorage.setItem(COLLAPSE_KEY, v ? '1' : '0'); } catch {}
}

// First-N chars of notes to use as hover-tooltip preview when the row
// is collapsed. Mirrors a "first paragraph" feel without parsing.
const NOTES_PREVIEW_LEN = 80;

// Format a duration in seconds as H:MM:SS or M:SS. Duplicate of the
// helper in ReplayPage.js — small enough that keeping a local copy
// is cheaper than the import dance.
function formatHms(sec) {
  if (!Number.isFinite(sec)) return '—';
  const total = Math.floor(sec);
  const h = Math.floor(total / 3600);
  const m = Math.floor((total % 3600) / 60);
  const s = total % 60;
  if (h > 0) return `${h}:${String(m).padStart(2,'0')}:${String(s).padStart(2,'0')}`;
  return `${m}:${String(s).padStart(2,'0')}`;
}

function MarkRow({ mark, annotation, sync, disabled, videoDuration,
                   nextMark, onJump, onClip, onClipToNext, onPatch }) {
  const [expanded, setExpanded] = useState(false);
  // Local edit state: typed-but-not-yet-saved values. Reseeds from
  // the annotation overlay whenever the underlying overlay changes
  // (i.e. journal load on log swap).
  const [name,  setName]  = useState(annotation?.name  || '');
  const [notes, setNotes] = useState(annotation?.notes || '');
  const debounceRef = useRef(null);

  // Reseed local state when the overlay changes from outside (a fresh
  // log load, or a future cross-tab sync). Skip the reseed if the user
  // is mid-edit on this row — we don't want to clobber unsaved typing.
  useEffect(() => {
    setName(annotation?.name  || '');
    setNotes(annotation?.notes || '');
    // Intentional: only run when the underlying annotation row changes.
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [annotation?.updatedAt]);

  // Flush any pending debounce when the row collapses or unmounts so
  // the last keystroke never gets stuck in a timer.
  useEffect(() => () => {
    if (debounceRef.current) {
      clearTimeout(debounceRef.current);
      debounceRef.current = null;
    }
  }, []);

  const scheduleSave = (patch) => {
    if (debounceRef.current) clearTimeout(debounceRef.current);
    debounceRef.current = setTimeout(() => {
      debounceRef.current = null;
      onPatch(mark, patch);
    }, SAVE_DEBOUNCE_MS);
  };

  const flushNow = (patch) => {
    if (debounceRef.current) {
      clearTimeout(debounceRef.current);
      debounceRef.current = null;
    }
    onPatch(mark, patch);
  };

  const videoSec = logMsToVideoSec(mark.logTimeMs, sync);
  const dur = Number.isFinite(videoDuration) ? videoDuration : Infinity;
  const inRange = Number.isFinite(videoSec) &&
                  videoSec >= 0 && videoSec < dur;
  const tStr = inRange
    ? `video ${formatHms(videoSec)}`
    : (Number.isFinite(videoSec) ? 'outside video' : 'no sync');

  const hasNotes = !!(annotation && (annotation.name || annotation.notes));
  const notesPreview = annotation?.notes
    ? annotation.notes.slice(0, NOTES_PREVIEW_LEN) +
      (annotation.notes.length > NOTES_PREVIEW_LEN ? '…' : '')
    : '';
  const tooltip = notesPreview || (annotation?.name || '');

  const rowClass = 'replay-mark-row' +
    (hasNotes ? ' replay-mark-has-notes' : '') +
    (expanded ? ' is-expanded' : '');

  return html`
    <div class=${rowClass}>
      <div class="replay-mark-row-head"
           title=${tooltip}
           onClick=${() => setExpanded(e => !e)}>
        <span class="replay-mark-disclosure">${expanded ? '▾' : '▸'}</span>
        <span class="replay-mark-label">${mark.label}</span>
        ${hasNotes
          ? html`<span class="replay-mark-dot" aria-label="has notes">•</span>`
          : null}
        ${annotation?.name
          ? html`<span class="replay-mark-name">${annotation.name}</span>`
          : null}
        <span class="replay-mark-time">log ${formatHms(mark.logTimeMs / 1000)} · ${tStr}</span>
        <span class="replay-spacer"></span>
        <button class="replay-btn" disabled=${disabled || !inRange}
                onClick=${e => { e.stopPropagation(); onJump(mark.logTimeMs); }}>Jump</button>
        <button class="replay-btn" disabled=${disabled || !inRange}
                onClick=${e => { e.stopPropagation(); onClip(mark, 30); }}>Clip 30 s</button>
        <button class="replay-btn" disabled=${disabled || !inRange}
                onClick=${e => { e.stopPropagation(); onClip(mark, 60); }}>Clip 60 s</button>
        <button class="replay-btn"
                disabled=${disabled || !nextMark}
                title=${nextMark
                  ? `Clip from this mark to mark ${nextMark.label}`
                  : 'no next mark'}
                onClick=${e => { e.stopPropagation(); onClipToNext && onClipToNext(mark, nextMark); }}>
          Clip → next
        </button>
      </div>
      ${expanded && html`
        <div class="replay-mark-expanded">
          <label class="replay-mark-field">
            <span>Name</span>
            <input type="text"
                   value=${name}
                   placeholder="e.g. Slow flight at 65 kt"
                   onInput=${e => {
                     const v = e.target.value;
                     setName(v);
                     scheduleSave({ name: v });
                   }}
                   onBlur=${() => flushNow({ name })} />
          </label>
          <label class="replay-mark-field">
            <span>Notes</span>
            <textarea rows="3"
                      value=${notes}
                      placeholder="What happened, what to look for…"
                      onInput=${e => {
                        const v = e.target.value;
                        setNotes(v);
                        scheduleSave({ notes: v });
                      }}
                      onBlur=${() => flushNow({ notes })}></textarea>
          </label>
        </div>`}
    </div>`;
}

const DataMarkPanel = ({ marks, sync, disabled, videoDuration,
                                markAnnotations,
                                onJump, onClip, onClipToNext,
                                onPatchAnnotation }) => {
  if (!marks || marks.length === 0) return null;
  const [collapsed, setCollapsed] = useState(readCollapsed());
  const toggleCollapsed = () => {
    setCollapsed(c => { writeCollapsed(!c); return !c; });
  };
  return html`
    <div class="replay-marks${collapsed ? ' is-collapsed' : ''}">
      <div class="replay-marks-header replay-section-header"
           role="button"
           tabIndex="0"
           onClick=${toggleCollapsed}
           onKeyDown=${e => { if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); toggleCollapsed(); }}}
           title=${collapsed ? 'Expand data marks' : 'Collapse data marks'}>
        <span class="replay-section-disclosure">${collapsed ? '▸' : '▾'}</span>
        <span class="replay-label">Data marks</span>
        <span class="replay-status">${marks.length}</span>
      </div>
      ${collapsed ? null : html`
        <div class="replay-marks-list">
          ${marks.map((m, i) => html`<${MarkRow}
                key=${markKey(m.value, m.logTimeMs)}
                mark=${m}
                annotation=${markAnnotations ? markAnnotations[markKey(m.value, m.logTimeMs)] : null}
                sync=${sync}
                disabled=${disabled}
                videoDuration=${videoDuration}
                nextMark=${i + 1 < marks.length ? marks[i + 1] : null}
                onJump=${onJump}
                onClip=${onClip}
                onClipToNext=${onClipToNext}
                onPatch=${onPatchAnnotation} />`)}
        </div>`}
    </div>`;
};

// === docs/site/docs/data-and-logs/replay/lib/replay/parseLog.js ===
// CSV log parser for OnSpeed SD-card logs, plus WASM engine helpers.
//
// Pure-JS, no deps. Reads the header to find column ordinals by name
// (matches the C++ LogCsvHeaderIndex pattern), then streams rows into
// typed arrays. Returns parallel arrays so the indexer's per-frame
// lookup is a single bsearch + array indexing.
//
// Empty cells (format-version 3+ Dynon-style) parse to NaN for floats
// and -1 for ints (mirrors the wsClient null-handling convention).
//
// Also exports hasFlapsRawAdc() and detectLogSampleRate() used by
// LogReplayEngine.create() (see logReplay.js).

const FLOAT_COLUMNS = [
  'timeStamp',
  'IAS', 'AngleofAttack', 'OAT', 'TAS', 'Palt', 'PStatic',
  'VerticalG', 'LateralG', 'ForwardG',
  'RollRate', 'PitchRate', 'YawRate',
  'Pitch', 'Roll',
  'EarthVerticalG', 'FlightPath', 'VSI', 'Altitude',
  'DerivedAOA', 'CoeffP',
  // Pressure sensor columns — used by the WASM AOA calculator.
  'Pfwd', 'PfwdSmoothed', 'P45', 'P45Smoothed',
  // EFIS group (when present)
  'efisIAS', 'efisPitch', 'efisRoll', 'efisLateralG', 'efisVerticalG',
  'efisPalt', 'efisVSI', 'efisTAS', 'efisOAT',
];

const INT_COLUMNS = [
  'flapsPos', 'DataMark', 'efisPercentLift', 'flapsRawADC',
];

// Parse a CSV. Returns:
//   {
//     timeStamp:   Float64Array (ms),
//     IAS:         Float32Array,
//     AOA:         Float32Array,    // sourced from "AngleofAttack"
//     ...,
//     Length:      number (row count),
//     ColumnsSeen: Set<string>,
//   }
function parseLog(text) {
  const lines = text.split(/\r?\n/);
  if (lines.length < 2) throw new Error('CSV log: need at least a header + one row');

  const headers = lines[0].split(',').map(s => s.trim());
  const idx = {};
  for (let i = 0; i < headers.length; i++) idx[headers[i]] = i;

  // Allocate parallel arrays. We allocate to the row count and let
  // unparseable rows leave NaN behind — simpler than a two-pass count.
  const N = lines.length - 1;
  const out = {
    Length: 0,
    ColumnsSeen: new Set(headers),
    columns: headers,   // for hasFlapsRawAdc()
  };
  out.timeStamp = new Float64Array(N);
  for (const k of FLOAT_COLUMNS) {
    if (k === 'timeStamp') continue;
    if (k in idx) out[k] = new Float32Array(N);
  }
  for (const k of INT_COLUMNS) {
    if (k in idx) out[k] = new Int32Array(N);
  }

  // Convenience aliases used by the rest of the pipeline.
  if ('AngleofAttack' in idx) out.AOA = out.AngleofAttack;

  let row = 0;
  for (let r = 1; r < lines.length; r++) {
    const line = lines[r];
    if (!line) continue;
    const tokens = line.split(',');

    // Require pure-numeric syntax. `parseFloat("17:55:19.87")` returns
    // 17 silently, which means a misaligned CSV row where a time-of-
    // day cell slid into the timeStamp column would parse as a tiny
    // valid timestamp. The row would then sort with the very-early-
    // flight rows and contaminate downstream logic (DataMark panel,
    // sync detection, etc.). Skip the whole row instead.
    const tsTok = tokens[idx.timeStamp];
    if (tsTok == null || !/^-?\d+(?:\.\d+)?$/.test(tsTok)) continue;
    const t = parseFloat(tsTok);
    if (!Number.isFinite(t)) continue;       // skip malformed rows
    out.timeStamp[row] = t;

    for (const k of FLOAT_COLUMNS) {
      if (k === 'timeStamp') continue;
      if (!(k in idx) || !out[k]) continue;
      const tok = tokens[idx[k]];
      if (tok == null || tok === '') {
        out[k][row] = NaN;
      } else {
        const v = parseFloat(tok);
        out[k][row] = Number.isFinite(v) ? v : NaN;
      }
    }
    for (const k of INT_COLUMNS) {
      if (!(k in idx) || !out[k]) continue;
      const tok = tokens[idx[k]];
      if (tok == null || tok === '') {
        out[k][row] = -1;
      } else {
        // parseInt is too permissive: `parseInt("8158.00", 10) === 8158`
        // and `parseInt("17:55:19", 10) === 17`. Both let garbage rows
        // from misaligned CSV slip into int columns. Require the token
        // to be a pure non-negative integer literal (optional leading
        // `-` allowed).
        const intLike = /^-?\d+$/.test(tok);
        if (intLike) {
          const v = parseInt(tok, 10);
          out[k][row] = Number.isFinite(v) ? v : -1;
        } else {
          out[k][row] = -1;
        }
      }
    }
    row++;
  }

  out.Length = row;

  // Truncate any over-allocated tails so .length reflects rows seen.
  // (Float32Array has no resize; subarray() gives a view, not a copy.)
  if (row !== N) {
    out.timeStamp = out.timeStamp.subarray(0, row);
    for (const k of FLOAT_COLUMNS) {
      if (out[k]) out[k] = out[k].subarray(0, row);
    }
    for (const k of INT_COLUMNS) {
      if (out[k]) out[k] = out[k].subarray(0, row);
    }
    if (out.AOA) out.AOA = out.AOA.subarray(0, row);
  }

  return out;
}

// Binary-search the timestamp array for the row whose timestamp is
// closest to the requested time (in the same units as timeStamp[i],
// i.e. milliseconds since power-on).
//
// Returns the row index (0..Length-1) or -1 if the log is empty.
function findRowAt(log, tMs) {
  const ts = log.timeStamp;
  const n = log.Length;
  if (n === 0) return -1;
  if (tMs <= ts[0]) return 0;
  if (tMs >= ts[n - 1]) return n - 1;

  let lo = 0, hi = n - 1;
  while (hi - lo > 1) {
    const mid = (lo + hi) >> 1;
    if (ts[mid] <= tMs) lo = mid;
    else hi = mid;
  }
  // Pick the closer of lo and hi.
  return (tMs - ts[lo] < ts[hi] - tMs) ? lo : hi;
}

// ---------------------------------------------------------------------------
// hasFlapsRawAdc(parsedLog) -> boolean
//
// Returns true when the log CSV carries a raw flap-pot ADC column.
// Logs written before ~PR #372 don't have this column; without it the
// LogReplayEngine cannot reproduce the smooth L/Dmax pip interpolation
// across detent transitions.
//
// Works with the columnar format returned by parseLog() above:
// checks parsedLog.columns (the CSV header string[]).
// ---------------------------------------------------------------------------
function hasFlapsRawAdc(parsedLog) {
  if (!parsedLog || !Array.isArray(parsedLog.columns)) return false;
  return parsedLog.columns.some(
    c => c.toLowerCase() === 'flapsrawadc'
  );
}

// ---------------------------------------------------------------------------
// detectLogSampleRate(parsedLog) -> 50 | 208
//
// Infers the log's sample rate from the average inter-row timestamp delta.
// Returns 50 or 208; defaults to 50 for ambiguous or short logs.
//
// Works with the columnar format returned by parseLog() above:
// reads from parsedLog.timeStamp (Float64Array) and parsedLog.Length.
// ---------------------------------------------------------------------------
function detectLogSampleRate(parsedLog) {
  if (!parsedLog || !parsedLog.timeStamp || parsedLog.Length < 10) {
    return 50;  // fallback: not enough rows to measure
  }

  const ts = parsedLog.timeStamp;
  const t0 = ts[0];
  const t9 = ts[9];
  if (!Number.isFinite(t0) || !Number.isFinite(t9)) return 50;

  const avgDeltaMs = (t9 - t0) / 9;

  if (avgDeltaMs >= 15 && avgDeltaMs <= 25) return 50;
  if (avgDeltaMs >= 3  && avgDeltaMs <= 7)  return 208;
  return 50;  // unknown rate — default to 50
}

// === docs/site/docs/data-and-logs/replay/lib/replay/wasm_core.js ===
// wasm_core.js — single-loader for the onspeed_core WASM module.
//
// The module is loaded once on first call and cached for the lifetime of
// the page. All replay-tool algorithm files import getWasmCore() from
// here rather than loading the module themselves.
//
// The WASM artifact is built by:
//   bash software/Libraries/onspeed_core/wasm/build_wasm.sh
// and copied to docs/site/docs/assets/wasm/onspeed_core.js by the
// docs-site build hook (see docs/site/hooks/copy_wasm.py).
//
// Path is relative to this module file (lib/replay/wasm_core.js):
//   start  : data-and-logs/replay/lib/replay/wasm_core.js
//   target : assets/wasm/onspeed_core.js
// Go up four levels (lib/ → replay/ → data-and-logs/ → docs root),
// then down into assets/wasm/.
//
// Callers:
//   import { getWasmCore } from './wasm_core.js';
//   const w = await getWasmCore();

const WASM_MODULE_URL = '../../../../assets/wasm/onspeed_core.js';

let _module = null;
let _initPromise = null;

async function getWasmCore() {
    if (_module) return _module;
    if (!_initPromise) {
        _initPromise = (async () => {
            // Dynamic import with a path resolved against the importing
            // module (the lib/replay/ subdirectory). The replay app lives
            // at .../replay/index.html, so this resolves against
            // .../replay/lib/replay/wasm_core.js → up two to
            // .../replay/, then across to .../assets/wasm/.
            // (__replayBundleBase + "lib/replay/wasm_core.js") gives us the file URL; build the absolute
            // URL from there.
            const here = new URL((__replayBundleBase + "lib/replay/wasm_core.js"));
            const wasmUrl = new URL(WASM_MODULE_URL, here).href;
            const mod = await import(/* @vite-ignore */ wasmUrl);
            const factory = mod.default ?? mod;
            _module = await factory();
            return _module;
        })();
    }
    return _initPromise;
}




// === docs/site/docs/data-and-logs/replay/lib/replay/config.js ===
// config.js — thin WASM wrapper for OnSpeed config XML parsing.
//
// Pre-PLAN_WASM_CORE.md Step 1 this file contained a JS port of the C++
// config parser including the V1/V2 detection logic and the <3DAUDIO>
// regex rewrite needed because browsers' DOMParser rejects digit-prefixed
// tags.  It now delegates entirely to the WASM build of onspeed_core,
// so the Replay tool and the firmware parse configs with the exact same
// compiled code.
//
// The <3DAUDIO> → <_3DAUDIO> XML preprocessing trick is handled by
// ConfigV1Parse.cpp's string-search parser, which locates tags by text
// scan and therefore accepts the digit-prefixed tag names that are invalid
// XML.  The JS-side regex rewrite is no longer needed.
//
// Public API (unchanged from the hand-port — callers don't need to change):
//
//   parseConfigXml(xmlText) -> Promise<object>
//
// The returned object has the same field names as host_main's parse_config
// JSON output:
//   { aoaSmoothing, pressureSmoothing, muteUnderIas, dataSource,
//     volumeControl, defaultVolume, audio3D, overGWarning, efisType,
//     serialOutFormat, pitchBias, rollBias, gxBias, gyBias, gzBias,
//     pstaticBias, loadLimitPositive, loadLimitNegative, iAhrsAlgorithm,
//     sdLogging, boomConvertData, logRate, vno, acGrossWeight,
//     acBestGlideIAS, acVfe,
//     flaps: [{ degrees, potPosition, ldmaxAoa, onSpeedFastAoa,
//               onSpeedSlowAoa, stallWarnAoa, stallAoa, manAoa,
//               alpha0, alphaStall, kFit,
//               aoaCurve: { type, coeff: [a3, a2, a1, a0] } }, ...]
//   }
//
// aoaCurve is required for non-zero engine AOA. SuFlaps's default ctor
// leaves AoaCurve all-zero, so a hand-rolled cfg that omits aoaCurve
// will pin engine AOA to 0 — see bindings.cpp ConfigFromVal.
//
// On parse error, parseConfigXml throws ConfigParseError.


/**
 * Thrown when parse_config returns an error object rather than a valid config.
 * Callers must handle this — do not silently render empty UI on bad XML.
 */
class ConfigParseError extends Error {
    /**
     * @param {string} message - Human-readable error description.
     * @param {string} xmlSnippet - First 200 characters of the input for diagnostics.
     */
    constructor(message, xmlSnippet) {
        super(message);
        this.name = 'ConfigParseError';
        this.xmlSnippet = xmlSnippet;
    }
}

/**
 * Parse a V1 or V2 OnSpeed config XML string.
 *
 * Both V1 (<CONFIG> root) and V2 (<CONFIG2> root) formats are supported.
 * The C++ parser auto-detects the format via IsV1Format().
 *
 * @param {string} xmlText - Raw XML text from a .cfg file.
 * @returns {Promise<object>} Parsed config object with flaps array,
 *   alpha values, etc.
 * @throws {ConfigParseError} If the XML cannot be parsed.
 *
 * (Declared as `async function` then exported separately because
 * build_web_bundle.py's regex grammar does not recognize the inline
 * form `export async function`.)
 */
async function parseConfigXml(xmlText) {
    const w = await getWasmCore();
    const result = w.parse_config(xmlText);
    if (result && typeof result === 'object' && result.error) {
        throw new ConfigParseError(
            `Failed to parse OnSpeed config XML: ${result.error}`,
            xmlText.slice(0, 200)
        );
    }
    return result;
}




// === docs/site/docs/data-and-logs/replay/lib/replay/syncDetect.js ===
// Anchor auto-detection in an OnSpeed SD log.
//
// We need ONE clean tick the pilot can also spot in the video, so the
// video and log clocks line up. The auto-detect provides a good
// initial guess; the pilot fine-tunes via the nudge buttons or
// Pause/Attach.
//
// Detection target: **first rotation**. VSI-positive after IAS-alive —
// the unambiguous moment the wheels release. Happens within seconds of
// takeoff on every flight. Wide-spread enough to auto-detect reliably;
// close-enough-to-truth that nudging by a few seconds gets it dead-on.
//
// Returns a row index into the log, or -1 if no rotation found.

// Detect rotation via IAS+VSI heuristic.
//   1. Find the first row where IAS >= 30 kt (well above pitot deadband).
//   2. From there, scan forward for the first sustained VSI > 200 fpm
//      with VSI staying positive for at least 1 s.
//   3. Walk back to the row where IAS first crossed (liftoff IAS - 10) —
//      that's the rotation point.
function detectRotation(log) {
  const ts = log.timeStamp;
  const ias = log.IAS;
  const vsi = log.VSI;
  if (!ts || !ias || !vsi) return -1;

  const N = log.Length;
  if (N < 50) return -1;

  let i30 = -1;
  for (let i = 0; i < N; i++) {
    if (Number.isFinite(ias[i]) && ias[i] >= 30) { i30 = i; break; }
  }
  if (i30 < 0) return -1;

  const SUSTAIN_ROWS = 50;
  let sustained = 0;
  let liftoffRow = -1;
  for (let i = i30; i < N; i++) {
    if (Number.isFinite(vsi[i]) && vsi[i] > 200) {
      sustained++;
      if (sustained >= SUSTAIN_ROWS) {
        liftoffRow = i - sustained + 1;
        break;
      }
    } else {
      sustained = 0;
    }
  }
  if (liftoffRow < 0) return -1;

  const rotationIas = (ias[liftoffRow] || 0) - 10;
  let rotationRow = liftoffRow;
  for (let i = liftoffRow; i >= i30; i--) {
    if (Number.isFinite(ias[i]) && ias[i] < rotationIas) {
      rotationRow = i + 1;
      break;
    }
  }

  return rotationRow;
}

// Build a "downsampled-for-plotting" view of the log. For a 30-min
// flight at 50 Hz that's 90,000 rows — too many to plot directly.
// We bin-down to ~2000 points by taking every (Length / 2000)-th row.
// Returns parallel arrays of {tMs, iasKt, vsiFpm} sized to the
// downsample target.
function downsampleForPlot(log, targetPoints = 2000) {
  const N = log.Length;
  if (N <= targetPoints) {
    return {
      tMs:    Array.from(log.timeStamp.subarray(0, N)),
      iasKt:  log.IAS ? Array.from(log.IAS.subarray(0, N)) : new Array(N).fill(NaN),
      vsiFpm: log.VSI ? Array.from(log.VSI.subarray(0, N)) : new Array(N).fill(0),
    };
  }
  const step = Math.ceil(N / targetPoints);
  const out = { tMs: [], iasKt: [], vsiFpm: [] };
  for (let i = 0; i < N; i += step) {
    out.tMs.push(log.timeStamp[i]);
    out.iasKt.push(log.IAS  ? log.IAS[i]  : NaN);
    out.vsiFpm.push(log.VSI ? log.VSI[i] : 0);
  }
  return out;
}

