// === docs/site/docs/data-and-logs/replay/lib/replay/m5sim.js ===
// m5sim.js — JS wrapper around the M5-Display firmware compiled to WASM.
//
// PR 2 of Project B2. The WASM artifact is produced by:
//
//   bash software/OnSpeed-M5-Display/sim/build_wasm.sh --target replay
//
// and copied to tools/web/lib/replay/m5sim/onspeed_m5.{js,wasm} by the
// build script. This module loads it once per page and exposes a
// minimal JS surface:
//
//   const sim = await M5Sim.create();      // loads onspeed_m5.{js,wasm}
//   sim.advanceTo(virtualMillis);          // sets g_replay_millis_us
//   sim.injectBytes(uint8Array);           // pushes wire bytes through parser
//   sim.setMode(0..4);                     // writes displayType
//   const state = sim.read();              // frozen object with all state vars
//   sim.delete();                          // tear down (defensive; usually noop)
//
// Time semantics: `advanceTo` sets the virtual clock and immediately calls
// `replay_loop()` so the firmware's 50 ms graphics tick / 500 ms numbers
// snapshot fire at the right virtual time. Callers drive at video frame
// rate (~30-60 Hz); `replay_loop` is cheap (no panel blit on this build,
// per RenderShim.h's no-op stubs).
//
// `read()` returns a frozen object with every state-var accessor's
// current value plus a `gHistory` Float32Array. `gHistory` is a copy
// (HEAPF32.slice) rather than a live view: the firmware writes into the
// ring buffer on each `replay_loop()`, and a live view would mutate
// underneath any caller that holds it across frames. Pay the 300×4 byte
// copy per read to keep the read result immutable.

// ---------------------------------------------------------------------
// Internal: load the WASM module once.
//
// build_wasm.sh emits the module with `EXPORT_ES6=0` (CommonJS-style
// factory). The .js file declares `var Module = (...)` at top scope
// and assigns `module.exports = Module` for Node consumers. In a
// browser, neither happens automatically — `var Module` is window
// scope under <script>, but ES dynamic-import() of a non-module .js
// throws a SyntaxError.
//
// Browser path: append a <script> tag with the file URL, wait for it
// to load, then capture `globalThis.Module` (the var Module assigns).
// We snatch the factory immediately so a second load doesn't trip on
// a leftover global.
//
// Node path: the m5sim-smoke.mjs harness passes a factory it loaded
// via `require()` directly to M5Sim.fromFactory, bypassing this.
//
// SINGLE_FILE is NOT enabled on this artifact (the .wasm is separate),
// so the dev-server must also serve `onspeed_m5.wasm` next to the .js.
// Emscripten's `locateFile` resolves the .wasm path relative to the
// .js file's URL — pinning the script src to the dev-server route
// keeps both fetches against the same origin.
// ---------------------------------------------------------------------

// URL for onspeed_m5.js: served by MkDocs from
// docs/site/docs/assets/wasm/m5/onspeed_m5.js. The .js + .wasm live
// in a subdir alongside a package.json that pins CommonJS resolution
// — Emscripten emits with EXPORT_ES6=0 so Node-side createRequire
// loaders (e.g. the m5sim-smoke test) need a CJS-typed package
// boundary.
//
// This module file lives at data-and-logs/replay/lib/replay/m5sim.js
// (4 levels deep), so the shared assets/wasm/m5/ root is reached via
// four ".." segments + assets/wasm/m5/.
//
// Compute the URL against (__replayBundleBase + "lib/replay/m5sim.js") so the resolved href has
// the docs-site origin baked in — necessary because the loader
// injects a <script src=...> tag that must be an absolute URL or
// origin-relative path (script src does NOT resolve relative to the
// importing module the way ESM import() does).
const M5SIM_URL = new URL(
  '../../../../assets/wasm/m5/onspeed_m5.js', (__replayBundleBase + "lib/replay/m5sim.js")).href;

let _factoryPromise = null;

// Browser-only: inject a <script> tag, wait for load, return the
// factory captured from globalThis.Module.
function loadFactoryViaScriptTag(url) {
  return new Promise((resolve, reject) => {
    if (typeof document === 'undefined') {
      reject(new Error(
        'M5Sim: no document — call M5Sim.fromFactory(factory) directly ' +
        'in Node-side code.'));
      return;
    }
    const script = document.createElement('script');
    script.src = url;
    script.async = true;
    script.onload = () => {
      // Capture and clear the factory from the global.
      const factory = globalThis.Module;
      if (typeof factory !== 'function') {
        reject(new Error(
          `M5Sim: ${url} did not assign globalThis.Module to a factory ` +
          `(got ${typeof factory}). Was the build target wrong?`));
        return;
      }
      // Defensive: clear so a second load isn't shadowed by the
      // first. Emscripten reuses the global, so a second module
      // could otherwise inherit unrelated state.
      // Use assign-to-undefined rather than `delete` because some
      // Emscripten output sets Module as a non-configurable own
      // property on window, and `delete` throws in strict mode.
      try { globalThis.Module = undefined; } catch (_) { /* ignore */ }
      resolve(factory);
    };
    script.onerror = () => reject(new Error(
      `M5Sim: failed to load ${url} — was the docs-site build hook ` +
      `(docs/site/hooks/copy_wasm.py) run? It copies onspeed_m5.{js,wasm} ` +
      `from software/OnSpeed-M5-Display/sim/build/wasm-replay/ into ` +
      `docs/site/docs/assets/wasm/.`));
    document.head.appendChild(script);
  });
}

async function loadFactory() {
  if (_factoryPromise) return _factoryPromise;
  _factoryPromise = loadFactoryViaScriptTag(M5SIM_URL);
  return _factoryPromise;
}

// ---------------------------------------------------------------------
// M5Sim — wrapper class.
// ---------------------------------------------------------------------

class M5Sim {
  // Private; use M5Sim.create() / M5Sim.fromFactory() instead.
  constructor(module) {
    this._m = module;
    this._gHistoryPtr = module._replay_get_gHistory_ptr();
    // setup() ran inside the factory promise; the firmware is now in
    // its post-setup state (loopTime/numbersUpdateTime initialised at
    // virtual t=0).
  }

  /**
   * Default factory: load the WASM module from the dev-server's
   * `/lib/replay/m5sim/` URL. Browser path.
   *
   * @returns {Promise<M5Sim>}
   */
  static async create() {
    const factory = await loadFactory();
    return M5Sim.fromFactory(factory);
  }

  /**
   * Construct from an already-loaded Emscripten factory. Used by the
   * Node smoke test, which loads the factory via `require()` to avoid
   * dynamic-import's URL resolution semantics.
   *
   * @param {Function} factory The Emscripten module factory.
   * @returns {Promise<M5Sim>}
   */
  static async fromFactory(factory) {
    const Module = await factory();
    // Boot the firmware at virtual t=0 before returning. After
    // `replay_init()` runs, all state-var accessors return their
    // post-setup values; advanceTo / injectBytes proceed from there.
    Module._replay_set_time(0n);
    Module._replay_init();
    return new M5Sim(Module);
  }

  /**
   * Advance virtual time and run one firmware loop tick.
   *
   * The M5 firmware's `loop()` checks `millis()` against tracked
   * timestamps to fire 50 ms graphics ticks, 500 ms numbers
   * snapshots, and 200 ms gHistory samples. Drive `advanceTo` at the
   * caller's frame rate (typ. 30-60 Hz) — the firmware's internal
   * cadence handles down-sampling.
   *
   * @param {number} virtualMillis Wall-clock-equivalent virtual time
   *   in milliseconds since the firmware's t=0.
   */
  advanceTo(virtualMillis) {
    // Coerce to BigInt for the uint64 ABI. Floor first since the
    // firmware's millis() is integer.
    const m = BigInt(Math.max(0, Math.floor(virtualMillis)));
    this._m._replay_set_time(m);
    this._m._replay_loop();
  }

  /**
   * Push wire bytes through the firmware's `#1` parser. The parser
   * runs synchronously inside `_replay_inject_byte` — on the trailing
   * LF of a valid frame, all SerialRead globals (`PercentLift`,
   * `Slip`, `iVSI`, ...) update before the call returns.
   *
   * @param {Uint8Array} bytes
   */
  injectBytes(bytes) {
    if (!bytes || typeof bytes.length !== 'number') return;
    const inject = this._m._replay_inject_byte;
    for (let i = 0; i < bytes.length; i++) inject(bytes[i]);
  }

  /**
   * Set the active display mode (0..4). Out-of-range values are
   * clamped by the firmware-side accessor.
   *
   * @param {number} mode
   */
  setMode(mode) {
    this._m._replay_set_displayType(mode | 0);
  }

  /**
   * Read every exposed state var into a plain JS object.
   *
   * The returned object is frozen; mutate it and Object.freeze
   * complains. `gHistory` is a copy of the WASM heap (Float32Array
   * length 300) — safe to retain across frames.
   *
   * @returns {object}
   */
  read() {
    const m = this._m;
    // Float32 view of the gHistory ring. Slice so the caller can
    // hold onto it across `advanceTo` calls (which would otherwise
    // mutate it underneath them).
    const histStart = this._gHistoryPtr / 4;
    const gHistory = m.HEAPF32.slice(histStart, histStart + 300);

    const out = {
      // Always populated (every mode reads at least these).
      displayIAS:           m._replay_get_displayIAS(),
      displayPalt:          m._replay_get_displayPalt(),
      displayPitch:         m._replay_get_displayPitch(),
      displayVerticalG:     m._replay_get_displayVerticalG(),
      displayPercentLift:   m._replay_get_displayPercentLift(),
      displayDecelRate:     m._replay_get_displayDecelRate(),
      Slip:                 m._replay_get_Slip(),
      // Unclamped lateralG / verticalG floats — Slip is constrained
      // to ±99 (≈ ±0.116 g), so any rendering pipeline that wants to
      // smooth in continuous space must read these instead of
      // reconstructing from Slip.
      LateralG:             m._replay_get_LateralG(),
      VerticalG:            m._replay_get_VerticalG(),
      PercentLift:          m._replay_get_PercentLift(),
      gOnsetRate:           m._replay_get_gOnsetRate(),
      IAS:                  m._replay_get_IAS(),
      Palt:                 m._replay_get_Palt(),
      IasIsValid:           m._replay_get_IasIsValid() !== 0,
      displayType:          m._replay_get_displayType(),
      iVSI:                 m._replay_get_iVSI(),
      OAT:                  m._replay_get_OAT(),
      FlightPath:           m._replay_get_FlightPath(),
      Pitch:                m._replay_get_Pitch(),
      Roll:                 m._replay_get_Roll(),

      // Mode 0 / Mode 2 anchors.
      TonesOnPctLift:       m._replay_get_TonesOnPctLift(),
      OnSpeedFastPctLift:   m._replay_get_OnSpeedFastPctLift(),
      OnSpeedSlowPctLift:   m._replay_get_OnSpeedSlowPctLift(),
      StallWarnPctLift:     m._replay_get_StallWarnPctLift(),
      PipPctLift:           m._replay_get_PipPctLift(),
      FlapsMinDeg:          m._replay_get_FlapsMinDeg(),
      FlapsMaxDeg:          m._replay_get_FlapsMaxDeg(),
      FlapPos:              m._replay_get_FlapPos(),

      // Mode 4 (Historic G).
      gHistoryIndex:        m._replay_get_gHistoryIndex(),
      gHistory,

      // Spin / DataMark.
      SpinRecoveryCue:      m._replay_get_SpinRecoveryCue(),
      DataMark:             m._replay_get_DataMark(),
    };
    return Object.freeze(out);
  }

  /**
   * Tear down. Defensive: Emscripten WASM modules don't need explicit
   * teardown for our usage, but callers that load and unload sims
   * (e.g. tests) can call this to drop the reference.
   */
  delete() {
    this._m = null;
    this._gHistoryPtr = 0;
  }
}

// === docs/site/docs/data-and-logs/replay/lib/replay/presentationFilter.js ===
// presentationFilter.js — render-side smoothing for the replay tool's
// SVG mode renderers.
//
// Scope and intent
// ----------------
// What the airplane M5 actually shows in flight is
//   EMA(raw IMU @ 208 Hz, τ=76.5ms continuous-time)
// where the EMA RUNS at IMU rate. Each output sample is a weighted
// average over ~12 raw samples (~60 ms of integration).
//
// What a 50 Hz SD log captures is ONE raw IMU sample every 20 ms — so
// the log loses ~75% of the smoothing work the AHRS did in flight.
// Replay then runs a rate-adjusted 50 Hz EMA with the same continuous-
// time τ; mathematically this recovers the LOW-frequency content of
// the original signal but cannot recover the HIGH-frequency averaging
// that 208 Hz oversampling provided. Result: replay's slip ball is
// structurally NOISIER than what the pilot saw, even with the engine's
// AHRS-equivalent EMA active.
//
// Tuning: the right τ was found empirically by σ-matching against
// the airplane's primary EFIS (Dynon SkyView ADAHRS) over Sam's
// 286k-row RV-10 flight log. Method:
//   1. Take the engine's accelLatSmoothed (post-rate-adjusted-EMA).
//   2. Sweep τ from 0.1 s to 30 s through a presentation EMA.
//   3. Compute σ of the smoothed signal over the in-flight portion
//      of the log; find the τ that matches the EFIS reference σ.
// The EFIS slip indicator is what the pilot accepts as "the right
// reading," so its variance is the visual target. RMS error against
// the EFIS is a misleading metric here — it monotonically improves
// with longer τ because the bias-free RMS includes uncorrelated
// noise that any heavy-enough filter can suppress at the cost of
// also suppressing real slip information.
//
// Tuning script: tools/replay-tuning/tune_presentation_tau.mjs.
// Different aircraft / IMU mountings produce different vibration
// spectra and thus different best-τ values; the script can be re-run
// per aircraft to validate or re-tune.
//
// What this is NOT
// ----------------
// - Not part of the wire-bytes path. The C++ LogReplayTask emits
//   exactly what the firmware would emit. This filter runs AFTER
//   m5sim.read() returns the firmware's display state, before the
//   SVG renderer reads it.
// - Not "the smoothing the airplane had". The airplane has 208 Hz IMU
//   + 76.5 ms continuous-time τ AHRS EMA. This filter cannot reproduce
//   that from 50 Hz log data; it can only attenuate residual aliasing.
// - Not on by default. Users who care about firmware fidelity see what
//   the wire actually carried.
//
// Channels filtered
// -----------------
// - LateralG: drives the slip ball x-position. Aliasing here is the
//   most visually loud at OnSpeed's slip-ball gain (~850 px/g).
// - VerticalG: drives the corner-G readout and the historic-G mode.
//   The corner readout is already 2 Hz-rate-limited by the firmware's
//   numbersUpdateTime gate, so it doesn't need much extra damping.
//
// We don't filter PercentLift / pip / chevrons. Those derive from AOA,
// which goes through the engine's alpha-EMA already.

'use strict';

// Discrete EMA mapping a continuous-time τ at a known sample interval.
//
//   α = 1 − exp(−Δt / τ)
//
// Higher α = less smoothing. Δt is the rate the caller calls apply()
// at — for the replay's per-frame effect that's whatever videoT delta
// the browser produces (RAF-rate, ~60 Hz).
function alphaForTau(dtSec, tauSec) {
  if (!(dtSec > 0) || !(tauSec > 0)) return 1.0;
  return 1.0 - Math.exp(-dtSec / tauSec);
}

// PresentationFilter — stateful, per-render-session.
//
// Lifecycle:
//   const f = new PresentationFilter();
//   f.setTau({ lateralSec: 0.5, verticalSec: 0.5 });
//   ...per frame...
//   const smoothed = f.apply(state, dtSec);
//   // smoothed is { lateralG, verticalG } — render-ready
//   ...on backward scrub or τ change:
//   f.reset();
//
// τ values are settable at any time; α is recomputed lazily on the
// next apply() that observes a new dt. Use 0 to disable a channel.
class PresentationFilter {
  constructor() {
    this._tauLat  = 0.0;
    this._tauVert = 0.0;
    this._lat  = NaN;
    this._vert = NaN;
  }

  // Set both channel τ in seconds. Set 0 (or any non-positive) to
  // disable a channel — apply() then passes the input through as-is
  // for that field.
  setTau({ lateralSec, verticalSec }) {
    if (typeof lateralSec  === 'number') this._tauLat  = Math.max(0, lateralSec);
    if (typeof verticalSec === 'number') this._tauVert = Math.max(0, verticalSec);
  }

  // Reset filter state. Next apply() seeds with the input value.
  reset() {
    this._lat  = NaN;
    this._vert = NaN;
  }

  // Apply filter to the lateral/vertical G values from m5sim state.
  // Returns { lateralG, verticalG }; mutates internal state.
  //
  // dtSec: time since the previous apply() call. The replay's per-
  // frame effect knows this (videoT delta). Sub-millisecond ticks
  // pass through with α≈0 — caller can skip apply() in that case if
  // they prefer.
  apply(lateralG, verticalG, dtSec) {
    const aLat  = (this._tauLat  > 0) ? alphaForTau(dtSec, this._tauLat)  : 1.0;
    const aVert = (this._tauVert > 0) ? alphaForTau(dtSec, this._tauVert) : 1.0;

    let outLat = lateralG;
    if (Number.isFinite(lateralG)) {
      this._lat = Number.isNaN(this._lat)
        ? lateralG
        : aLat * lateralG + (1.0 - aLat) * this._lat;
      outLat = this._lat;
    }

    let outVert = verticalG;
    if (Number.isFinite(verticalG)) {
      this._vert = Number.isNaN(this._vert)
        ? verticalG
        : aVert * verticalG + (1.0 - aVert) * this._vert;
      outVert = this._vert;
    }

    return { lateralG: outLat, verticalG: outVert };
  }
}

// Preset τ values offered in the UI. Off is encoded as 0.
//
// The 'efis-match' default was tuned offline against Sam's Dynon-
// equipped RV-10 flight log via tools/replay-tuning/tune_presentation_tau.mjs.
// At 50 Hz log replay:
//   - lateral τ = 0.75 s brings σ from 0.043 g (engine direct) down to
//     0.024 g, matching Dynon ADAHRS's σ = 0.025 g over 4+ hours of
//     Sam's flight log.
//   - vertical τ = 0.1 s brings σ from 0.111 g to 0.095 g, matching
//     Dynon's 0.100 g.
// These are aircraft-specific (different IMU mounting / different
// vibration spectrum will shift the right τ); the presets cover a
// range so users can pick what looks right for their data.
//
// Slider semantics: the UI exposes a single lateral τ value the pilot
// dials in by eye against their own EFIS-display memory. Vertical-G
// smoothing is left at 0 (verticalGScaled10 already comes off the
// wire integer-quantized, so additional smoothing isn't observable
// at the M5 panel and risks false damping on the corner readout).
//
// Slider range 0..3.0 s. Reference points:
//   0.00  Off — byte-faithful, what the firmware/M5 actually computed.
//   0.25  Light — VN-300 territory; livelier ball.
//   0.75  Medium — Dynon SkyView σ-match (Sam's RV-10 reference).
//   3.00  Heavy — useful for cinematic exports, not faithful.
const PRESENTATION_LATERAL_TAU_MIN = 0;
const PRESENTATION_LATERAL_TAU_MAX = 3.0;
const PRESENTATION_LATERAL_TAU_STEP = 0.05;

// Default lateral τ chosen at log load. Sub-200 Hz logs (Dynon at 50 Hz)
// inherit a Dynon-shaped default; 208 Hz logs default to 0 (off) since
// the firmware-rate AHRS EMA already runs at ~76 ms internally.
function defaultLateralTauForLogRate(logSampleRateHz) {
  return (logSampleRateHz >= 200) ? 0 : 0.75;
}

// === docs/site/docs/data-and-logs/replay/lib/replay/chapters.js ===
// chapters.js — GoPro multi-chapter ingest for the replay tool.
//
// GoPro cameras split long recordings into chapter files. The first
// chapter is named GOPR####.MP4; each continuation is GP0N####.MP4
// where N is the chapter index (1-9) and #### is a 4-digit sequence
// number that stays constant across siblings.
//
// Example: a 50-minute recording named #0314 produces
//   GOPR0314.MP4   (chapter 0)
//   GP010314.MP4   (chapter 1)
//   GP020314.MP4   (chapter 2)
//   GP030314.MP4   (chapter 3)
//
// This module:
//   1. Parses GoPro chapter filenames (detectGoProChapterPattern).
//   2. Groups a flat list of files into the largest chapter cluster
//      sharing the same sequence number (groupChapterSiblings).
//   3. Builds a virtual single-timeline from a chapter array
//      (buildChapterTimeline) by probing each file's duration with a
//      temporary <video> element.
//   4. Maps a global timeline second to a (chapter, local-sec) pair
//      and back (globalToLocal / localToGlobal).
//   5. Selects the chapter segments overlapping a global time window,
//      with local-time bounds per segment, for the cross-chapter clip
//      export (selectChaptersForClip).
//
// Pure functions only — no React imports, no DOM coupling outside the
// duration probe (which is gated behind a Promise so Node-side smoke
// tests can stub it). The chapter-swap playback hook lives in
// ReplayPage.js itself, where it can wire into the existing rVFC chain
// and videoRef.

// GoPro chapter filename pattern. The core token is:
//   - GOPR####.MP4   (first chapter, chapterIndex 0)
//   - GP0N####.MP4   (continuation, chapterIndex = N, 1..9)
//
// The leading prefix MUST be either nothing or one of `-` / `_` (covers
// the `chapter01-GOPR0314.MP4` symlink fixtures and any reasonable
// renaming convention). Free-text prefixes like "My flight " are
// rejected — they shouldn't be detected as a chapter regardless of
// what the file actually contains.
//
// Case-sensitive on the prefix and extension to match GoPro's actual
// filenames; if a future GoPro tool ships lowercase variants, loosen
// then (and add a test case).
const GOPRO_FIRST_RE = /(?:^|[-_])(GOPR)(\d{4})\.MP4$/;
const GOPRO_CONT_RE  = /(?:^|[-_])(GP)0([1-9])(\d{4})\.MP4$/;

// Parse a GoPro chapter filename. Returns
//   { prefix: 'GOPR' | 'GP', seq: '0314', chapterIndex: 0..9 } | null
// for non-matches. The leading-folder/garbage tolerance is intentional
// — Playwright mirror-symlinks chapters as `chapter01-GOPR0314.MP4` so
// the test path needs to work too.
function detectGoProChapterPattern(filename) {
  if (typeof filename !== 'string' || filename.length === 0) return null;
  // GP0N first: the continuation pattern is more specific (GP0 prefix
  // + non-zero digit). GOPR after, since GP01...09 followed by 4 digits
  // shouldn't be mis-detected as GOPR.
  const cont = filename.match(GOPRO_CONT_RE);
  if (cont) {
    return {
      prefix: 'GP',
      seq: cont[3],
      chapterIndex: parseInt(cont[2], 10),
    };
  }
  const first = filename.match(GOPRO_FIRST_RE);
  if (first) {
    return {
      prefix: 'GOPR',
      seq: first[2],
      chapterIndex: 0,
    };
  }
  return null;
}

// Given a flat array of File-like objects (anything with a `.name`),
// find the largest cluster of GoPro chapters that share the same `seq`,
// sort by chapterIndex, and return [{file, chapterIndex}, ...].
//
// If no two files share a seq, returns a single-element array containing
// the first GoPro-matching file in input order — single chapter is a
// degenerate case of multi-chapter, handled the same way downstream.
//
// If NO file matches the GoPro pattern, returns an empty array. The
// caller (ReplayPage) treats the empty result as "this isn't a chapter
// pick — use the file as a standalone video" and the legacy path runs.
function groupChapterSiblings(files) {
  if (!Array.isArray(files) || files.length === 0) return [];
  const bySeq = new Map();
  for (const file of files) {
    const m = detectGoProChapterPattern(file?.name || '');
    if (!m) continue;
    if (!bySeq.has(m.seq)) bySeq.set(m.seq, []);
    bySeq.get(m.seq).push({ file, chapterIndex: m.chapterIndex });
  }
  if (bySeq.size === 0) return [];

  // Pick the largest cluster. Ties broken by first-seen order in the
  // input — Map iteration preserves insertion order so the first seq
  // that hit max size wins.
  let best = null;
  let bestSize = 0;
  for (const cluster of bySeq.values()) {
    if (cluster.length > bestSize) {
      best = cluster;
      bestSize = cluster.length;
    }
  }
  // Deduplicate chapterIndex within the cluster. If the user picks the
  // same chapter twice (e.g. two filesystem entries pointing at the
  // same recording), keep the first occurrence — sort is stable but
  // the duplicate would make timeline math undefined.
  const seenIdx = new Set();
  const deduped = [];
  for (const c of best) {
    if (seenIdx.has(c.chapterIndex)) continue;
    seenIdx.add(c.chapterIndex);
    deduped.push(c);
  }
  deduped.sort((a, b) => a.chapterIndex - b.chapterIndex);
  return deduped;
}

// Probe one File's duration by mounting it in a temporary off-DOM
// <video> element. Returns Promise<number> (seconds). Rejects if
// metadata fails to load (corrupt file, unsupported codec).
//
// Exported so the chapter-build path can be Node-tested by replacing
// this function with a stub. In the browser, called transparently by
// buildChapterTimeline.
function probeFileDurationSec(file) {
  if (typeof document === 'undefined' || typeof URL === 'undefined') {
    return Promise.reject(new Error('chapters: probeFileDurationSec requires a DOM environment'));
  }
  return new Promise((resolve, reject) => {
    const url = URL.createObjectURL(file);
    const v = document.createElement('video');
    v.preload = 'metadata';
    v.muted = true;
    const cleanup = () => {
      URL.revokeObjectURL(url);
      v.removeAttribute('src');
      try { v.load(); } catch (_) { /* best-effort */ }
    };
    v.onloadedmetadata = () => {
      const dur = v.duration;
      cleanup();
      if (Number.isFinite(dur) && dur > 0) resolve(dur);
      else reject(new Error(`chapters: invalid duration ${dur} for ${file?.name}`));
    };
    v.onerror = () => {
      cleanup();
      reject(new Error(`chapters: failed to probe ${file?.name}`));
    };
    v.src = url;
  });
}

// Build the chapter timeline given a sorted chapter list. Each entry's
// duration is probed via the supplied probeDuration function (defaults
// to probeFileDurationSec; tests pass a stub).
//
// Returned shape:
//   { chapters: [{file, durationSec, startSec, endSec, chapterIndex}],
//     totalDurationSec,
//     signature }
//
// startSec / endSec are global-timeline seconds; signature is a stable
// hash of (name, size) pairs used for persistence keying so a re-pick
// of the same chapter cluster restores sync + clips.
async function buildChapterTimeline(chapters, { probeDuration = probeFileDurationSec } = {}) {
  if (!Array.isArray(chapters) || chapters.length === 0) {
    throw new Error('chapters: buildChapterTimeline requires at least one chapter');
  }
  const durations = await Promise.all(chapters.map(c => probeDuration(c.file)));
  let cursor = 0;
  const built = chapters.map((c, i) => {
    const durationSec = durations[i];
    const startSec = cursor;
    const endSec   = cursor + durationSec;
    cursor = endSec;
    return {
      file: c.file,
      chapterIndex: c.chapterIndex,
      durationSec,
      startSec,
      endSec,
    };
  });
  const sigParts = built.map(c => `${c.file?.name || '?'}:${c.file?.size || 0}`);
  return {
    chapters: built,
    totalDurationSec: cursor,
    signature: sigParts.join('|'),
  };
}

// Map a global second to (chapterIndex, localSec). Past-the-end times
// clamp to the last chapter's end. Negative or pre-start clamp to
// chapter 0 localSec=0. Binary search; O(log N) chapters.
function globalToLocal(timeline, globalSec) {
  if (!timeline || !Array.isArray(timeline.chapters) || timeline.chapters.length === 0) {
    return { chapterIndex: 0, localSec: 0 };
  }
  const chapters = timeline.chapters;
  if (!Number.isFinite(globalSec) || globalSec <= 0) {
    return { chapterIndex: 0, localSec: 0 };
  }
  if (globalSec >= timeline.totalDurationSec) {
    const last = chapters[chapters.length - 1];
    return { chapterIndex: chapters.length - 1, localSec: last.durationSec };
  }
  // Binary search for the chapter whose [startSec, endSec) covers globalSec.
  let lo = 0;
  let hi = chapters.length - 1;
  while (lo < hi) {
    const mid = (lo + hi) >>> 1;
    if (chapters[mid].endSec <= globalSec) lo = mid + 1;
    else hi = mid;
  }
  const c = chapters[lo];
  return { chapterIndex: lo, localSec: Math.max(0, globalSec - c.startSec) };
}

// Inverse of globalToLocal. Out-of-range chapterIndex clamps; invalid
// localSec falls back to 0.
function localToGlobal(timeline, chapterIndex, localSec) {
  if (!timeline || !Array.isArray(timeline.chapters) || timeline.chapters.length === 0) {
    return 0;
  }
  const chapters = timeline.chapters;
  const idx = Math.max(0, Math.min(chapters.length - 1, chapterIndex | 0));
  const c = chapters[idx];
  const local = Number.isFinite(localSec) ? Math.max(0, Math.min(c.durationSec, localSec)) : 0;
  return c.startSec + local;
}

// Pick the chapter segments that overlap a global time window. Used by
// the cross-chapter clip export to iterate "open chapter N from local A
// to local B" pairs.
//
// Returns [{
//   file, chapterIndex,
//   localStartSec,        // sec inside this chapter file
//   localEndSec,
//   globalStartSec,       // sec in the virtual timeline
//   globalEndSec,
// }, ...] — possibly empty if [startGlobalSec, endGlobalSec) doesn't
// overlap the timeline.
function selectChaptersForClip(timeline, startGlobalSec, endGlobalSec) {
  if (!timeline || !Array.isArray(timeline.chapters)) return [];
  if (!Number.isFinite(startGlobalSec) || !Number.isFinite(endGlobalSec)) return [];
  if (endGlobalSec <= startGlobalSec) return [];
  const segs = [];
  for (const c of timeline.chapters) {
    const segStart = Math.max(c.startSec, startGlobalSec);
    const segEnd   = Math.min(c.endSec,   endGlobalSec);
    if (segEnd <= segStart) continue;
    segs.push({
      file:           c.file,
      chapterIndex:   c.chapterIndex,
      localStartSec:  segStart - c.startSec,
      localEndSec:    segEnd   - c.startSec,
      globalStartSec: segStart,
      globalEndSec:   segEnd,
    });
  }
  return segs;
}

// Friendly status-line text for the toolbar.
//   ("foo.mp4")                 — single chapter (or non-GoPro pick)
//   ("foo.mp4 + 3 chapters")    — multi-chapter cluster, 4 files total
//   (with optional " (51m 23s)" suffix when total duration is known)
function describeChapterPick(timeline, primaryName) {
  if (!timeline || !Array.isArray(timeline.chapters) || timeline.chapters.length === 0) {
    return primaryName || '';
  }
  const n = timeline.chapters.length;
  const head = primaryName || (timeline.chapters[0].file?.name || '');
  if (n <= 1) return head;
  const extra = n - 1;
  let label = `${head} + ${extra} chapter${extra === 1 ? '' : 's'}`;
  if (Number.isFinite(timeline.totalDurationSec) && timeline.totalDurationSec > 0) {
    label += ` (${formatDurationShort(timeline.totalDurationSec)})`;
  }
  return label;
}

// Compact H:MM:SS / M:SS for the toolbar status line.
function formatDurationShort(sec) {
  const total = Math.floor(sec);
  const h = Math.floor(total / 3600);
  const m = Math.floor((total % 3600) / 60);
  const s = total % 60;
  if (h > 0) return `${h}h ${m}m ${s}s`;
  return `${m}m ${s}s`;
}

// === docs/site/docs/data-and-logs/replay/lib/replay/mp4Export.js ===
// Export a synced video + indexer overlay as an MP4 using WebCodecs.
//
// Pipeline (one clip at a time):
//
//   Video — Mediabunny demux + VideoDecoder:
//     1. Open the source File with `new Input({ source: new BlobSource(file),
//        formats: ALL_FORMATS })`. Mediabunny streams reads natively
//        — no head/tail probe budget; the moov can sit anywhere in
//        the file.
//     2. From the primary video track, pull codec config (avcC or
//        hvcC bytes, via getDecoderConfig()) and rotation
//        (getRotation()).
//     3. Find the keyframe at-or-before clampedStart via
//        `videoSink.getKeyPacket(clampedStart)`, then walk forward
//        with `videoSink.packets(startPacket)` (decode order).
//        Packets with cts in [clampedStart, clampedEnd] are flagged
//        `output: true`; earlier packets (the decode dependency
//        chain back to the anchor key) are flagged `output: false`.
//     4. For each packet: wrap as `EncodedVideoChunk` →
//        `VideoDecoder.decode()`. Output frames land in a queue,
//        sorted by timestamp (cts → display order).
//     5. For each output sample (in cts order): drive sim to that
//        sample's mediaTime, render overlay SVG, composite
//        VideoFrame + overlay onto OffscreenCanvas, encode with the
//        source's exact (timestamp, duration).
//
//   Audio — Mediabunny demux, no re-encode:
//     1. Same Input — both tracks share one underlying source.
//     2. Find the audio packet at-or-before clampedStart, walk
//        forward via `audioSink.packets()` until ts >= clampedEnd.
//     3. For each packet: build a Mediabunny `EncodedPacket` with
//        timestamp re-anchored at the first muxed packet's source ts
//        (so the output MP4 starts at t=0), push to the audio
//        EncodedAudioPacketSource. First push carries the
//        AudioSpecificConfig DSI in meta.decoderConfig.description.
//
//   Both video and audio share a single Mediabunny Output. After
//   `finalize()`, `output.target.buffer` is the complete MP4 as an
//   ArrayBuffer.







// Browser feature gate. Both VideoEncoder AND VideoDecoder are now
// required — the export demuxes the source via Mediabunny, decodes
// frames with VideoDecoder, composites the overlay, and re-encodes
// with VideoEncoder. OffscreenCanvas is the compositor target.
function isMp4ExportSupported() {
  if (typeof window === 'undefined') return false;
  if (!('VideoEncoder' in window)) return false;
  if (!('VideoDecoder' in window)) return false;
  if (!('OffscreenCanvas' in window)) return false;
  return true;
}

// Audio export needs nothing beyond Blob.slice() (universally
// supported where MP4 export itself runs). Kept as a separate gate
// so the UI can advertise "exports with audio" without parsing the
// file. Note: actual audio output still falls back to silent if the
// source has no AAC track or Mediabunny can't parse the container.
function isMp4AudioExportSupported() {
  if (typeof window === 'undefined') return false;
  if (typeof Blob === 'undefined' || !Blob.prototype.slice) return false;
  return true;
}

// Fallback encoder parameters used only when the source's own framerate
// or codec can't be discovered. The export defaults to "match source"
// — same resolution, framerate, codec family, and a bitrate scaled to
// the source's pixel rate.
const DEFAULT_FRAMERATE = 30;

// Bitrate target as a function of pixel count + framerate. YouTube's
// "good upload quality" recommendations: 1080p30 ≈ 8 Mbps, 1440p30 ≈
// 16 Mbps, 2160p30 ≈ 35-45 Mbps. Scale linearly with pixel rate. For
// 4K and up, bump the bits-per-pixel slightly because compression
// efficiency drops at very high resolutions.
function computeBitrate(width, height, framerate) {
  const w = Number.isFinite(width)     && width     > 0 ? width     : 1920;
  const h = Number.isFinite(height)    && height    > 0 ? height    : 1080;
  const f = Number.isFinite(framerate) && framerate > 0 ? framerate : 30;
  const pixelsPerSec = w * h * f;
  const bitsPerPixel = (w >= 2560) ? 0.15 : 0.13;
  return Math.round(pixelsPerSec * bitsPerPixel);
}

// Pick a VideoEncoder config. When the source is HEVC, probe HEVC
// Main candidates first so the output codec family matches the source
// (avoids transcoding a 4K HEVC to a 1080p AVC by accident). Falls
// back to H.264 High profile, then Baseline as a last resort.
async function pickEncoderConfig({ width, height, bitrate, framerate, sourceCodec }) {
  const w = Math.max(2, Math.floor(width  / 2) * 2);
  const h = Math.max(2, Math.floor(height / 2) * 2);
  // Mediabunny's getCodec() returns the codec family name ('hevc', 'avc',
  // 'vp9', etc) — not a full parameter string. Match that family here.
  const isHevc = sourceCodec === 'hevc';

  // HEVC candidates (in level order — try 4K-capable first if the
  // source is 4K, otherwise lower levels suffice). L153 = up to 4K60,
  // L150 = up to 4K30, L120 = up to 1080p60.
  const hevcCandidates = [
    { codec: 'hev1.1.6.L153.B0', width: w, height: h, bitrate, framerate, hevc: { format: 'hevc' } },
    { codec: 'hev1.1.6.L150.B0', width: w, height: h, bitrate, framerate, hevc: { format: 'hevc' } },
    { codec: 'hev1.1.6.L120.B0', width: w, height: h, bitrate, framerate, hevc: { format: 'hevc' } },
  ];

  // H.264 High profile candidates: avc1.640033 = High @ Level 5.1 (4K),
  // avc1.640028 = High @ Level 4.0 (1080p). Baseline (avc1.42E028) is
  // kept as a last-resort fallback for environments without High
  // encode support.
  const avcCandidates = [
    { codec: 'avc1.640033', width: w, height: h, bitrate, framerate, avc: { format: 'avc' } },
    { codec: 'avc1.640028', width: w, height: h, bitrate, framerate, avc: { format: 'avc' } },
    { codec: 'avc1.42E028', width: w, height: h, bitrate, framerate, avc: { format: 'avc' } },
  ];

  const candidates = isHevc
    ? [...hevcCandidates, ...avcCandidates]
    : [...avcCandidates];

  for (const cfg of candidates) {
    try {
      const r = await VideoEncoder.isConfigSupported(cfg);
      if (r.supported) return r.config;
    } catch (_) { /* try next */ }
  }
  throw new Error(
    `No supported video encoder config at ${w}x${h}. Tried ` +
    `${isHevc ? 'HEVC Main + H.264 High/Baseline' : 'H.264 High/Baseline'}. ` +
    `Your browser has WebCodecs but no usable encode path.`);
}

// Rasterize an SVG element to an HTMLImageElement via a Blob URL.
// drawImage(img, x, y, w, h) paints with explicit destination dims so
// SVGs without intrinsic width/height still rasterize at usable size.
function svgToImage(svgEl) {
  const xml  = new XMLSerializer().serializeToString(svgEl);
  const blob = new Blob([xml], { type: 'image/svg+xml;charset=utf-8' });
  const url  = URL.createObjectURL(blob);
  return new Promise((resolve, reject) => {
    const img = new Image();
    img.onload  = () => { URL.revokeObjectURL(url); resolve(img); };
    img.onerror = (e) => { URL.revokeObjectURL(url); reject(e); };
    img.src = url;
  });
}

// Overlay placement. position='right' is the default single-panel
// corner (the live page's .replay-overlay-frame position).
// position='left' mirrors X across the centerline for the "standard"
// two-panel export — same width, same Y, same margins, just pinned
// to the opposite edge. position='fullframe' covers the entire
// output canvas, for the full-frame HUD. Returns { x, y, w, h } in
// canvas pixels.
function overlayPlacement(W, H, position) {
  if (position === 'fullframe') return { x: 0, y: 0, w: W, h: H };
  const w = Math.round(W * 0.22);
  const h = Math.round(w * 3 / 4);
  const y = H - Math.round(H * 0.030) - h;
  const x = position === 'left'
    ? Math.round(W * 0.012)
    : W - Math.round(W * 0.012) - w;
  return { x, y, w, h };
}

// Composite one frame: video frame first (rotated to upright orientation
// if the source has a display-matrix rotation, e.g. GoPro -180°), then
// each overlay drawn at its requested corner. Overlays are always drawn
// AFTER the rotation so they sit upright on screen regardless of source
// orientation. Mirrors the live page's .replay-overlay-frame layout.
// `videoSrc` can be any drawImage-compatible source (VideoFrame,
// HTMLVideoElement, ImageBitmap, etc). `rotationDeg` is the angle to
// rotate the source pixels by — 0 / 90 / 180 / 270 (or -90 / -180).
// `overlays` is an array of { img, position } entries; falsy `img`
// entries are skipped. Empty array = source-only frame.
function compositeFrame(ctx, videoSrc, overlays, W, H, rotationDeg = 0) {
  if (videoSrc) {
    const r = ((rotationDeg % 360) + 360) % 360;
    if (r === 0) {
      ctx.drawImage(videoSrc, 0, 0, W, H);
    } else {
      ctx.save();
      // Rotate around the canvas center so the rotated image fills the
      // same WxH bounds. For 90/270 the source's natural aspect would
      // be sideways; we still target WxH so the encoder gets a normal
      // landscape frame. (For literal sideways video we'd want to
      // swap W/H at the encoder, but that's a future concern.)
      ctx.translate(W / 2, H / 2);
      ctx.rotate(r * Math.PI / 180);
      ctx.drawImage(videoSrc, -W / 2, -H / 2, W, H);
      ctx.restore();
    }
  }
  if (!overlays || overlays.length === 0) return;
  // The corner-panel canvas shadow is sized for a ~22%-of-frame
  // panel — its blur radius (W * 0.006) is calibrated against the
  // panel's own line weight. Applied to a fullframe HUD it halos
  // every tick and label as if they were the edge of a small image,
  // producing a fringed look that pilots find distracting at 4K.
  // The HUD widget legibility instead comes from the SVG's own
  // styling; we draw fullframe overlays without the canvas shadow.
  for (const ov of overlays) {
    if (!ov || !ov.img) continue;
    const { x, y, w, h } = overlayPlacement(W, H, ov.position);
    if (ov.position === 'fullframe') {
      ctx.drawImage(ov.img, x, y, w, h);
    } else {
      ctx.save();
      ctx.shadowColor   = 'rgba(0,0,0,0.7)';
      ctx.shadowBlur    = Math.round(W * 0.006);
      ctx.shadowOffsetY = Math.round(W * 0.0015);
      ctx.drawImage(ov.img, x, y, w, h);
      ctx.restore();
    }
  }
}

// Derive the source video's display rotation from its tkhd matrix.
// mp4 tkhd matrices are 9-element fixed-point arrays in row-major
// order: [a, b, u, c, d, v, x, y, w]. For rotation θ the 2x2 (a,b,c,d)
// block holds [cosθ, sinθ, -sinθ, cosθ] in 16.16 fixed-point — so
// dividing by 65536 recovers the float values. We probe the standard
// orientations (0/90/180/270) and return the matching angle, or 0 if
// the matrix is identity / unrecognized.
//
// The live export path reads rotation directly via Mediabunny's
// `track.getRotation()` (which returns 0/90/180/270 having already
// inspected the matrix internally). This helper is retained for
// diagnostics and tests — round-tripping canonical matrices locks
// the algebra against regressions in either path.
//
// Matrix values arrive either as raw int32 16.16 fixed-point (the
// ISO BMFF wire format) or as already-unpacked floats (some
// upstream parsers do the conversion eagerly). Normalize before
// reading.
function rotationFromTkhdMatrix(matrix) {
  if (!matrix || matrix.length < 9) return 0;
  // Detect fixed-point vs already-unpacked floats. At a 90°/270°
  // rotation the (0,0) entry is 0, so we sniff the largest magnitude
  // across the 2x2 rotation block (entries 0,1,3,4) — at least one of
  // those is ±1 in float form, ±65536 in fixed-point.
  const maxMag = Math.max(
    Math.abs(matrix[0] || 0),
    Math.abs(matrix[1] || 0),
    Math.abs(matrix[3] || 0),
    Math.abs(matrix[4] || 0),
  );
  const scale = maxMag > 2 ? 1 / 65536 : 1;
  const a = matrix[0] * scale;
  const b = matrix[1] * scale;
  // c = matrix[3] * scale, d = matrix[4] * scale — not needed since
  // a/b alone disambiguate the four cardinal rotations.
  const eps = 0.01;
  if (Math.abs(a - 1) < eps && Math.abs(b)     < eps) return 0;
  if (Math.abs(a)     < eps && Math.abs(b - 1) < eps) return 90;
  if (Math.abs(a + 1) < eps && Math.abs(b)     < eps) return 180;
  if (Math.abs(a)     < eps && Math.abs(b + 1) < eps) return 270;
  return 0;
}

// ---------------------------------------------------------------------
// Sim driver — same logic as ReplayPage's live driver. Walks 50 ms wire
// boundaries from lastBoundaryMs to targetVirtMs, injects one wire
// frame per boundary, then advances virtual clock to targetVirtMs.
// ---------------------------------------------------------------------
const M5_TICK_MS = 50;
const M5_LARGE_JUMP_MS = 5000;

function driveSimToVirtMs(sim, state, targetVirtMs, log, sync, cppWireFrames) {
  const frames = cppWireFrames && cppWireFrames.frames;
  const injectAt = (virtMs) => {
    if (!frames) return;
    const logMs = sync.logTakeoffMs + (virtMs / 1000 - sync.videoTakeoffSec) * 1000;
    const rowIdx = findRowAt(log, logMs);
    if (rowIdx < 0) return;
    const frameBytes = frames[rowIdx];
    if (!frameBytes) return;
    sim.injectBytes(frameBytes);
  };
  const last = state.lastVirtMs;
  const jump = targetVirtMs - last;
  if (jump < 0 || jump > M5_LARGE_JUMP_MS) {
    injectAt(targetVirtMs);
    sim.advanceTo(targetVirtMs);
    state.lastVirtMs = targetVirtMs;
    state.lastBoundaryMs = Math.floor(targetVirtMs / M5_TICK_MS) * M5_TICK_MS;
    return;
  }
  let lastBoundary = state.lastBoundaryMs;
  let nextBoundary = lastBoundary + M5_TICK_MS;
  while (nextBoundary <= targetVirtMs) {
    injectAt(nextBoundary);
    sim.advanceTo(nextBoundary);
    lastBoundary = nextBoundary;
    nextBoundary += M5_TICK_MS;
  }
  state.lastBoundaryMs = lastBoundary;
  if (targetVirtMs > lastBoundary) sim.advanceTo(targetVirtMs);
  state.lastVirtMs = targetVirtMs;
}

// ---------------------------------------------------------------------
// Mediabunny demux helpers — open the source, pick out primary tracks,
// pull decoder configs + rotation.
// ---------------------------------------------------------------------

// Open `file` (File | Blob) as a Mediabunny Input. ALL_FORMATS lets
// the library sniff the container — we only ship MP4 today but the
// docs-site replay page may grow MOV / MKV support later, and the
// extra format detectors weigh nothing at runtime.
function openInput(file) {
  return new Input({
    source: new BlobSource(file),
    formats: ALL_FORMATS,
  });
}

// Pull the primary video track + its decoder config + rotation +
// (estimated) framerate from the first packet's duration. Returns
// null if the source has no decodable video.
async function readVideoTrackInfo(input) {
  const track = await input.getPrimaryVideoTrack();
  if (!track) {
    console.warn('mediabunny: source has no video track.');
    return null;
  }
  const codec = await track.getCodec();           // 'avc' | 'hevc' | ...
  if (codec !== 'avc' && codec !== 'hevc') {
    console.warn(`mediabunny: unsupported video codec "${codec}".`);
    return null;
  }
  const decoderCfg = await track.getDecoderConfig();
  if (!decoderCfg || !decoderCfg.description) {
    console.warn('mediabunny: video track missing decoder config.');
    return null;
  }
  const width  = await track.getCodedWidth();
  const height = await track.getCodedHeight();
  if (!width || !height) {
    console.warn('mediabunny: video track missing width/height.');
    return null;
  }
  const rotationDeg = await track.getRotation();   // 0 | 90 | 180 | 270

  return {
    track,
    codec,                                          // 'avc' | 'hevc'
    codecParameterString: decoderCfg.codec,         // e.g. 'avc1.640033'
    width,
    height,
    description: new Uint8Array(decoderCfg.description),
    rotationDeg: rotationDeg || 0,
    decoderCfg,
  };
}

// Pull the primary audio track if it's AAC. Returns null if no AAC
// track — caller falls back to silent MP4.
async function readAudioTrackInfo(input) {
  const track = await input.getPrimaryAudioTrack();
  if (!track) {
    console.warn('mediabunny: source has no audio track; emitting silent MP4.');
    return null;
  }
  const codec = await track.getCodec();
  if (codec !== 'aac') {
    console.warn(`mediabunny: audio codec "${codec}" is not AAC; emitting silent MP4.`);
    return null;
  }
  const decoderCfg = await track.getDecoderConfig();
  if (!decoderCfg) {
    console.warn('mediabunny: AAC track has no decoder config; emitting silent MP4.');
    return null;
  }
  if (!decoderCfg.description) {
    console.warn('mediabunny: AAC track missing AudioSpecificConfig; emitting silent MP4.');
    return null;
  }
  const sampleRate = await track.getSampleRate();
  const channelCount = await track.getNumberOfChannels();
  if (!sampleRate || !channelCount) {
    console.warn('mediabunny: AAC track missing sample_rate/channel_count; emitting silent MP4.');
    return null;
  }
  return {
    track,
    codec,                                            // 'aac'
    codecParameterString: decoderCfg.codec,           // 'mp4a.40.2' etc.
    sampleRate,
    channelCount,
    description: new Uint8Array(decoderCfg.description),
  };
}

// Pull every AAC packet whose presentation time overlaps [clampedStart,
// clampedEnd] and push it through `audioSource` unchanged. Returns
// { added, skipped, reason }.
//
// First push carries decoderConfig (codec, channels, sampleRate,
// description). Subsequent pushes have no meta.
async function feedAacPacketsToOutput({
  audioSource, videoTrack: _vt, audioInfo, clampedStart, clampedEnd, signal,
}) {
  const sink = new EncodedPacketSink(audioInfo.track);

  // Find the first packet at-or-before clampedStart. AAC has no
  // inter-frame prediction (each ADTS frame is independent), so any
  // packet at-or-before the window start is a valid decoder anchor
  // AND a usable mux input. We include any packet whose time range
  // overlaps the window.
  let firstPacket = await sink.getPacket(clampedStart);
  if (!firstPacket && clampedStart < 1.0) {
    // Edge case: clip starts at t=0 (or near it) but the AAC track's
    // first packet is at a small positive offset (typical: ~0.046s).
    // getPacket(0) returns null in that case. Walk forward to find
    // the actual first audio packet rather than producing a silent
    // export.
    // eslint-disable-next-line no-restricted-syntax
    for await (const p of sink.packets()) {
      firstPacket = p;
      break;
    }
  }
  if (!firstPacket) {
    return { added: 0, skipped: true, reason: 'no audio packets at-or-before window start' };
  }

  // Iterate forward. Anchor output timestamps at the first muxed
  // packet's source timestamp so the output MP4's audio timeline
  // starts at t=0.
  let firstTs = null;
  let added = 0;
  let metaSent = false;

  for await (const packet of sink.packets(firstPacket)) {
    if (signal?.aborted) throw new DOMException('aborted', 'AbortError');
    // Stop at-or-after clampedEnd. Use packet.timestamp (cts) — AAC
    // packets are short (1024 / sampleRate ≈ 23ms at 44.1kHz) so
    // including a few past the end if any straddle the boundary is
    // cheap and avoids cutting mid-frame.
    if (packet.timestamp >= clampedEnd) break;
    // Skip packets entirely before the window. AAC packets are
    // independently decodable, so we don't need pre-window decode
    // context (unlike video).
    if (packet.timestamp + packet.duration <= clampedStart) continue;

    if (firstTs === null) firstTs = packet.timestamp;
    const reTimed = new EncodedPacket(
      packet.data,
      packet.type,                           // always 'key' for AAC
      packet.timestamp - firstTs,            // re-anchor at t=0
      packet.duration,
    );

    const meta = metaSent ? undefined : {
      decoderConfig: {
        codec:            audioInfo.codecParameterString,
        sampleRate:       audioInfo.sampleRate,
        numberOfChannels: audioInfo.channelCount,
        description:      audioInfo.description,
      },
    };
    // eslint-disable-next-line no-await-in-loop
    await audioSource.add(reTimed, meta);
    metaSent = true;
    added++;
  }

  if (added === 0) {
    return { added: 0, skipped: true, reason: 'no audio packets overlap window' };
  }
  return { added, skipped: false };
}

// Per-segment variant: re-anchor packets at `outOffsetSec` (where this
// segment lives on the output's audio timeline) and skip the
// decoderConfig meta if a previous segment already sent it. Returns
// { added, addedSec, skipped, reason } where addedSec is the audio
// duration written for this segment so callers can advance their
// cumulative offset.
async function feedAacSegmentToOutput({
  audioSource, audioInfo, clampedStart, clampedEnd,
  outOffsetSec, metaAlreadySent, signal,
}) {
  const sink = new EncodedPacketSink(audioInfo.track);
  let firstPacket = await sink.getPacket(clampedStart);
  if (!firstPacket && clampedStart < 1.0) {
    // eslint-disable-next-line no-restricted-syntax
    for await (const p of sink.packets()) {
      firstPacket = p;
      break;
    }
  }
  if (!firstPacket) {
    return { added: 0, addedSec: 0, skipped: true, reason: 'no audio packets at-or-before segment start' };
  }
  let firstTs = null;
  let lastTs = 0;
  let lastDur = 0;
  let added = 0;
  let metaSent = !!metaAlreadySent;
  for await (const packet of sink.packets(firstPacket)) {
    if (signal?.aborted) throw new DOMException('aborted', 'AbortError');
    if (packet.timestamp >= clampedEnd) break;
    if (packet.timestamp + packet.duration <= clampedStart) continue;
    if (firstTs === null) firstTs = packet.timestamp;
    const outTs = outOffsetSec + (packet.timestamp - firstTs);
    const reTimed = new EncodedPacket(
      packet.data,
      packet.type,
      outTs,
      packet.duration,
    );
    const meta = metaSent ? undefined : {
      decoderConfig: {
        codec:            audioInfo.codecParameterString,
        sampleRate:       audioInfo.sampleRate,
        numberOfChannels: audioInfo.channelCount,
        description:      audioInfo.description,
      },
    };
    // eslint-disable-next-line no-await-in-loop
    await audioSource.add(reTimed, meta);
    metaSent = true;
    added++;
    lastTs = outTs;
    lastDur = packet.duration;
  }
  if (added === 0) {
    return { added: 0, addedSec: 0, skipped: true, reason: 'no audio packets overlap segment window' };
  }
  const addedSec = (lastTs + lastDur) - outOffsetSec;
  return { added, addedSec, skipped: false };
}

// ---------------------------------------------------------------------
// Public API.
// ---------------------------------------------------------------------
//
// Options (v5 — source-faithful, multi-chapter aware):
//   videoTimeline:     Timeline | null — preferred for GoPro multi-chapter
//                      recordings. Shape: `{ chapters: [{file, startSec,
//                      endSec, ...}], totalDurationSec }`. When provided,
//                      the export stitches across chapter boundaries into
//                      one output MP4 with continuous timestamps.
//                      Codec config + framerate + dimensions are taken
//                      from the FIRST chapter only — chapters are assumed
//                      to share encoder configuration (GoPro guarantees
//                      this for siblings within one recording).
//   sourceFile:        File | Blob — legacy single-file path. Ignored when
//                      videoTimeline is provided. If neither is given the
//                      export aborts.
//   videoEl:           HTMLVideoElement — used ONLY for videoWidth /
//                      videoHeight / duration reads. We never call
//                      play() / seek() on it during export.
//   presentationTau:   { lateralSec, verticalSec } | null — render-side
//                      smoothing applied to state.LateralG/VerticalG
//                      before SVG render. Mirrors the live preview's
//                      PresentationFilter; null = no smoothing.
//   outputWidth:       int | null — override the output width to
//                      downscale. null = match source width (default,
//                      source-faithful).
//   bitrate:           int | null — override the encoder target bitrate
//                      in bits/sec. null = compute from output
//                      resolution + framerate using computeBitrate.
//   framerate:         number | null — override the output framerate
//                      (passed to the encoder + muxer as a hint). null
//                      = match source framerate exactly from the first
//                      packet's duration.
//
// Returns: Promise<Blob>  — an MP4 ready to download.
async function exportClipAsMp4({
  videoEl,
  clip,
  sync,
  log,
  cppWireFrames,
  renderOverlaySvg,
  // Optional: full-frame HUD overlay rendered UNDER the corner panels.
  // (m5State) → SVGElement. When provided, every output frame
  // composites the HUD across the entire canvas before the corner
  // panels are drawn — so the inset / standard pair sit on top of
  // the HUD widgets in the same way as the live preview.
  renderHudSvg    = null,
  sourceFile      = null,
  videoTimeline   = null,
  presentationTau = null,
  // Which M5 mode the burned-in overlay should render. Integer 0-4
  // matching the firmware's kModeNames / M5_MODES. Default 0 (Energy)
  // matches a fresh M5Sim's default but is almost always wrong for
  // export — the page should pass the live preview's current mode so
  // the export matches what the pilot sees on screen.
  displayMode     = 0,
  // "Standard" layout: render BOTH Attitude (ADI, displayType 1) and
  // Energy (displayType 0) burned into the source frame — ADI in the
  // bottom-left, Energy in the bottom-right (same Y, X mirrored across
  // the source centerline). When true, `displayMode` is ignored.
  standardOverlay = false,
  outputWidth     = null,
  bitrate         = null,
  framerate       = null,
  onProgress      = null,
  signal          = null,
}) {
  if (!isMp4ExportSupported()) {
    throw new Error(
      'MP4 export requires Chrome or Edge desktop. WebCodecs ' +
      '(VideoEncoder + VideoDecoder) is incomplete in Safari / Firefox.');
  }
  if (!videoEl)        throw new Error('exportClipAsMp4: videoEl required');
  if (!clip)           throw new Error('exportClipAsMp4: clip required');
  if (!sync || !Number.isFinite(sync.logTakeoffMs) ||
      !Number.isFinite(sync.videoTakeoffSec)) {
    throw new Error('exportClipAsMp4: complete sync anchor required ' +
                    '(set both video and log anchors before exporting).');
  }
  if (!log)            throw new Error('exportClipAsMp4: log required');
  if (!cppWireFrames || !cppWireFrames.frames) {
    throw new Error(
      'exportClipAsMp4: cppWireFrames required (build the replay engine ' +
      'pre-pass first).');
  }
  if (!videoEl.videoWidth || !videoEl.videoHeight) {
    throw new Error('exportClipAsMp4: video metadata not loaded yet');
  }
  // Either a multi-chapter timeline OR a single legacy sourceFile is
  // accepted. Both paths flow through the same per-segment loop below;
  // single-chapter is a one-segment degenerate case.
  if (!videoTimeline &&
      (!sourceFile || typeof sourceFile.slice !== 'function')) {
    throw new Error(
      'exportClipAsMp4: pass either videoTimeline (multi-chapter) or ' +
      'sourceFile (legacy single-file). Mediabunny demuxes from these; ' +
      'without one the input video cannot be decoded.');
  }
  // Build the unified timeline used for segment selection. Single-file
  // becomes a synthetic 1-chapter timeline covering [0, videoEl.duration).
  const resolvedTimeline = videoTimeline && Array.isArray(videoTimeline.chapters) &&
                           videoTimeline.chapters.length > 0
    ? videoTimeline
    : {
        chapters: [{
          file:           sourceFile,
          chapterIndex:   0,
          durationSec:    videoEl.duration,
          startSec:       0,
          endSec:         videoEl.duration,
        }],
        totalDurationSec: videoEl.duration,
      };

  // Map clip times to global video seconds (offset across all chapters).
  const startGlobalSec = sync.videoTakeoffSec +
                         (clip.startMs - sync.logTakeoffMs) / 1000;
  const endGlobalSec   = sync.videoTakeoffSec +
                         (clip.endMs   - sync.logTakeoffMs) / 1000;
  if (!Number.isFinite(startGlobalSec) || !Number.isFinite(endGlobalSec) ||
      endGlobalSec <= startGlobalSec) {
    throw new Error('exportClipAsMp4: clip window maps to an empty or ' +
                    'invalid video range.');
  }
  const clampedStart = Math.max(0, startGlobalSec);
  const clampedEnd   = Math.min(resolvedTimeline.totalDurationSec, endGlobalSec);
  if (clampedEnd <= clampedStart) {
    throw new Error('exportClipAsMp4: clip falls outside the loaded video.');
  }
  const totalSec    = clampedEnd - clampedStart;

  // Slice the timeline into per-chapter segments overlapping the clip
  // window. Each segment is one open-then-close Input cycle below.
  // Single-chapter timeline reduces to one segment with localStartSec=
  // clampedStart, localEndSec=clampedEnd.
  const segments = selectChaptersForClip(
    resolvedTimeline, clampedStart, clampedEnd);
  if (segments.length === 0) {
    throw new Error('exportClipAsMp4: no chapter segments overlap clip window.');
  }

  const sim = await M5Sim.create();
  if (signal?.aborted) { sim.delete(); throw new DOMException('aborted', 'AbortError'); }
  // Set the display mode on the fresh sim so state.displayType matches
  // the live preview's mode. Without this, every export rendered the
  // sim's default mode (0 = Energy) regardless of what the page showed.
  if (Number.isFinite(displayMode)) {
    try { sim.setMode(displayMode); } catch (_) { /* sim may not yet support */ }
  }
  const simState = { lastVirtMs: 0, lastBoundaryMs: 0 };

  // PresentationFilter — same as live preview's render-side smoothing.
  // Fresh instance per export so it seeds clean from the first frame.
  let presFilter = null;
  if (presentationTau &&
      (presentationTau.lateralSec > 0 || presentationTau.verticalSec > 0)) {
    presFilter = new PresentationFilter();
    presFilter.setTau({
      lateralSec:  presentationTau.lateralSec  || 0,
      verticalSec: presentationTau.verticalSec || 0,
    });
  }

  // ---------- Probe FIRST segment for codec/fps/dims ----------------
  // Encoder configuration is taken from chapter 0. Subsequent chapters
  // are assumed to share the same encode parameters — GoPro always
  // ships matching siblings within one recording. A future hardening
  // pass could re-probe per segment and warn on mismatches.
  //
  // The probe Input is discarded immediately after the probe finishes
  // — the segment loop opens a fresh Input per segment including
  // segment 0. Reusing the probe Input on segment 0 would alias the
  // track cursor with the probe's EncodedPacketSink walks; safer to
  // pay the open cost twice for chapter 0 than to risk a subtle
  // first-segment seek/anchor corruption.
  const firstSegment = segments[0];
  const probeInput = openInput(firstSegment.file);
  // Inputs we'll close in `finally`. Probe is added immediately; each
  // segment Input gets pushed as it's opened.
  const openedInputs = [probeInput];
  let videoInfo;
  try {
    videoInfo = await readVideoTrackInfo(probeInput);
  } catch (e) {
    sim.delete();
    throw new Error(`mediabunny: failed to open source video track: ${e?.message || e}`);
  }
  if (!videoInfo) {
    sim.delete();
    throw new Error(
      'No supported video track in source file. Expected H.264 (avc1/avc3) ' +
      'or HEVC (hvc1/hev1). HEVC requires Chrome with hardware HEVC support.');
  }
  const probeAudioInfo = await readAudioTrackInfo(probeInput);
  const hasAudio = !!probeAudioInfo;

  // Resolution: default to source dims; if outputWidth is given,
  // downscale aspect-preserving. Round both axes to even numbers
  // (encoder requirement).
  const srcW = videoInfo.width;
  const srcH = videoInfo.height;
  const W = outputWidth
    ? Math.max(2, Math.floor(outputWidth / 2) * 2)
    : Math.max(2, Math.floor(srcW / 2) * 2);
  const H = outputWidth
    ? Math.max(2, Math.floor(W * srcH / srcW / 2) * 2)
    : Math.max(2, Math.floor(srcH / 2) * 2);

  // Framerate: probe via the first chapter's anchor keyframe duration.
  const probeVideoSink = new EncodedPacketSink(videoInfo.track);
  const probeAnchor =
    (await probeVideoSink.getKeyPacket(firstSegment.localStartSec)) ||
    (await probeVideoSink.getPacket(0));
  if (!probeAnchor) {
    sim.delete();
    throw new Error('Video track has no packets.');
  }
  let resolvedFps;
  if (Number.isFinite(framerate) && framerate > 0) {
    resolvedFps = framerate;
  } else if (probeAnchor.duration > 0) {
    resolvedFps = 1 / probeAnchor.duration;
  } else {
    resolvedFps = DEFAULT_FRAMERATE;
  }
  const resolvedBitrate = (Number.isFinite(bitrate) && bitrate > 0)
    ? bitrate
    : computeBitrate(W, H, resolvedFps);
  const canvas = new OffscreenCanvas(W, H);
  const ctx    = canvas.getContext('2d');

  // -------- Pick encoder config + output codec family ---------------
  const encConfig = await pickEncoderConfig({
    width: W, height: H,
    bitrate: resolvedBitrate,
    framerate: resolvedFps,
    sourceCodec: videoInfo.codec,
  });
  const outputCodecFamily = /^hev1\.|^hvc1\./i.test(encConfig.codec) ? 'hevc' : 'avc';
  const muxerFrameRate = Math.max(1, Math.round(resolvedFps));

  // -------- Build Mediabunny Output ---------------------------------
  // Single Output for video + (optional) audio across ALL chapter
  // segments. Output timestamps are anchored at the clip's global
  // start, so segment boundaries appear as monotone-continuous frames
  // in the muxed timeline (no gap or overlap).
  //
  // Rotation: we rotate pixels at composite time (compositeFrame) so
  // the output frames are upright. Pass rotation: 0 so the muxer
  // writes an identity tkhd matrix — players don't apply any
  // additional rotation.
  const output = new Output({
    format: new Mp4OutputFormat({ fastStart: 'in-memory' }),
    target: new BufferTarget(),
  });
  let outputFinalized = false;

  const videoPacketSource = new EncodedVideoPacketSource(outputCodecFamily);
  output.addVideoTrack(videoPacketSource, {
    rotation:  0,
    frameRate: muxerFrameRate,
  });
  let audioPacketSource = null;
  if (hasAudio) {
    audioPacketSource = new EncodedAudioPacketSource('aac');
    output.addAudioTrack(audioPacketSource);
  }
  await output.start();

  let encoderError = null;
  let firstVideoMetaSent = false;
  const encoder = new VideoEncoder({
    output: (chunk, meta) => {
      try {
        const packet = EncodedPacket.fromEncodedChunk(chunk);
        const m = firstVideoMetaSent ? undefined : meta;
        firstVideoMetaSent = true;
        videoPacketSource.add(packet, m).catch((e) => {
          encoderError = e;
        });
      } catch (e) {
        encoderError = e;
      }
    },
    error: (e) => { encoderError = e; },
  });
  encoder.configure(encConfig);

  // Pre-check decoder support once (chapters share codec config, so a
  // single probe answers for all of them).
  const decoderCfg = {
    codec:        videoInfo.codecParameterString,
    description:  videoInfo.description,
    codedWidth:   videoInfo.width,
    codedHeight:  videoInfo.height,
  };
  try {
    const support = await VideoDecoder.isConfigSupported(decoderCfg);
    if (!support.supported) {
      sim.delete();
      const what = videoInfo.codec === 'hevc' ? 'HEVC (h.265)' :
                   `codec "${videoInfo.codecParameterString}"`;
      throw new Error(
        `Browser cannot decode ${what}. Try Chrome ≥107 with hardware ` +
        `HEVC support, or transcode the source to H.264 first.`);
    }
  } catch (e) {
    if (e?.message?.startsWith('Browser cannot decode')) throw e;
    sim.delete();
    throw new Error(`VideoDecoder.isConfigSupported failed: ${e?.message || e}`);
  }

  // Cumulative output offset (seconds) anchored at clip-start. Each
  // segment writes packets with output ts = segmentOutOffsetSec +
  // (sampleLocalCts - segment.localStartSec). For a within-window
  // sample at the clip's first segment, segmentOutOffsetSec is 0 and
  // out-ts walks 0..N. For segment 2, segmentOutOffsetSec equals the
  // first segment's encoded duration, so timestamps stay monotone.
  let cumulativeOutSec = 0;
  // Total output frame count across all segments; computed as we
  // discover output samples per segment. Used for the progress callback
  // — onProgress fires per-frame; totalFrames is an upper bound we
  // refine as we go (segment 1 we know, later segments we update).
  let totalFrames = 0;
  let slotsEncoded = 0;
  // Keyframe cadence in output frames. Each segment starts with its
  // own keyframe naturally (decode anchor), but we also force a keyframe
  // every ~1 second to keep seeking responsive in the output.
  const keyframeStride = Math.max(1, Math.round(resolvedFps));

  // Audio cumulative offset. We re-anchor each segment's first AAC
  // packet to cumulativeOutSec at the time the segment runs.
  let audioCumulativeOutSec = 0;
  // Track audio meta state across segments — only the first push needs
  // decoderConfig.
  let audioMetaSent = false;

  try {
    // -------- Per-segment loop --------------------------------------
    // Each iteration: open a fresh Input (one chapter file), set up a
    // fresh VideoDecoder, demux video packets [localStart, localEnd],
    // decode + composite + encode. Audio packets within the same
    // window get re-anchored and pushed to the shared output's audio
    // source.
    for (let segIdx = 0; segIdx < segments.length; segIdx++) {
      if (signal?.aborted) throw new DOMException('aborted', 'AbortError');
      const seg = segments[segIdx];

      // Fresh Input per segment, including segment 0 — the probe
      // Input is already in `openedInputs` for `finally`-time close.
      // Independent Inputs give each EncodedPacketSink its own track
      // cursor, avoiding any aliasing with the probe walk.
      const segInput = openInput(seg.file);
      openedInputs.push(segInput);
      const segVideoInfo = await readVideoTrackInfo(segInput);
      if (!segVideoInfo) {
        throw new Error(`Chapter ${seg.chapterIndex}: no decodable video track.`);
      }
      const segAudioInfo = hasAudio
        ? await readAudioTrackInfo(segInput)
        : null;

      const segVideoSink = new EncodedPacketSink(segVideoInfo.track);
      const anchorKey =
        (await segVideoSink.getKeyPacket(seg.localStartSec)) ||
        (await segVideoSink.getPacket(0));
      if (!anchorKey) {
        throw new Error(`Chapter ${seg.chapterIndex}: video track has no packets.`);
      }

      // Collect packets for this segment's [localStart, localEnd) range.
      const segPackets = [];
      for await (const packet of segVideoSink.packets(anchorKey)) {
        if (signal?.aborted) throw new DOMException('aborted', 'AbortError');
        if (packet.timestamp >= seg.localEndSec) break;
        const inWindow =
          (packet.timestamp + packet.duration > seg.localStartSec) &&
          (packet.timestamp < seg.localEndSec);
        segPackets.push({
          data:      packet.data,
          type:      packet.type,
          timestamp: packet.timestamp,
          duration:  packet.duration,
          output:    inWindow,
        });
      }
      if (segPackets.length === 0) {
        // No samples in this segment's window; skip cleanly. Can happen
        // if the clip ends almost exactly at a chapter boundary.
        continue;
      }
      const segOutputSamples = segPackets.filter(p => p.output);
      if (segOutputSamples.length === 0) continue;
      totalFrames += segOutputSamples.length;

      // Frame queue + decoder per segment. Fresh state for each chapter
      // — codec config stays the same across chapters by assumption,
      // but a new decoder avoids any internal-state contamination from
      // the previous chapter's trailing frames.
      const frameQueue = [];
      let decoderError = null;
      const insertFrame = (frame) => {
        const ts = frame.timestamp;
        let lo = 0, hi = frameQueue.length;
        while (lo < hi) {
          const mid = (lo + hi) >>> 1;
          if (frameQueue[mid].timestamp <= ts) lo = mid + 1;
          else hi = mid;
        }
        frameQueue.splice(lo, 0, frame);
      };
      const decoder = new VideoDecoder({
        output: (frame) => {
          if (decoderError) { frame.close(); return; }
          // Drop decode-context frames whose timestamp falls before
          // the segment's clip window. For segment 0 these often have
          // a negative timestamp (pre-zero seed frames). For later
          // segments timestamps are positive but still below the
          // window start (the prior chapter's tail-anchor decoding
          // catches us up). Either way, they exist only to warm the
          // decoder and never reach the output.
          if (frame.timestamp < 0) {
            frame.close();
            return;
          }
          insertFrame(frame);
        },
        error: (e) => { decoderError = e; },
      });
      decoder.configure(decoderCfg);

      // Anchor video timestamps at this segment's first output sample's
      // cts. Combined with cumulativeOutSec, the muxer sees a monotone
      // t=0-origin timeline across segments.
      const firstWindowLocalTs = segOutputSamples[0].timestamp;
      const toOutTsUs = (srcSec) =>
        Math.round(
          (cumulativeOutSec + (srcSec - firstWindowLocalTs)) * 1_000_000
        );
      const toOutDurUs = (srcDurSec) =>
        Math.max(1, Math.round(srcDurSec * 1_000_000));

      let feedError = null;
      const feedDone = (async () => {
        for (let i = 0; i < segPackets.length; i++) {
          if (signal?.aborted) throw new DOMException('aborted', 'AbortError');
          if (decoderError) throw decoderError;
          while (decoder.decodeQueueSize + frameQueue.length > 64) {
            if (signal?.aborted) throw new DOMException('aborted', 'AbortError');
            // eslint-disable-next-line no-await-in-loop
            await new Promise(r => setTimeout(r, 1));
          }
          const p = segPackets[i];
          const chunk = new EncodedVideoChunk({
            type:      p.type,
            timestamp: toOutTsUs(p.timestamp),
            duration:  toOutDurUs(p.duration),
            data:      p.data,
          });
          decoder.decode(chunk);
          segPackets[i].data = null;
        }
        await decoder.flush();
      })();
      feedDone.catch((e) => { feedError = e; });

      // Audio for this segment: re-anchor at the first muxed packet's
      // local ts, offset by audioCumulativeOutSec so the output audio
      // timeline stays monotone across segment boundaries.
      let audioPromise = null;
      if (hasAudio && segAudioInfo && audioPacketSource) {
        audioPromise = feedAacSegmentToOutput({
          audioSource:    audioPacketSource,
          audioInfo:      segAudioInfo,
          clampedStart:   seg.localStartSec,
          clampedEnd:     seg.localEndSec,
          outOffsetSec:   audioCumulativeOutSec,
          metaAlreadySent: audioMetaSent,
          signal,
        }).then((res) => {
          if (res && !res.skipped) {
            audioMetaSent = true;
            audioCumulativeOutSec += res.addedSec;
          }
          return res;
        });
      }

      // Encode loop for this segment's output samples.
      let segEncodedSec = 0;
      for (let i = 0; i < segOutputSamples.length; i++) {
        if (signal?.aborted) throw new DOMException('aborted', 'AbortError');
        if (decoderError) throw decoderError;
        if (feedError && !(feedError.name === 'AbortError')) throw feedError;
        if (encoderError) throw encoderError;

        const s = segOutputSamples[i];
        const sampleLocalCts = s.timestamp;             // seconds in this chapter
        const sampleGlobalSec =
          seg.globalStartSec + (sampleLocalCts - seg.localStartSec);
        const targetTsUs = toOutTsUs(sampleLocalCts);

        // eslint-disable-next-line no-await-in-loop
        let frame = await waitForFrameAtOrBefore(
          frameQueue, targetTsUs, feedDone, signal);

        if (!frame) {
          ctx.fillStyle = '#000';
          ctx.fillRect(0, 0, W, H);
        }

        // Drive sim from the GLOBAL video time of this sample, mapped
        // back to log time via the same sync anchor used everywhere.
        const targetVirtMs = Math.max(0, sampleGlobalSec * 1000);
        driveSimToVirtMs(sim, simState, targetVirtMs, log, sync, cppWireFrames);
        let rawState = sim.read();
        let m5State  = rawState;
        if (presFilter && rawState) {
          const dtSec = s.duration;
          const smoothed = presFilter.apply(rawState.LateralG, rawState.VerticalG, dtSec);
          m5State = Object.freeze({
            ...rawState,
            LateralG:  Number.isFinite(smoothed.lateralG)  ? smoothed.lateralG  : rawState.LateralG,
            VerticalG: Number.isFinite(smoothed.verticalG) ? smoothed.verticalG : rawState.VerticalG,
          });
        }

        const overlays = [];
        // HUD goes first so corner panels composite on top of it in
        // the canvas drawImage order.
        if (renderHudSvg) {
          try {
            const hudSvg = renderHudSvg(m5State);
            if (hudSvg) {
              // eslint-disable-next-line no-await-in-loop
              const hudImg = await svgToImage(hudSvg);
              if (hudImg) overlays.push({ img: hudImg, position: 'fullframe' });
            }
          } catch (e) {
            // eslint-disable-next-line no-console
            console.warn('HUD raster failed for frame', i, e);
          }
        }
        const renderOne = async (displayType, position) => {
          try {
            const svgEl = renderOverlaySvg ? renderOverlaySvg(m5State, displayType) : null;
            if (svgEl) {
              // eslint-disable-next-line no-await-in-loop
              const img = await svgToImage(svgEl);
              if (img) overlays.push({ img, position });
            }
          } catch (e) {
            // eslint-disable-next-line no-console
            console.warn('overlay raster failed for frame', i, e);
          }
        };
        if (standardOverlay) {
          await renderOne(1, 'left');   // ADI / Attitude
          await renderOne(0, 'right');  // Energy
        } else {
          await renderOne(undefined, 'right');
        }

        if (frame) compositeFrame(ctx, frame, overlays, W, H, segVideoInfo.rotationDeg);
        else if (overlays.length > 0) compositeFrame(ctx, null, overlays, W, H, 0);

        if (frame) { try { frame.close(); } catch (_) {} }

        while (encoder.encodeQueueSize > 4) {
          if (signal?.aborted) throw new DOMException('aborted', 'AbortError');
          // eslint-disable-next-line no-await-in-loop
          await new Promise(r => setTimeout(r, 0));
        }
        if (encoderError) throw encoderError;

        const outTsUs  = targetTsUs;
        const outDurUs = toOutDurUs(s.duration);
        // Force keyframe at every segment boundary (i === 0 here) AND
        // at the keyframeStride cadence. The decoder restart-per-segment
        // can't reuse old reference frames, so a key at the boundary
        // also matches what the encoder would have done naturally.
        const isKey = (i === 0) || (slotsEncoded % keyframeStride === 0);
        const outFrame = new VideoFrame(canvas, { timestamp: outTsUs, duration: outDurUs });
        encoder.encode(outFrame, { keyFrame: isKey });
        outFrame.close();

        slotsEncoded++;
        segEncodedSec = (sampleLocalCts - firstWindowLocalTs) + s.duration;
        if (onProgress) {
          onProgress({
            frame:      slotsEncoded,
            totalFrames,
            encodedSec: cumulativeOutSec + segEncodedSec,
            totalSec,
          });
        }
      }

      try { await feedDone; }
      catch (e) {
        if (e?.name === 'AbortError') throw e;
        console.warn('video demux feed finished with:', e?.message || e);
      }
      if (audioPromise) {
        try { await audioPromise; }
        catch (e) {
          if (e?.name === 'AbortError') throw e;
          // eslint-disable-next-line no-console
          console.warn(`audio mux failed for chapter ${seg.chapterIndex}, exporting silent for this segment:`, e);
        }
      }

      // Close per-segment decoder + drop any leftover frames.
      for (const f of frameQueue) { try { f.close(); } catch (_) {} }
      frameQueue.length = 0;
      try { decoder.state !== 'closed' && decoder.close(); } catch (_) {}

      cumulativeOutSec += segEncodedSec;
    }

    if (slotsEncoded === 0) {
      throw new Error('No video samples overlap the clip window.');
    }

    await encoder.flush();
    if (encoderError) throw encoderError;
    encoder.close();

    await output.finalize();
    outputFinalized = true;

    const buffer = output.target.buffer;
    if (!buffer) throw new Error('Output produced no buffer.');
    return new Blob([buffer], { type: 'video/mp4' });
  } finally {
    try { encoder.state !== 'closed' && encoder.close(); } catch (_) {}
    if (!outputFinalized) {
      try { await output.cancel(); } catch (_) {}
    }
    // Close every Mediabunny Input we opened. Each wraps a BlobSource
    // with internal byte-range caches; leaving them for GC could
    // hold MBs of ArrayBuffer per chapter across a 4-chapter export.
    for (const inp of openedInputs) {
      try { inp.close?.(); } catch (_) {}
    }
    try { sim.delete(); } catch (_) {}
  }
}

// Wait for the queue to contain a frame whose timestamp is the
// largest <= targetTsUs, AND for that frame's successor (or feed
// drain) to be observed so we know the choice is final. Returns the
// chosen frame (popped from the queue) or null if no frame can serve
// the target (feed drained, nothing at-or-before target).
//
// Frames with timestamp < targetTsUs but not the chosen one are
// closed and discarded — they're earlier than the current slot and
// can't serve later slots either (slots only advance forward).
async function waitForFrameAtOrBefore(frameQueue, targetTsUs, feedDone, signal) {
  let feedFinished = false;
  feedDone.then(() => { feedFinished = true; }, () => { feedFinished = true; });

  while (true) {
    if (signal?.aborted) throw new DOMException('aborted', 'AbortError');

    // Find the chosen frame: largest timestamp <= targetTsUs.
    // We can finalize the choice when:
    //   (a) the queue has a frame with timestamp > targetTsUs
    //       (proving no later-arriving in-order frame can beat the
    //       current best), OR
    //   (b) the feed has fully drained (no more frames can arrive).
    let chosenIdx = -1;
    let hasFuture = false;
    for (let i = 0; i < frameQueue.length; i++) {
      const ts = frameQueue[i].timestamp;
      if (ts <= targetTsUs) chosenIdx = i;
      else { hasFuture = true; break; }
    }

    if (hasFuture || feedFinished) {
      if (chosenIdx < 0) return null;
      const chosen = frameQueue[chosenIdx];
      // Close + drop frames strictly before chosen — they're now
      // unreachable (slots only advance forward).
      for (let i = 0; i < chosenIdx; i++) {
        try { frameQueue[i].close(); } catch (_) {}
      }
      frameQueue.splice(0, chosenIdx + 1);
      return chosen;
    }

    // Queue currently empty or only has candidates <= target;
    // wait for more frames.
    await new Promise(r => setTimeout(r, 1));
  }
}

// Trigger a browser download for a Blob.
function downloadBlob(blob, filename) {
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = filename;
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);
  setTimeout(() => URL.revokeObjectURL(url), 60_000);
}

// Pure-logic helpers exported for unit testing.
function clipToVideoWindow(clip, sync, videoDurationSec) {
  if (!clip || !sync) return null;
  if (!Number.isFinite(sync.logTakeoffMs) ||
      !Number.isFinite(sync.videoTakeoffSec)) return null;
  if (!Number.isFinite(clip.startMs) || !Number.isFinite(clip.endMs)) return null;
  if (clip.endMs <= clip.startMs) return null;
  const startVideoSec = sync.videoTakeoffSec + (clip.startMs - sync.logTakeoffMs) / 1000;
  const endVideoSec   = sync.videoTakeoffSec + (clip.endMs   - sync.logTakeoffMs) / 1000;
  const start = Math.max(0, startVideoSec);
  const end   = Number.isFinite(videoDurationSec) ? Math.min(videoDurationSec, endVideoSec) : endVideoSec;
  if (end <= start) return null;
  return { startVideoSec: start, endVideoSec: end };
}

function expectedFrameCount(clipDurationSec, frameRate) {
  if (!Number.isFinite(clipDurationSec) || clipDurationSec <= 0) return 0;
  if (!Number.isFinite(frameRate) || frameRate <= 0) return 0;
  return Math.max(1, Math.round(clipDurationSec * frameRate));
}

// ---------------------------------------------------------------------
// Overlay-only export: render JUST the M5 mode panel against a
// chroma-key background (no source video involved). Optimised to
// render N modes in one pass — shared sim + presentation filter,
// parallel encoders. Output is one MP4 per mode, ready to drop into
// an NLE for chroma-key compositing over GoPro footage.
// ---------------------------------------------------------------------

// Mode-id string → M5Sim displayType int. The five modes the M5
// firmware supports; matches M5_MODES in ReplayPage.js.
const OVERLAY_MODE_IDS = Object.freeze({
  'energy':     0,
  'attitude':   1,
  'indexer':    2,
  'decel':      3,
  'historic-g': 4,
});

// Order the UI lists modes in — matches the M5 firmware's BtnB-cycle
// order (kModeNames[5]) and the live page's mode-selector radio row.
// Pilots already have muscle memory for "Energy first" from the
// hardware display, so matching that here keeps the workflow obvious.
const OVERLAY_MODE_ORDER = Object.freeze([
  'energy',     // 0
  'attitude',   // 1
  'indexer',    // 2
  'decel',      // 3
  'historic-g', // 4
]);

// Feature gate. Overlay-only export only needs VideoEncoder +
// OffscreenCanvas — no VideoDecoder (no source video to demux).
function isOverlayExportSupported() {
  if (typeof window === 'undefined') return false;
  if (!('VideoEncoder' in window)) return false;
  if (!('OffscreenCanvas' in window)) return false;
  return true;
}

// Pick an H.264 encoder config for overlay-only output. Simpler than
// the source-faithful pipeline: no source codec to match, so we go
// straight to H.264 High profile (broadest NLE compat).
async function pickOverlayEncoderConfig({ width, height, bitrate, framerate }) {
  const w = Math.max(2, Math.floor(width  / 2) * 2);
  const h = Math.max(2, Math.floor(height / 2) * 2);
  const candidates = [
    { codec: 'avc1.640033', width: w, height: h, bitrate, framerate, avc: { format: 'avc' } },
    { codec: 'avc1.640028', width: w, height: h, bitrate, framerate, avc: { format: 'avc' } },
    { codec: 'avc1.42E028', width: w, height: h, bitrate, framerate, avc: { format: 'avc' } },
  ];
  for (const cfg of candidates) {
    try {
      const r = await VideoEncoder.isConfigSupported(cfg);
      if (r.supported) return r.config;
    } catch (_) { /* try next */ }
  }
  throw new Error(`No supported H.264 encoder config at ${w}x${h}.`);
}

// Composite the overlay SVG into the entire canvas. In native-dimensions
// mode (default), the canvas IS the M5 panel — same 320×240 pixel grid
// the hardware draws to, same black background that the avionics SVG
// renders against. There's no padding, no chroma key, no "video to
// composite onto" — the output IS the M5 panel as a video.
//
// Vac drops this into his NLE on top of his GoPro footage, scales /
// positions to taste. iMovie, Final Cut, Premiere, Resolve all treat
// the black panel correctly — it sits over the underlying video like
// a real cockpit instrument.
//
// `background` is the canvas fill before the overlay draws. Default
// '#000' matches the M5's --panel-bg. Set to a chroma color if the
// caller wants the legacy chroma-key fallback.
function compositeOverlayNative(ctx, overlayImg, background, W, H) {
  ctx.fillStyle = background;
  ctx.fillRect(0, 0, W, H);
  if (!overlayImg) return;
  // Overlay SVG viewBox is 0 0 M5_PANEL_W M5_PANEL_H (320×240). When
  // canvas dims match the panel exactly, this draws at 1:1; when the
  // canvas is scaled (e.g. user opted into 1080p), the SVG scales
  // proportionally — the aspect matches, so no letterboxing.
  ctx.drawImage(overlayImg, 0, 0, W, H);
}

// One encoder + Mediabunny output + canvas, scoped to a single mode.
// The frame loop instantiates one of these per mode requested. Each
// has its own VideoEncoder back-pressure queue; sharing a single
// encoder across modes would serialise the per-mode encode work
// pointlessly.
class OverlayModeEncoder {
  constructor({ modeId, encConfig, W, H, framerate }) {
    this.modeId = modeId;
    this.W = W;
    this.H = H;
    this.canvas = new OffscreenCanvas(W, H);
    this.ctx    = this.canvas.getContext('2d');
    this.output = new Output({
      format: new Mp4OutputFormat({ fastStart: 'in-memory' }),
      target: new BufferTarget(),
    });
    this.videoSource = new EncodedVideoPacketSource('avc');
    this.output.addVideoTrack(this.videoSource, {
      rotation:  0,
      frameRate: framerate,
    });
    this.error = null;
    let firstMetaSent = false;
    this.encoder = new VideoEncoder({
      output: (chunk, meta) => {
        try {
          const packet = EncodedPacket.fromEncodedChunk(chunk);
          const m = firstMetaSent ? undefined : meta;
          firstMetaSent = true;
          this.videoSource.add(packet, m).catch((e) => { this.error = e; });
        } catch (e) { this.error = e; }
      },
      error: (e) => { this.error = e; },
    });
    this.encoder.configure(encConfig);
    this.framesEncoded = 0;
    this.started = false;
    // Set true once output.finalize() resolves. Used by closeOnError
    // to skip cancel() on already-finalized outputs (which would log
    // a benign but noisy "already finalized" warning).
    this.finalized = false;
  }

  async start() {
    await this.output.start();
    this.started = true;
  }

  async finalize() {
    if (this.error) throw this.error;
    await this.encoder.flush();
    if (this.error) throw this.error;
    this.encoder.close();
    await this.output.finalize();
    this.finalized = true;
    const buffer = this.output.target.buffer;
    if (!buffer) throw new Error(`Output for "${this.modeId}" produced no buffer.`);
    return new Blob([buffer], { type: 'video/mp4' });
  }

  async closeOnError() {
    try { if (this.encoder.state !== 'closed') this.encoder.close(); } catch (_) {}
    // Only cancel the Output if we're bailing out before finalize.
    // Post-finalize cancel() logs a benign warning. Wrapped so a
    // teardown error can't shadow the original failure.
    if (!this.finalized) {
      try { await this.output.cancel(); } catch (_) {}
    }
  }
}

// Per-frame timing instrumentation. The caller-facing onProgress
// callback exposes aggregated counts; this object accumulates totals
// for the final report.
function newTimingsBag() {
  return { simMs: 0, renderMs: 0, encodeMs: 0, frames: 0 };
}

// Public API: render overlay-only MP4s for one or more modes.
//
// Options:
//   clip:               { startMs, endMs, label? } — required.
//   sync:               { logTakeoffMs, videoTakeoffSec } — required.
//   log:                parsed log — required.
//   cppWireFrames:      pre-pass output { frames: Uint8Array[] } — required.
//   renderOverlaySvg:   (m5State, displayTypeOverride?) → SVGElement.
//                       The override lets us render a different mode
//                       per encoder while reusing one sim state. The
//                       ReplayPage callback is backwards-compatible:
//                       if it ignores the override, only m5State.displayType
//                       is used (existing source-faithful path).
//   modes:              string[] of mode-id strings from OVERLAY_MODE_IDS.
//                       Defaults to all five in OVERLAY_MODE_ORDER.
//   sourceVideoInfo:    { width, height, frameRate } | null — used as
//                       the default output res/fps if outputWidth /
//                       outputHeight / framerate are omitted. Pass
//                       videoEl.videoWidth/etc. from the page, or null.
//   presentationTau:    same shape as exportClipAsMp4 — mirror live
//                       preview's slip-ball smoothing.
//   background:         CSS color string for the canvas background.
//                       Default '#000' — matches the M5's own panel
//                       background. The output IS the M5 panel as a
//                       video; Vac composites it on top of his footage
//                       in his NLE. Pass a chroma color (e.g.
//                       '#00ff00') if you specifically want chroma-key.
//   outputWidth/Height: explicit output dims. Default = M5 panel native
//                       dimensions (320×240). The avionics SVG renders
//                       to exactly this pixel grid (it's the M5
//                       hardware's screen size), so the default is
//                       lossless 1:1 — no upscale, no downscale.
//                       Override to render bigger (e.g. 1920×1440)
//                       for callers that want pre-scaled output.
//   framerate:          override the encode frame rate. Default = 30.
//   bitrate:            override the encoder bitrate. null = compute
//                       from output dims + fps via computeBitrate.
//   durationSec:        clip duration in seconds. Default = computed
//                       from clip.startMs/endMs.
//   onProgress:         ({ mode, frame, totalFrames, encodedSec, totalSec })
//                       → void. Called once per (mode, frame).
//   signal:             AbortSignal | null.
//
// Returns: Promise<Map<modeId, Blob>>.
async function exportOverlayOnly({
  clip,
  sync,
  log,
  cppWireFrames,
  renderOverlaySvg,
  modes             = null,
  sourceVideoInfo   = null,
  presentationTau   = null,
  background        = '#000',
  outputWidth       = null,
  outputHeight      = null,
  framerate         = null,
  bitrate           = null,
  durationSec       = null,
  onProgress        = null,
  signal            = null,
} = {}) {
  if (!isOverlayExportSupported()) {
    throw new Error(
      'Overlay-only export requires Chrome or Edge desktop. WebCodecs ' +
      'VideoEncoder + OffscreenCanvas needed.');
  }
  if (!clip) throw new Error('exportOverlayOnly: clip required');
  if (!sync || !Number.isFinite(sync.logTakeoffMs) ||
      !Number.isFinite(sync.videoTakeoffSec)) {
    throw new Error('exportOverlayOnly: complete sync anchor required.');
  }
  if (!log) throw new Error('exportOverlayOnly: log required');
  if (!cppWireFrames || !cppWireFrames.frames) {
    throw new Error('exportOverlayOnly: cppWireFrames required.');
  }
  if (!renderOverlaySvg) {
    throw new Error('exportOverlayOnly: renderOverlaySvg callback required.');
  }

  // Resolve mode list. Each entry is an { id, displayType } pair.
  const requested = (modes && modes.length > 0) ? modes : OVERLAY_MODE_ORDER;
  const modeList = [];
  for (const m of requested) {
    if (!(m in OVERLAY_MODE_IDS)) {
      throw new Error(`exportOverlayOnly: unknown mode id "${m}". ` +
        `Known: ${Object.keys(OVERLAY_MODE_IDS).join(', ')}.`);
    }
    modeList.push({ id: m, displayType: OVERLAY_MODE_IDS[m] });
  }
  if (modeList.length === 0) {
    throw new Error('exportOverlayOnly: at least one mode required.');
  }

  // Resolve output dims + framerate. The default is the M5 panel's
  // native pixel grid (320×240) — same as the M5 hardware screen, same
  // as the avionics SVG viewBox. Rendered at 1:1, the output IS the
  // M5 panel as a video. Caller can override (e.g. for 1080p prescaled
  // output) but most workflows want native: Vac scales in the NLE.
  const srcFps = sourceVideoInfo?.frameRate;
  let W = outputWidth  || M5_PANEL_W;
  let H = outputHeight || M5_PANEL_H;
  W = Math.max(2, Math.floor(W / 2) * 2);
  H = Math.max(2, Math.floor(H / 2) * 2);
  const fps = (Number.isFinite(framerate) && framerate > 0)
    ? framerate
    : (Number.isFinite(srcFps) && srcFps > 0 ? srcFps : DEFAULT_FRAMERATE);
  const muxerFps = Math.max(1, Math.round(fps));
  const resolvedBitrate = (Number.isFinite(bitrate) && bitrate > 0)
    ? bitrate
    : computeBitrate(W, H, fps);

  // Clip duration.
  const clipDurSec = (Number.isFinite(durationSec) && durationSec > 0)
    ? durationSec
    : (clip.endMs - clip.startMs) / 1000;
  if (!Number.isFinite(clipDurSec) || clipDurSec <= 0) {
    throw new Error('exportOverlayOnly: clip has zero or invalid duration.');
  }

  // ----------- Sim + presentation filter (shared across modes) -----
  const sim = await M5Sim.create();
  if (signal?.aborted) { sim.delete(); throw new DOMException('aborted', 'AbortError'); }
  const simState = { lastVirtMs: 0, lastBoundaryMs: 0 };
  let presFilter = null;
  if (presentationTau &&
      (presentationTau.lateralSec > 0 || presentationTau.verticalSec > 0)) {
    presFilter = new PresentationFilter();
    presFilter.setTau({
      lateralSec:  presentationTau.lateralSec  || 0,
      verticalSec: presentationTau.verticalSec || 0,
    });
  }

  // ----------- Per-mode encoder set --------------------------------
  // Pick the encoder config ONCE (same dims for all modes) then
  // clone it into one encoder + Output per mode. Mediabunny's Output
  // and WebCodecs' VideoEncoder are both independent instances, so
  // running N in parallel is safe.
  const encConfig = await pickOverlayEncoderConfig({
    width: W, height: H, bitrate: resolvedBitrate, framerate: fps,
  });

  const modeEncoders = new Map(); // modeId → OverlayModeEncoder
  try {
    for (const m of modeList) {
      const me = new OverlayModeEncoder({
        modeId: m.id, encConfig, W, H, framerate: muxerFps,
      });
      // eslint-disable-next-line no-await-in-loop
      await me.start();
      modeEncoders.set(m.id, me);
    }

    // ----------- Frame loop ---------------------------------------
    // Walk output slots at CFR (1/fps spacing). Per slot: drive sim
    // once, smooth once, then for each mode render the SVG and
    // encode. svgToImage is the dominant per-frame cost — it does a
    // round-trip through a Blob URL + <img> decode for every mode.
    const totalFrames = Math.max(1, Math.round(clipDurSec * fps));
    const dtUs = Math.round(1_000_000 / fps);
    const dtSec = 1 / fps;
    const keyframeStride = Math.max(1, Math.round(fps));

    // Sim virtual time anchor: clip.startMs in log-time. We use the
    // log timeline directly (not video time) — the overlay only
    // cares about log values, no video sample alignment to honour.
    // Pre-pass build keeps state.lastVirtMs at clip-start as the
    // sim's t=0.
    const simStartVirtMs = 0;
    simState.lastVirtMs    = simStartVirtMs;
    simState.lastBoundaryMs = 0;

    // For each frame slot, virtual ms = (frame / fps) * 1000.
    // driveSimToVirtMs converts this back to a log row via
    // sync — but the sync.videoTakeoffSec is in VIDEO time, and we
    // don't have video here. We build a synthetic sync that maps
    // virtMs directly to log time anchored at clip.startMs.
    const syntheticSync = {
      logTakeoffMs:    clip.startMs,
      videoTakeoffSec: 0,
    };

    const aggregateTimings = newTimingsBag();
    let lastReportedAt = performance.now();

    for (let f = 0; f < totalFrames; f++) {
      if (signal?.aborted) throw new DOMException('aborted', 'AbortError');

      // Check per-mode encoder errors before doing more work.
      for (const enc of modeEncoders.values()) {
        if (enc.error) throw enc.error;
      }

      const virtMs = (f / fps) * 1000;
      const tsUs   = f * dtUs;
      const isKey  = (f % keyframeStride) === 0;

      // -------- Sim drive (once per frame, all modes share) -------
      const t0 = performance.now();
      driveSimToVirtMs(sim, simState, virtMs, log, syntheticSync, cppWireFrames);
      let rawState = sim.read();
      let m5State  = rawState;
      if (presFilter && rawState) {
        const smoothed = presFilter.apply(rawState.LateralG, rawState.VerticalG, dtSec);
        m5State = Object.freeze({
          ...rawState,
          LateralG:  Number.isFinite(smoothed.lateralG)  ? smoothed.lateralG  : rawState.LateralG,
          VerticalG: Number.isFinite(smoothed.verticalG) ? smoothed.verticalG : rawState.VerticalG,
        });
      }
      aggregateTimings.simMs += performance.now() - t0;

      // -------- Per-mode SVG render → composite → encode ---------
      for (const m of modeList) {
        if (signal?.aborted) throw new DOMException('aborted', 'AbortError');
        const enc = modeEncoders.get(m.id);
        if (enc.error) throw enc.error;

        // Encoder back-pressure (per-mode queue).
        while (enc.encoder.encodeQueueSize > 4) {
          if (signal?.aborted) throw new DOMException('aborted', 'AbortError');
          // eslint-disable-next-line no-await-in-loop
          await new Promise(r => setTimeout(r, 0));
        }

        // Render: override displayType so the SVG renders THIS
        // mode regardless of which mode the live sim is in.
        const tR = performance.now();
        let overlayImg = null;
        try {
          // eslint-disable-next-line no-await-in-loop
          const svgEl = renderOverlaySvg(m5State, m.displayType);
          if (svgEl) {
            // eslint-disable-next-line no-await-in-loop
            overlayImg = await svgToImage(svgEl);
          }
        } catch (e) {
          console.warn(`overlay raster failed for ${m.id} frame ${f}:`, e);
        }
        aggregateTimings.renderMs += performance.now() - tR;

        const tC = performance.now();
        compositeOverlayNative(enc.ctx, overlayImg, background, W, H);
        const outFrame = new VideoFrame(enc.canvas, {
          timestamp: tsUs, duration: dtUs,
        });
        enc.encoder.encode(outFrame, { keyFrame: isKey });
        outFrame.close();
        aggregateTimings.encodeMs += performance.now() - tC;
        enc.framesEncoded++;

      }

      // Report progress once per frame (not once per mode). Aggregate
      // across modes so the bar advances smoothly instead of flashing
      // 5 times per frame. `framesEncoded` counts encoded *output*
      // slots (one per frame, regardless of how many modes are
      // simultaneously encoding). `totalFrames` is also per-mode, so
      // the ratio is the same for every mode — no mode-switch flicker.
      if (onProgress) {
        onProgress({
          // No `mode` field: this is a multi-mode aggregate report.
          // The page-side label can show "exporting N modes" instead
          // of cycling through individual mode IDs.
          frame:      f + 1,
          totalFrames,
          modeCount:  modeList.length,
          encodedSec: ((f + 1) * dtUs) / 1_000_000,
          totalSec:   clipDurSec,
        });
      }
      aggregateTimings.frames++;

      // Yield to the event loop periodically so the page doesn't
      // freeze. Every ~250 ms of wall-clock work; cheaper than once
      // per frame.
      const now = performance.now();
      if (now - lastReportedAt > 250) {
        lastReportedAt = now;
        // eslint-disable-next-line no-await-in-loop
        await new Promise(r => setTimeout(r, 0));
      }
    }

    // ----------- Finalize all encoders + collect blobs -------------
    const blobs = new Map();
    for (const [id, enc] of modeEncoders) {
      // eslint-disable-next-line no-await-in-loop
      const blob = await enc.finalize();
      blobs.set(id, blob);
    }

    // Stash timings on the returned map for the report. Maps allow
    // an extra symbol-keyed property; we attach via a plain field.
    blobs.__timings = aggregateTimings;
    return blobs;
  } finally {
    // Best-effort teardown. closeOnError is async (it awaits
    // output.cancel()), so we await all of them in parallel before
    // tearing the sim down. Wrapping in a single catch so one
    // encoder's failure doesn't prevent the others from cleaning up.
    try {
      await Promise.all(
        Array.from(modeEncoders.values()).map(enc => enc.closeOnError()),
      );
    } catch (_) {}
    try { sim.delete(); } catch (_) {}
  }
}

// Exported for tests + diagnostics. The rotation helper in particular
// is non-trivial enough (fixed-point vs float, sign-disambiguation
// across four cardinal angles) that round-tripping a few canonical
// matrices belongs in the test suite. Mediabunny exposes the result
// directly via `track.getRotation()` in production code, but the
// helper round-trips the same algebra against canonical matrices in
// the smoke tests to lock the rotation semantics.



const MP4_EXPORT_INTERNAL = Object.freeze({
  M5_TICK_MS,
  M5_LARGE_JUMP_MS,
  DEFAULT_FRAMERATE,
});

// === docs/site/docs/data-and-logs/replay/lib/replay/clipContains.js ===
// clipContains — pure helper for the "Contains: Mark NN, Mark NN" line
// shown in an expanded clip row.
//
// A clip is shaped { startMs, endMs }; a mark is shaped
// { logTimeMs, value, label } per dataMarks.js. The relationship is
// computed on read, never stored — rename or delete a mark and every
// clip's contains-list re-derives for free. See PLAN_FLIGHT_JOURNAL.md
// ("What this rules out") for the rationale.
//
// The range is half-open on the upper end so a clip that ends EXACTLY
// at a mark's logTimeMs does not double-count the mark when an
// adjacent clip starts at the same moment (the "Clip → next" button
// produces this pattern). Pilots reading the inline list see each
// mark assigned to one clip, never two.

function marksWithinClip(clip, marks) {
  if (!clip || !Array.isArray(marks)) return [];
  const { startMs, endMs } = clip;
  if (!Number.isFinite(startMs) || !Number.isFinite(endMs)) return [];
  if (endMs <= startMs) return [];
  const out = [];
  for (const m of marks) {
    if (!m || !Number.isFinite(m.logTimeMs)) continue;
    if (m.logTimeMs >= startMs && m.logTimeMs < endMs) out.push(m);
  }
  return out;
}

// === docs/site/docs/data-and-logs/replay/lib/replay/clipBuilder.js ===
// ClipBuilder — clip-list UI for the replay tool.
//
// Renders the clip list, the in/out marker controls, and per-clip
// editing (label rename, scrub-to-clip, in/out adjust, delete, export).
// The page above owns the clips array; this module is presentational
// glue.
//
// Each clip is shaped { startMs, endMs, label? } in log-time
// milliseconds — the same wire shape Stream A persists.
//
// The page injects two callbacks for the export pipeline:
//   onExportMp4(clip):    kicks off an MP4 export, returns a handle
//                         with `progress` (0..1) and `cancel()`.
//   exportingClipIdx:     number | null — index of the clip currently
//                         being exported (so its row can show progress
//                         in place of the Export button).
//
// The component itself doesn't manage that state — it only renders
// what the parent hands it. Keeps the rendering pure: same props,
// same DOM, no internal effects.



// Debounce window for IDB writes from clip notes — matches the value
// used in DataMarkPanel. Long enough that a typing burst flushes once;
// short enough that a glance-away-and-back finds the row saved.
const CLIP_SAVE_DEBOUNCE_MS = 500;

const CLIP_COLLAPSE_KEY = 'replay-clips-collapsed-v1';

function readClipCollapsed() {
  try { return localStorage.getItem(CLIP_COLLAPSE_KEY) === '1'; }
  catch { return false; }
}
function writeClipCollapsed(v) {
  try { localStorage.setItem(CLIP_COLLAPSE_KEY, v ? '1' : '0'); } catch {}
}

// Stable per-clip identity for journal annotations. UUID-v4 via the
// platform crypto API where available; falls back to a high-entropy
// pseudo-random string for the (rare) test/node-runtime where it
// isn't. Tests don't actually round-trip the value through the journal
// layer, so the fallback only needs to be sortably-unique.
function newClipId() {
  if (typeof crypto !== 'undefined' && typeof crypto.randomUUID === 'function') {
    return crypto.randomUUID();
  }
  const t = Date.now().toString(36);
  const r = Math.random().toString(36).slice(2, 10);
  return `clip-${t}-${r}`;
}

// Map a log timestamp (ms) to a video time (seconds). Inlined here
// rather than imported from dataMarks so the module has no replay
// dependencies (testability + reuse).
function logMsToVideoSec(logMs, sync) {
  if (!sync) return null;
  if (!Number.isFinite(sync.logTakeoffMs) ||
      !Number.isFinite(sync.videoTakeoffSec)) return null;
  return sync.videoTakeoffSec + (logMs - sync.logTakeoffMs) / 1000;
}

// Format a duration in seconds as H:MM:SS or M:SS.
function formatHms(sec) {
  if (!Number.isFinite(sec)) return '—';
  const total = Math.max(0, Math.floor(sec));
  const h = Math.floor(total / 3600);
  const m = Math.floor((total % 3600) / 60);
  const s = total % 60;
  if (h > 0) return `${h}:${String(m).padStart(2,'0')}:${String(s).padStart(2,'0')}`;
  return `${m}:${String(s).padStart(2,'0')}`;
}

// Default label for a new clip. Pads the index so a sort order on
// label is stable; pilots usually rename anyway.
function defaultClipLabel(index) {
  return `clip ${String(index + 1).padStart(2, '0')}`;
}

// Build a clip from a video time + sync, with a configurable duration
// window. Used by both quick-add buttons (30s/60s windows) and the
// mark-in/mark-out flow (no duration; caller passes both ends).
function buildClipFromPlayhead(videoSec, durationSec, sync, label) {
  if (!sync) return null;
  if (!Number.isFinite(sync.logTakeoffMs) ||
      !Number.isFinite(sync.videoTakeoffSec)) return null;
  if (!Number.isFinite(videoSec)) return null;
  const startMs = sync.logTakeoffMs + (videoSec - sync.videoTakeoffSec) * 1000;
  const endMs   = startMs + durationSec * 1000;
  return { id: newClipId(), startMs, endMs, label: label || '' };
}

// Build a clip from explicit in/out video times. Used by the mark-in /
// mark-out flow. Returns null if either is missing or in <= out.
function buildClipFromMarkers(inVideoSec, outVideoSec, sync, label) {
  if (!sync) return null;
  if (!Number.isFinite(sync.logTakeoffMs) ||
      !Number.isFinite(sync.videoTakeoffSec)) return null;
  if (!Number.isFinite(inVideoSec) || !Number.isFinite(outVideoSec)) return null;
  if (outVideoSec <= inVideoSec) return null;
  const startMs = sync.logTakeoffMs + (inVideoSec  - sync.videoTakeoffSec) * 1000;
  const endMs   = sync.logTakeoffMs + (outVideoSec - sync.videoTakeoffSec) * 1000;
  return { id: newClipId(), startMs, endMs, label: label || '' };
}

// Build a clip spanning two DataMarks. Used by the per-DataMark
// "Clip → next" button. Caller supplies both marks; we copy the log
// times directly (no sync round-trip needed — DataMark logTimeMs is
// already in the log timeline).
function buildClipFromMarkToNextMark(thisMark, nextMark, label) {
  if (!thisMark || !nextMark) return null;
  const startMs = thisMark.logTimeMs;
  const endMs   = nextMark.logTimeMs;
  if (!Number.isFinite(startMs) || !Number.isFinite(endMs)) return null;
  if (endMs <= startMs) return null;
  return { id: newClipId(), startMs, endMs, label: label || '' };
}

// Mutate one clip in the list immutably, copying everything else.
// Exported so tests can hit it directly.
function updateClipAt(clips, index, patch) {
  return clips.map((c, i) => (i === index ? { ...c, ...patch } : c));
}

// Remove a clip by index. Exported for tests.
function removeClipAt(clips, index) {
  return clips.filter((_, i) => i !== index);
}

// Clip in/out adjustment: clamp the new value so endMs > startMs by
// at least 100ms. Returns the validated patch, or null if the change
// would produce an invalid window.
//
// Reason for the 100ms floor: a clip with start == end produces an
// empty export, and the encoder errors out late in the pipeline. Catch
// it at the edit site so the pilot sees feedback immediately.
function validateClipEdit(clip, patch) {
  const next = { ...clip, ...patch };
  if (!Number.isFinite(next.startMs) || !Number.isFinite(next.endMs)) return null;
  if (next.endMs - next.startMs < 100) return null;
  return next;
}

// ---- Component ----------------------------------------------------

const ClipBuilder = ({
  clips,
  setClips,
  sync,
  syncReady,
  videoEl,                // for scrub-to-clip
  exportingClipIdx,       // index of the clip currently being exported
  exportProgress,         // 0..1 progress of that export
  exportLabel,            // label of the exporting clip (for status)
  disabled,
  // Callbacks bubbling up to ReplayPage:
  onAddQuick,             // (durationSec)
  onExport,               // (clip)        — single-clip export (composite)
  onExportAll,            // ()            — sequential all-clips export
  onCancel,               // ()            — cancel the running export
  onScrubTo,              // (videoSec)    — seek the live video
  // Mark-in/mark-out flow:
  pendingInVideoSec,      // currently-marked in-point, or null
  onMarkIn,               // ()
  onMarkOut,              // ()
  onCancelMark,           // ()            — discard pendingIn
  mp4Available,           // boolean — feature-detect result
  mp4UnavailableTooltip,  // string — shown on hover when grayed out
  // Overlay-only export — runs alongside the composite path:
  onExportOverlays,       // (clip, idx)  — render selected-modes overlay MP4 batch
  onCancelOverlays,       // ()            — cancel overlay export
  overlayExporting,       // boolean — true while any overlay batch is running
  overlayCurrentMode,     // string | null — id of the mode currently being encoded
  overlayProgress,        // 0..1 — progress within the current mode
  overlayAvailable,       // boolean — feature-detect result for overlay path
  selectedOverlayModes,   // string[] — modes the user picked (default: ['indexer'])
  onChangeOverlayModes,   // (string[]) — replaces the selection list
  overlayModeOrder,       // string[]  — canonical mode list for the checkboxes
  overlaySize,            // 'native' | '0.2' | '0.3' | '0.5'
  onChangeOverlaySize,    // (string) — updates the size selection
  // Forwarded to each row so Set-in-here / Set-out-here resolve to a
  // global timeline-second across multi-chapter playback.
  getCurrentVideoSec,
  // Journal annotations for clips — { [id]: { label, notes, updatedAt } }.
  // The journal layer is the source of truth for clip label + notes;
  // the in-memory clip carries startMs/endMs + id. Optional: when
  // omitted, rows still render with just the in-memory label.
  clipAnnotations,
  onPatchClipAnnotation,  // (id, patch) — emits to useReplayJournal.upsertClipAnnotation
  // DataMarks (sorted by logTimeMs) for the "Contains:" inline list
  // shown in expanded clip rows. Mark name overlay lets each entry
  // render its pilot-given name when one exists.
  marks,
  markAnnotations,
  onJumpToMark,           // (logTimeMs) — seek the live video to a mark
}) => {
  const [collapsed, setCollapsed] = useState(readClipCollapsed());
  const toggleCollapsed = () => {
    setCollapsed(c => { writeClipCollapsed(!c); return !c; });
  };
  const cancelMarkBtn = pendingInVideoSec != null
    ? html`
        <button class="replay-btn-ghost" onClick=${onCancelMark} disabled=${disabled}>
          Cancel mark-in
        </button>`
    : null;

  // Helper: render the "Export" button or, for the currently-exporting
  // clip, an inline progress widget with cancel.
  const renderExportControls = (clip, i) => {
    if (exportingClipIdx === i) {
      return html`
        <div class="replay-clip-progress" role="status">
          <progress class="replay-progress"
                    max="1" value=${exportProgress ?? 0}></progress>
          <span class="replay-clip-progress-pct">
            ${Math.round((exportProgress ?? 0) * 100)}%
          </span>
          <button class="replay-btn-ghost" onClick=${onCancel}>Cancel</button>
        </div>`;
    }
    // Disable Export when (a) globally disabled, (b) some other clip
    // is exporting (sequence has to drain), (c) sync isn't ready,
    // (d) MP4 isn't supported in this browser.
    const exportDisabled = disabled || exportingClipIdx != null ||
                           !syncReady || !mp4Available || overlayExporting;
    return html`
      <button class="replay-btn"
              disabled=${exportDisabled}
              title=${mp4Available ? '' : (mp4UnavailableTooltip || '')}
              onClick=${() => onExport(clip, i)}>
        Export MP4
      </button>`;
  };

  // Overlay-only export: button + per-mode checkbox row. Each MP4 is
  // 320×240 (native M5 panel size) against the panel's own black
  // background — drop it into iMovie / Final Cut, scale and position
  // on top of the source footage.
  const renderOverlayControls = (clip, i) => {
    if (overlayExporting && overlayCurrentMode) {
      return html`
        <div class="replay-clip-progress" role="status">
          <span class="replay-clip-progress-pct">
            ${overlayCurrentMode}
          </span>
          <progress class="replay-progress"
                    max="1" value=${overlayProgress ?? 0}></progress>
          <span class="replay-clip-progress-pct">
            ${Math.round((overlayProgress ?? 0) * 100)}%
          </span>
          <button class="replay-btn-ghost" onClick=${onCancelOverlays}>Cancel</button>
        </div>`;
    }
    const selectedCount = (selectedOverlayModes || []).length;
    const overlayDisabled = disabled || exportingClipIdx != null ||
                            !syncReady || !overlayAvailable || overlayExporting ||
                            selectedCount === 0;
    if (!onExportOverlays) return null;
    return html`
      <button class="replay-btn"
              disabled=${overlayDisabled}
              title=${overlayAvailable
                ? `Render ${selectedCount} overlay MP4${selectedCount === 1 ? '' : 's'} at 320×240, M5 panel as the background (no chroma).`
                : (mp4UnavailableTooltip || '')}
              onClick=${() => onExportOverlays(clip, i)}>
        Overlays · NLE${selectedCount > 1 ? ` (${selectedCount})` : ''}
      </button>`;
  };

  // Mode-picker checkbox row. Lets the user toggle which M5 modes the
  // overlay-export batch should include. Shown once at the top of the
  // clip list (not per-row) — the selection applies to all overlay
  // exports until changed.
  const toggleMode = (m) => {
    if (!onChangeOverlayModes || !Array.isArray(selectedOverlayModes)) return;
    const has = selectedOverlayModes.includes(m);
    const next = has
      ? selectedOverlayModes.filter(x => x !== m)
      : [...selectedOverlayModes, m];
    // Keep canonical order so the export output is deterministic.
    const order = overlayModeOrder || [];
    next.sort((a, b) => order.indexOf(a) - order.indexOf(b));
    onChangeOverlayModes(next);
  };
  const renderOverlayModePicker = () => {
    if (!overlayAvailable || !onExportOverlays || !overlayModeOrder) return null;
    return html`
      <div class="replay-overlay-modes" role="group" aria-label="Overlay modes">
        <span class="replay-label">Overlay modes</span>
        ${overlayModeOrder.map(m => html`
          <label class="replay-overlay-mode-toggle">
            <input type="checkbox"
                   checked=${(selectedOverlayModes || []).includes(m)}
                   disabled=${overlayExporting}
                   onChange=${() => toggleMode(m)} />
            ${m}
          </label>`)}
        ${onChangeOverlaySize ? html`
          <span class="replay-spacer"></span>
          <label class="replay-overlay-mode-toggle">
            Size:
            <select class="replay-overlay-size-select"
                    value=${overlaySize || '0.2'}
                    disabled=${overlayExporting}
                    onChange=${(e) => onChangeOverlaySize(e.target.value)}>
              <option value="native">Native (320×240)</option>
              <option value="0.2">20% of source</option>
              <option value="0.3">30% of source</option>
              <option value="0.5">50% of source</option>
            </select>
          </label>` : null}
      </div>`;
  };

  return html`
    <div class="replay-clips${collapsed ? ' is-collapsed' : ''}">
      <div class="replay-clips-header">
        <span class="replay-section-disclosure"
              role="button"
              tabindex="0"
              title=${collapsed ? 'Expand clips' : 'Collapse clips'}
              onClick=${toggleCollapsed}
              onKeyDown=${e => { if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); toggleCollapsed(); }}}>
          ${collapsed ? '▸' : '▾'}
        </span>
        <span class="replay-label replay-clips-label-clickable"
              onClick=${toggleCollapsed}>Clips</span>
        <span class="replay-status">${clips.length}</span>
        <span class="replay-spacer"></span>

        <button class="replay-btn"
                disabled=${disabled || !syncReady}
                onClick=${() => onAddQuick(30)}>
          + 30 s clip from playhead
        </button>
        <button class="replay-btn"
                disabled=${disabled || !syncReady}
                onClick=${() => onAddQuick(60)}>
          + 60 s clip from playhead
        </button>

        ${pendingInVideoSec == null
          ? html`
              <button class="replay-btn"
                      disabled=${disabled || !syncReady}
                      onClick=${onMarkIn}>
                Mark clip in
              </button>`
          : html`
              <span class="replay-status replay-status-attention">
                in @ ${formatHms(pendingInVideoSec)} — scrub and click Mark
                clip out
              </span>
              <button class="replay-btn-primary"
                      disabled=${disabled || !syncReady}
                      onClick=${onMarkOut}>
                Mark clip out
              </button>
              ${cancelMarkBtn}`}

        ${clips.length > 0 && html`
          <button class="replay-btn-primary"
                  disabled=${disabled || !mp4Available ||
                             exportingClipIdx != null || !syncReady}
                  title=${mp4Available ? '' : (mp4UnavailableTooltip || '')}
                  onClick=${onExportAll}>
            Export all
          </button>`}
      </div>

      ${collapsed ? null : renderOverlayModePicker()}

      ${collapsed ? null : (clips.length === 0
        ? html`<div class="replay-clips-empty">
            no clips yet — scrub to a moment, click "+ 30 s" / "+ 60 s" or
            "Mark clip in" → "Mark clip out".
          </div>`
        : html`<div class="replay-clips-list">
            ${clips.map((c, i) => html`
              <${ClipRow}
                clip=${c}
                index=${i}
                sync=${sync}
                videoEl=${videoEl}
                disabled=${disabled}
                isExporting=${exportingClipIdx === i}
                annotation=${c.id && clipAnnotations ? clipAnnotations[c.id] : null}
                marks=${marks}
                markAnnotations=${markAnnotations}
                onJumpToMark=${onJumpToMark}
                onPatchAnnotation=${onPatchClipAnnotation}
                onScrubTo=${onScrubTo}
                onPatch=${(patch) => {
                  const next = validateClipEdit(c, patch);
                  if (next) setClips(updateClipAt(clips, i, next));
                }}
                onRemove=${() => setClips(removeClipAt(clips, i))}
                renderExport=${() => renderExportControls(c, i)}
                renderOverlayExport=${() => renderOverlayControls(c, i)}
                getCurrentVideoSec=${getCurrentVideoSec} />
            `)}
          </div>`)}
    </div>`;
};

// ---- Single-row component ----------------------------------------
//
// Each clip row shows: editable label, formatted in/out times,
// duration, scrub buttons, set-in-here/set-out-here buttons, export
// button (or progress widget), delete button. Expanding the row
// reveals a Notes textarea + an inline "Contains:" line listing the
// DataMarks whose logTimeMs falls inside the clip range.
const ClipRow = ({
  clip, index, sync, videoEl, disabled,
  isExporting,
  annotation,             // { label, notes, updatedAt } from journal, or null
  marks,                  // sorted DataMarks for the "Contains:" inline list
  markAnnotations,        // mark-name overlay map (keyed by value:logTimeMs)
  onJumpToMark,           // (logTimeMs) — seek the video to a mark
  onPatchAnnotation,      // (id, patch) — emits to journal upsert
  onScrubTo, onPatch, onRemove, renderExport, renderOverlayExport,
  // Multi-chapter playback wants the global timeline-second, not the
  // raw videoEl.currentTime. Function-style prop so each click reads
  // a fresh value rather than a render-time snapshot.
  getCurrentVideoSec,
}) => {
  // Display label: journal annotation wins over the in-memory clip's
  // initial label. Edits feed BOTH: the in-memory clip (so existing
  // localStorage persistence + MP4 export filenames see fresh labels)
  // AND the journal (the cross-session source of truth).
  const effectiveLabel = annotation?.label != null && annotation.label !== ''
    ? annotation.label
    : (clip.label || '');
  const [labelDraft, setLabelDraft] = useState(effectiveLabel);
  const [notesDraft, setNotesDraft] = useState(annotation?.notes || '');
  const [expanded, setExpanded] = useState(false);
  const debounceRef = useRef(null);

  // Reseed local state when the underlying annotation row changes from
  // outside (a fresh log load swaps the whole clipAnnotations map).
  // Guarded on updatedAt so an in-flight edit isn't clobbered by the
  // local-state echo of the same change.
  useEffect(() => {
    setLabelDraft(effectiveLabel);
    setNotesDraft(annotation?.notes || '');
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [annotation?.updatedAt, clip.id]);

  // Flush any pending debounce on unmount so the last keystroke
  // doesn't get stuck in a timer.
  useEffect(() => () => {
    if (debounceRef.current) {
      clearTimeout(debounceRef.current);
      debounceRef.current = null;
    }
  }, []);

  const scheduleSaveAnnotation = (patch) => {
    if (!clip.id || typeof onPatchAnnotation !== 'function') return;
    if (debounceRef.current) clearTimeout(debounceRef.current);
    debounceRef.current = setTimeout(() => {
      debounceRef.current = null;
      onPatchAnnotation(clip.id, patch);
    }, CLIP_SAVE_DEBOUNCE_MS);
  };
  const flushNowAnnotation = (patch) => {
    if (!clip.id || typeof onPatchAnnotation !== 'function') return;
    if (debounceRef.current) {
      clearTimeout(debounceRef.current);
      debounceRef.current = null;
    }
    onPatchAnnotation(clip.id, patch);
  };

  const startSec = logMsToVideoSec(clip.startMs, sync);
  const endSec   = logMsToVideoSec(clip.endMs,   sync);
  const spanSec  = (clip.endMs - clip.startMs) / 1000;

  // Snap the start/end to the current playhead. Useful for tightening
  // a clip after rough-marking it: scrub to where you actually want
  // it to start/end, click "Set in here" / "Set out here".
  //
  // For multi-chapter timelines `getCurrentVideoSec` returns the global
  // timeline second; for single-file playback it falls back to
  // videoEl.currentTime via the default below.
  const readCurrentSec = () => {
    if (typeof getCurrentVideoSec === 'function') {
      const t = getCurrentVideoSec();
      if (Number.isFinite(t)) return t;
    }
    const v = videoEl?.current || null;
    return v ? v.currentTime : null;
  };
  const setInHere = () => {
    if (!sync) return;
    const t = readCurrentSec();
    if (!Number.isFinite(t)) return;
    const newStartMs = sync.logTakeoffMs +
                       (t - sync.videoTakeoffSec) * 1000;
    onPatch({ startMs: newStartMs });
  };
  const setOutHere = () => {
    if (!sync) return;
    const t = readCurrentSec();
    if (!Number.isFinite(t)) return;
    const newEndMs = sync.logTakeoffMs +
                     (t - sync.videoTakeoffSec) * 1000;
    onPatch({ endMs: newEndMs });
  };

  // Commit the label draft on blur or Enter. Writes to both the
  // in-memory clip (export filenames + localStorage) and the journal
  // annotation (cross-session truth).
  const commitLabel = () => {
    if ((effectiveLabel || '') === labelDraft) return;
    onPatch({ label: labelDraft });
    flushNowAnnotation({ label: labelDraft });
  };

  const contained = marks ? marksWithinClip(clip, marks) : [];
  const hasNotes = !!(annotation && (annotation.label || annotation.notes));

  const rowClass = 'replay-clip-row' +
    (isExporting ? ' is-exporting' : '') +
    (expanded ? ' is-expanded' : '') +
    (hasNotes ? ' replay-clip-has-notes' : '');

  return html`
    <div class=${rowClass}>
      <div class="replay-clip-row-head">
        <span class="replay-mark-disclosure"
              onClick=${() => setExpanded(e => !e)}
              role="button"
              aria-label=${expanded ? 'Collapse' : 'Expand'}>
          ${expanded ? '▾' : '▸'}
        </span>
        <input class="replay-clip-label-input"
               type="text"
               value=${labelDraft}
               placeholder=${`clip ${String(index + 1).padStart(2, '0')}`}
               disabled=${disabled || isExporting}
               onInput=${(e) => setLabelDraft(e.target.value)}
               onBlur=${commitLabel}
               onKeyDown=${(e) => {
                 if (e.key === 'Enter') { e.preventDefault(); commitLabel(); }
                 if (e.key === 'Escape') { setLabelDraft(effectiveLabel); }
               }} />
        ${hasNotes
          ? html`<span class="replay-mark-dot" aria-label="has notes">•</span>`
          : null}

        <span class="replay-mark-time">
          ${Number.isFinite(startSec) ? formatHms(startSec) : '—'}
          → ${Number.isFinite(endSec) ? formatHms(endSec) : '—'}
          · ${spanSec.toFixed(1)} s
        </span>

        <span class="replay-spacer"></span>

        <button class="replay-btn-ghost"
                disabled=${disabled || isExporting || !Number.isFinite(startSec)}
                title="Jump to clip start"
                onClick=${() => Number.isFinite(startSec) && onScrubTo(startSec)}>
          In
        </button>
        <button class="replay-btn-ghost"
                disabled=${disabled || isExporting || !Number.isFinite(endSec)}
                title="Jump to clip end"
                onClick=${() => Number.isFinite(endSec) && onScrubTo(endSec)}>
          Out
        </button>
        <button class="replay-btn-ghost"
                disabled=${disabled || isExporting}
                title="Move this clip's start to the current playhead"
                onClick=${setInHere}>
          Set in
        </button>
        <button class="replay-btn-ghost"
                disabled=${disabled || isExporting}
                title="Move this clip's end to the current playhead"
                onClick=${setOutHere}>
          Set out
        </button>

        ${renderExport()}
        ${renderOverlayExport ? renderOverlayExport() : null}

        <button class="replay-btn-ghost"
                disabled=${disabled || isExporting}
                title="Delete this clip"
                onClick=${onRemove}>×</button>
      </div>
      ${expanded && html`
        <div class="replay-clip-expanded">
          ${contained.length > 0 && html`
            <div class="replay-clip-contains">
              <span class="replay-clip-contains-label">Contains</span>
              ${contained.map((m, i) => {
                const ann = markAnnotations
                  ? markAnnotations[String(m.value) + ':' + String(m.logTimeMs)]
                  : null;
                const display = ann?.name
                  ? `${ann.name} (mark ${m.label})`
                  : `mark ${m.label}`;
                return html`
                  ${i > 0 ? html`<span class="replay-clip-contains-sep">·</span>` : null}
                  <button class="replay-clip-contains-link"
                          onClick=${() => onJumpToMark && onJumpToMark(m.logTimeMs)}
                          title="Jump video to this mark">
                    ${display}
                  </button>`;
              })}
            </div>`}
          <label class="replay-mark-field">
            <span>Notes</span>
            <textarea rows="3"
                      value=${notesDraft}
                      placeholder="What happened in this clip…"
                      disabled=${!clip.id}
                      onInput=${e => {
                        const v = e.target.value;
                        setNotesDraft(v);
                        scheduleSaveAnnotation({ notes: v });
                      }}
                      onBlur=${() => flushNowAnnotation({ notes: notesDraft })}></textarea>
          </label>
        </div>`}
    </div>`;
};

// === docs/site/docs/data-and-logs/replay/lib/replay/reassemble.js ===
// Reassemble engine output (immediates + tail) into row-aligned results.
//
// Engine semantics (see LogReplayEngine.h):
//   - hasPot=true: every step() returns a result. tail is empty.
//     immediates[i] is the result for row i.
//   - hasPot=false: first synthHalfWindowTicks step()s return null
//     while the buffer fills. After that, immediates[i] holds the
//     result for row (i - lag). flush() returns the trailing
//     synthHalfWindowTicks rows that were still buffered at EOF.
//     If N < synthHalfWindowTicks, all step()s return null and
//     tail.length === N.
//
// Parameters:
//   immediates  - Array of results from step(), in order (may contain
//                 leading nulls on the synth path).
//   tail        - Array from flush() (trailing rows drained at EOF).
//   N           - Total row count (= immediates.length).
//   hasPot      - True when the log has flapsRawAdc data (fast path).
//
// Returns results[0..N-1] where results[i] is the ReplayStepResult for
// input row i.
function reassembleResults(immediates, tail, N, hasPot) {
    const results = new Array(N).fill(null);
    if (hasPot) {
        // Fast path: every step() returns a result immediately.
        // immediates[i] is the result for row i. Tail is empty.
        for (let i = 0; i < N; i++) results[i] = immediates[i];
    } else {
        // Synth path: the circular buffer introduces a lag.
        // immediates[lag..N-1] → results[0..N-lag-1]
        // tail[0..tail.length-1] → results[N-tail.length..N-1]
        //
        // When N < synthHalfWindowTicks every step() returns null, so
        // firstNonNull is -1. In that case lag = N (all rows are in
        // tail) and the immediates loop below is empty.
        const firstNonNull = immediates.findIndex(r => r !== null);
        const lag = (firstNonNull < 0) ? N : firstNonNull;
        for (let i = lag; i < N; i++) results[i - lag] = immediates[i];
        for (let j = 0; j < tail.length; j++) {
            results[N - tail.length + j] = tail[j];
        }
    }
    return results;
}

// === docs/site/docs/data-and-logs/replay/lib/replay/persistence.js ===
// persistence.js — localStorage persistence for the replay tool.
//
// Keyed by a 16-char hex SHA-256 prefix of the first 10 KB of the log
// file. Because the key derives from file content, the same log picked
// on reload yields the same key; a different log never restores stale state.
//
// Three localStorage namespaces:
//
//   replay-sync-<digest>-v1
//     { videoTakeoffSec, logTakeoffMs }
//
//   replay-clips-<digest>-v1
//     [{ startMs, endMs, label }, ...]
//
//   replay-recent-files-v1
//     { video: { name, size, lastModified },
//       log:   { name, size, lastModified },
//       cfg:   { name, size, lastModified } | null }
//
// Pure exports (testable in Node without Preact or browser APIs):
//   fileMetadata(file)           → { name, size, lastModified } | null
//   filesMatch(stored, picked)   → boolean
//   computeLogDigest(file)       → Promise<string | null>
//
// Preact hook: useReplayPersistence({ logFile })
// Preact component: RecentFilesBanner({ info, onDismiss })


function safeLsGet(key) { try { return localStorage.getItem(key); } catch { return null; } }
function safeLsSet(key, value) { try { localStorage.setItem(key, value); } catch {} }

const RECENT_FILES_KEY = 'replay-recent-files-v1';
// Stores the JSON-stringified bannerInfo that was most recently
// dismissed. Persisted across reloads so a dismissed "last session"
// banner stays dismissed for THAT session's file set; a fresh
// session (different file names) gets a fresh banner.
const BANNER_DISMISSED_KEY = 'replay-banner-dismissed-v1';

function syncKey(digest)  { return `replay-sync-${digest}-v1`;  }
function clipsKey(digest) { return `replay-clips-${digest}-v1`; }

function fileMetadata(file) {
  if (!file || typeof file !== 'object') return null;
  const { name, size, lastModified } = file;
  if (typeof name !== 'string') return null;
  return { name, size: Number(size), lastModified: Number(lastModified) };
}

function filesMatch(stored, picked) {
  if (!stored || !picked) return false;
  return stored.name === picked.name &&
         stored.size === picked.size &&
         stored.lastModified === picked.lastModified;
}

async function computeLogDigest(file) {
  if (!file) return null;
  try {
    const buf = await file.slice(0, 10_240).arrayBuffer();
    const hash = await crypto.subtle.digest('SHA-256', buf);
    const bytes = new Uint8Array(hash);
    let hex = '';
    for (let i = 0; i < 8; i++) {
      hex += bytes[i].toString(16).padStart(2, '0');
    }
    return hex;
  } catch {
    return null;
  }
}

function loadStoredSync(digest) {
  if (!digest) return null;
  const raw = safeLsGet(syncKey(digest));
  if (!raw) return null;
  try {
    const p = JSON.parse(raw);
    if (Number.isFinite(p.logTakeoffMs) && Number.isFinite(p.videoTakeoffSec)) return p;
  } catch {}
  return null;
}

function loadStoredClips(digest) {
  if (!digest) return null;
  const raw = safeLsGet(clipsKey(digest));
  if (!raw) return null;
  try {
    const p = JSON.parse(raw);
    if (Array.isArray(p)) return p;
  } catch {}
  return null;
}

function useReplayPersistence({ logFile }) {
  const [logDigest, setLogDigest]           = useState(null);
  const [digestReady, setDigestReady]       = useState(false);
  const [storedSync, setStoredSync]         = useState(null);
  const [storedClips, setStoredClips]       = useState(null);
  const [bannerInfo, setBannerInfo]         = useState(null);
  // Read the dismissed-signature on mount. The signature is a
  // JSON-stringified bannerInfo; we treat the banner as dismissed
  // only when the current bannerInfo matches the stored signature.
  // A fresh session with a different file set produces a different
  // signature and re-surfaces the banner.
  const [dismissedSig, setDismissedSig]     = useState(() => safeLsGet(BANNER_DISMISSED_KEY) || '');
  const pickedFilesRef = useRef({ video: null, log: null, cfg: null });
  // Synchronous mirror of logDigest. storeSync / storeClips read this
  // ref instead of the React state, so they see the digest go to null
  // the instant a new logFile is provided — not on the next render
  // after the persistence hook's logFile-effect commits state. Without
  // this, the persist effects in ReplayPage can fire one extra time
  // with the previous log's digest still bound, corrupting the prior
  // log's localStorage keys with the new log's (reset) state.
  const logDigestRef = useRef(null);

  useEffect(() => {
    const raw = safeLsGet(RECENT_FILES_KEY);
    if (!raw) return;
    try {
      const info = JSON.parse(raw);
      if (info && info.video && info.log) setBannerInfo(info);
    } catch {}
  }, []);

  useEffect(() => {
    logDigestRef.current = null;
    setLogDigest(null);
    setDigestReady(false);
    setStoredSync(null);
    setStoredClips(null);
    if (!logFile) return;
    let cancelled = false;
    computeLogDigest(logFile).then(digest => {
      if (cancelled) return;
      logDigestRef.current = digest;
      setLogDigest(digest);
      setDigestReady(true);
      setStoredSync(loadStoredSync(digest));
      setStoredClips(loadStoredClips(digest));
    });
    return () => { cancelled = true; };
  }, [logFile]);

  const bannerSig = bannerInfo ? JSON.stringify(bannerInfo) : '';
  const bannerDismissed = bannerSig !== '' && bannerSig === dismissedSig;

  const dismissBanner = useCallback(() => {
    if (!bannerSig) return;
    safeLsSet(BANNER_DISMISSED_KEY, bannerSig);
    setDismissedSig(bannerSig);
  }, [bannerSig]);

  const notifyFilePicked = useCallback((slot, file) => {
    pickedFilesRef.current = {
      ...pickedFilesRef.current,
      [slot]: fileMetadata(file),
    };
    const { video, log, cfg } = pickedFilesRef.current;
    if (video && log) {
      safeLsSet(RECENT_FILES_KEY, JSON.stringify({ video, log, cfg: cfg || null }));
    }
  }, []);

  // Synchronous hook a page-level handler calls just before swapping
  // logFile. Clears logDigestRef so any persist-on-change effects
  // that fire during the same React render — with the OLD logDigest
  // state still bound — see ref=null and refuse to write. Without
  // this, ReplayPage's setClips([]) + setLogFile(f) batch causes the
  // clips persist-effect to write [] to the PREVIOUS log's
  // localStorage key before the digest recomputes.
  const beginLogSwap = useCallback(() => {
    logDigestRef.current = null;
  }, []);

  // Both writers read the synchronous ref so they reflect the most
  // recent logFile prop — not whichever logDigest state-value the
  // useCallback closure last captured. storeSync stayed bound to
  // logDigest as the React-state dep so consumers still get a stable
  // identity per-log, but the actual digest used for the write comes
  // from the ref.
  const storeSync = useCallback((sync) => {
    const digest = logDigestRef.current;
    if (!digest) return;
    if (!sync ||
        !Number.isFinite(sync.videoTakeoffSec) ||
        !Number.isFinite(sync.logTakeoffMs)) return;
    safeLsSet(syncKey(digest), JSON.stringify(sync));
  }, [logDigest]);

  const storeClips = useCallback((clips) => {
    const digest = logDigestRef.current;
    if (!digest) return;
    if (!Array.isArray(clips)) return;
    safeLsSet(clipsKey(digest), JSON.stringify(clips));
  }, [logDigest]);

  // Stable string signature of the currently-known recent-files set.
  // Empty until at least video+log metadata is present. Consumed by the
  // file-handle persistence layer (fileHandles.js) to key its IDB
  // record so it can detect whether stored handles match the active
  // session's metadata. Mirrors the JSON-stringified RECENT_FILES_KEY
  // value exactly.
  const recentFilesSig = bannerInfo
    ? JSON.stringify({
        video: bannerInfo.video,
        log:   bannerInfo.log,
        cfg:   bannerInfo.cfg || null,
      })
    : '';

  return {
    digestReady,
    logDigest,
    bannerInfo: bannerDismissed ? null : bannerInfo,
    rawBannerInfo: bannerInfo,
    recentFilesSig,
    dismissBanner,
    notifyFilePicked,
    beginLogSwap,
    storedSync,
    storedClips,
    storeSync,
    storeClips,
  };
}

function RecentFilesBanner({ info, onDismiss }) {
  if (!info) return null;
  const parts = [];
  if (info.video && info.video.name) parts.push(info.video.name);
  if (info.log   && info.log.name)   parts.push(info.log.name);
  if (info.cfg   && info.cfg.name)   parts.push(info.cfg.name);
  const label = parts.join(' + ') || 'previous session files';
  return html`
    <div class="replay-recent-banner">
      <span class="replay-recent-text">
        Last session: ${label}.
        Re-pick these files to restore sync and clips.
      </span>
      <button class="replay-recent-dismiss"
              type="button"
              onClick=${onDismiss}>×</button>
    </div>
  `;
}

// === docs/site/docs/data-and-logs/replay/lib/replay/fileHandles.js ===
// fileHandles.js — File System Access API integration for the replay
// tool. Persists FileSystemFileHandle objects in IndexedDB so a page
// reload can offer "Resume last session?" with a single permission
// re-grant covering all three files.
//
// Background: the replay page takes three file inputs (video, log,
// config). Sync state and clip lists already persist across reloads
// via persistence.js (content-keyed by log SHA-256). But the file
// inputs themselves cannot be auto-restored — browsers do not give
// pages programmatic access to previously selected <input type="file">
// results, for security reasons.
//
// The File System Access API gives the page a FileSystemFileHandle
// that can be stored in IndexedDB and re-grant'd in a single user-
// gesture click. Chrome and Edge desktop ship this API; Firefox and
// Safari do not. On unsupported browsers, callers should fall through
// to the existing <input type="file"> flow.
//
// Permissions: handle.requestPermission({mode:'read'}) MUST be called
// inside a user-gesture handler (button click). Browsers batch the
// permission prompts when multiple handles are requested in the same
// gesture, so one click can grant read access to all three files.
//
// Storage schema (IndexedDB):
//   database  'replay-fsa'
//   store     'handles-v1'
//   key       'current'
//   value     { signature: string, handles: { video, log, cfg } }
//
// The signature is the JSON-stringified recent-files metadata
// ({video, log, cfg} from persistence.js's RECENT_FILES_KEY). On
// reload, we compare the stored signature against the current
// recent-files signature; if it matches, the handles are still
// relevant. The store name carries the schema version (`handles-v1`)
// so a future bump can ignore old data cleanly.


const DB_NAME = 'replay-fsa';
const STORE_NAME = 'handles-v1';
const DB_VERSION = 1;
const RECORD_KEY = 'current';

// ---------------------------------------------------------------------
// Pure helpers (testable in Node)
// ---------------------------------------------------------------------

// Returns true iff the browser supports File System Access showOpenFilePicker.
// Chrome/Edge desktop ship it. Firefox/Safari do not.
function isFileHandleApiSupported() {
  return typeof globalThis !== 'undefined' &&
         typeof globalThis.window !== 'undefined' &&
         typeof globalThis.window.showOpenFilePicker === 'function';
}

// Accept-list per slot. Mirrors the existing <input> accept attrs:
//   video: video/*,.mp4,.mov,.webm
//   log:   .csv,text/csv
//   cfg:   .cfg,.xml,text/xml
//
// showOpenFilePicker's types[] takes a {description, accept: {mime: [exts]}}
// shape; the OS dialog filters on this.
function pickerOptionsForSlot(slot) {
  if (slot === 'video') {
    return {
      multiple: false,
      types: [{
        description: 'Flight video',
        accept: { 'video/*': ['.mp4', '.mov', '.webm'] },
      }],
    };
  }
  if (slot === 'log') {
    return {
      multiple: false,
      types: [{
        description: 'OnSpeed SD log',
        accept: { 'text/csv': ['.csv'] },
      }],
    };
  }
  if (slot === 'cfg') {
    return {
      multiple: false,
      types: [{
        description: 'OnSpeed config XML',
        accept: { 'text/xml': ['.cfg', '.xml'] },
      }],
    };
  }
  throw new Error(`fileHandles: unknown slot ${slot}`);
}

// Compute the signature for a recent-files info object. Same shape as
// persistence.js's RECENT_FILES_KEY value, so the signature matches
// what that module writes.
function recentFilesSignature(info) {
  if (!info || !info.video || !info.log) return '';
  return JSON.stringify({
    video: info.video,
    log: info.log,
    cfg: info.cfg || null,
  });
}

// Pull {name, size, lastModified} from a File-like object. Mirrors
// persistence.js's fileMetadata so the same metadata shape feeds both
// the recent-files banner and the signature used to key IDB.
function metaOf(file) {
  if (!file || typeof file !== 'object') return null;
  const { name, size, lastModified } = file;
  if (typeof name !== 'string') return null;
  return { name, size: Number(size), lastModified: Number(lastModified) };
}

// Build a signature from raw File objects (whatever live state
// ReplayPage holds for the three slots). Returns '' if video+log are
// not both present.
function signatureFromFiles({ video, log, cfg }) {
  const v = metaOf(video);
  const l = metaOf(log);
  const c = metaOf(cfg);
  if (!v || !l) return '';
  return JSON.stringify({ video: v, log: l, cfg: c });
}

// ---------------------------------------------------------------------
// IndexedDB plumbing
// ---------------------------------------------------------------------

function openDb() {
  return new Promise((resolve, reject) => {
    if (typeof indexedDB === 'undefined') {
      reject(new Error('IndexedDB not available'));
      return;
    }
    const req = indexedDB.open(DB_NAME, DB_VERSION);
    req.onupgradeneeded = () => {
      const db = req.result;
      if (!db.objectStoreNames.contains(STORE_NAME)) {
        db.createObjectStore(STORE_NAME);
      }
    };
    req.onsuccess = () => resolve(req.result);
    req.onerror = () => reject(req.error || new Error('IDB open failed'));
  });
}

function withStore(mode, fn) {
  return openDb().then(db => new Promise((resolve, reject) => {
    let result;
    const tx = db.transaction(STORE_NAME, mode);
    const store = tx.objectStore(STORE_NAME);
    Promise.resolve(fn(store)).then(r => { result = r; }, reject);
    tx.oncomplete = () => { db.close(); resolve(result); };
    tx.onabort = () => { db.close(); reject(tx.error || new Error('IDB tx aborted')); };
    tx.onerror = () => { db.close(); reject(tx.error || new Error('IDB tx error')); };
  }));
}

function reqToPromise(req) {
  return new Promise((resolve, reject) => {
    req.onsuccess = () => resolve(req.result);
    req.onerror = () => reject(req.error || new Error('IDB request failed'));
  });
}

// ---------------------------------------------------------------------
// Public IDB API
// ---------------------------------------------------------------------

// Store the full bundle keyed by signature. Overwrites any prior record.
// signature: string (recent-files signature, may be empty if not all
// three files have metadata yet — caller decides whether to call).
// handles: { video?, log?, cfg? } — slots present in this bundle.
async function storeHandles(signature, handles) {
  if (typeof signature !== 'string') return;
  await withStore('readwrite', store => reqToPromise(
    store.put({ signature, handles }, RECORD_KEY)
  ));
}

// Read the current record. Returns null if missing or mismatched.
// If expectedSignature is provided and non-empty, returns null when the
// stored signature differs (the bundle belongs to a different session).
async function loadHandles(expectedSignature) {
  let record;
  try {
    record = await withStore('readonly', store => reqToPromise(store.get(RECORD_KEY)));
  } catch {
    return null;
  }
  if (!record || !record.handles) return null;
  if (typeof expectedSignature === 'string' && expectedSignature.length > 0 &&
      record.signature !== expectedSignature) {
    return null;
  }
  return record.handles;
}

async function clearHandles() {
  try {
    await withStore('readwrite', store => reqToPromise(store.delete(RECORD_KEY)));
  } catch {
    // best-effort; missing is fine
  }
}

// ---------------------------------------------------------------------
// Permission helper. Must be called from a user-gesture handler.
// ---------------------------------------------------------------------

// Extract the FileSystemHandle that needs read permission from a slot
// value. For the `video` slot the value is either a FileSystemFileHandle
// (single-chapter session) or a `{kind:'multi-chapter', directoryHandle,
// chapterNames}` envelope — in the latter case the directory handle is
// the permission target (granting it implicitly grants every file inside).
//
// Discriminator note: the FSA spec defines `.kind` on FileSystemHandle
// as `'file' | 'directory'`. Our envelope adds the synthetic value
// `'multi-chapter'` to the same field — the three values are disjoint
// today, but if the spec ever adds a new handle kind that string-equals
// our envelope marker, this branch would misclassify. Cheap to defend:
// rename the envelope discriminator (e.g. `envelopeKind`) only if/when
// that becomes a concrete risk.
function permissionTarget(slotValue) {
  if (!slotValue) return null;
  if (slotValue.kind === 'multi-chapter') return slotValue.directoryHandle || null;
  return slotValue;
}

async function requestPermissionForHandles(handles) {
  if (!handles) return false;
  const slots = ['video', 'log', 'cfg'];
  // The synchronous `.map()` dispatches all three `requestPermission()`
  // calls in the same JS turn, BEFORE any `await` runs. Chrome's
  // user-activation token survives synchronous dispatch and the
  // resulting microtask chain, so all three prompts read as
  // "user-triggered" and the browser batches them into one combined
  // dialog. `Promise.all` here only collects the results — it does
  // NOT guarantee the batching; that comes from the sync dispatch in
  // the `.map()` body. If a future Chrome change tightens this
  // (e.g. user-activation only survives one async hop), the prompts
  // would degrade to "first ok, rest denied" — observable in dev
  // before it bites a pilot.
  const results = await Promise.all(slots.map(slot => {
    const target = permissionTarget(handles[slot]);
    if (!target) return 'granted'; // missing slot (e.g. cfg) is fine
    if (typeof target.requestPermission !== 'function') return 'denied';
    return target.requestPermission({ mode: 'read' }).catch(() => 'denied');
  }));
  return results.every(r => r === 'granted');
}

// Non-prompting permission probe. `queryPermission` reports the current
// state without surfacing a dialog, so it is safe to call outside a
// user-gesture context (page load, mount-time effect). Returns true iff
// every present slot's queryPermission resolves to 'granted' — the
// signal the auto-resume path needs to skip the banner click. A 'prompt'
// or 'denied' result on any slot falls back to the banner-required path.
async function queryPermissionForHandles(handles) {
  if (!handles) return false;
  const slots = ['video', 'log', 'cfg'];
  const results = await Promise.all(slots.map(slot => {
    const target = permissionTarget(handles[slot]);
    if (!target) return 'granted';
    if (typeof target.queryPermission !== 'function') return 'prompt';
    return target.queryPermission({ mode: 'read' }).catch(() => 'prompt');
  }));
  return results.every(r => r === 'granted');
}

// Same as queryPermissionForHandles but returns a per-slot breakdown.
// Used by the ?debug=1 diagnostic path so the pilot can see which slot
// is blocking auto-resume (e.g. cfg granted but video stuck on 'prompt'
// because the directory handle came from a different gesture).
async function queryPermissionPerSlot(handles) {
  if (!handles) return [];
  const slots = ['video', 'log', 'cfg'];
  return Promise.all(slots.map(async slot => {
    const target = permissionTarget(handles[slot]);
    if (!target) return { slot, present: false, result: 'granted' };
    if (typeof target.queryPermission !== 'function') {
      return { slot, present: true, result: 'unsupported' };
    }
    let result = 'prompt';
    try { result = await target.queryPermission({ mode: 'read' }); }
    catch (e) { result = 'error:' + (e && e.name); }
    return { slot, present: true, result };
  }));
}

// Walk a stored multi-chapter envelope: re-open the directory handle's
// entries, match against the persisted chapter-name list, return the
// ordered file + handle arrays. Permission must already be granted on
// `directoryHandle` (caller is the post-Resume click path).
//
// If a chapter's file is missing (renamed, moved, deleted) it's
// dropped from the result; the caller can detect a partial recovery
// by comparing `result.files.length` to `envelope.chapterNames.length`.
async function expandMultiChapterHandle(envelope) {
  if (!envelope || envelope.kind !== 'multi-chapter') return null;
  const { directoryHandle, chapterNames } = envelope;
  if (!directoryHandle || !Array.isArray(chapterNames)) return null;
  const found = new Map(); // name → { file, handle }
  for await (const [name, entry] of directoryHandle.entries()) {
    if (entry.kind !== 'file') continue;
    if (!chapterNames.includes(name)) continue;
    try {
      const file = await entry.getFile();
      found.set(name, { file, handle: entry });
    } catch (_) { /* unreadable: skip */ }
  }
  const ordered = chapterNames
    .map(n => found.get(n))
    .filter(Boolean);
  return {
    files:    ordered.map(x => x.file),
    handles:  ordered.map(x => x.handle),
    directoryHandle,
  };
}

// ---------------------------------------------------------------------
// showOpenFilePicker wrapper. Returns {file, handle} or null on cancel.
// ---------------------------------------------------------------------

async function pickFile(slot) {
  if (!isFileHandleApiSupported()) return null;
  let handle;
  try {
    const [h] = await window.showOpenFilePicker(pickerOptionsForSlot(slot));
    handle = h;
  } catch (err) {
    // User cancelled the picker; AbortError is the standard signal.
    if (err && err.name === 'AbortError') return null;
    throw err;
  }
  if (!handle) return null;
  const file = await handle.getFile();
  return { file, handle };
}

// ---------------------------------------------------------------------
// Preact hook: useFileHandleResume
//
// Reads IDB on mount + whenever recentFilesSig changes. Exposes:
//   supported       — boolean, FSA available
//   availableHandles — { video, log, cfg } | null (matched signature)
//   resumeReady     — true iff video + log handles both present
//                     (cfg is optional, mirrors persistence.js)
//   autoResumeReady — true iff resumeReady AND every present handle's
//                     queryPermission returned 'granted'. Lets the page
//                     skip the banner click and load files at mount.
//   dismissed       — pilot dismissed the resume offer this session
//   dismiss()       — hide the resume offer + clear IDB record
//   markUsed()      — call after a successful resume so future
//                     renders don't keep offering the same resume
//
// The hook re-queries IDB whenever the recentFilesSig changes (so a
// fresh session triggers a fresh lookup).
// ---------------------------------------------------------------------

function useFileHandleResume({ recentFilesSig }) {
  const [supported] = useState(() => isFileHandleApiSupported());
  const [availableHandles, setAvailableHandles] = useState(null);
  // Set only when queryPermission reports 'granted' on every present
  // slot. Reset to false alongside availableHandles on signature change.
  const [permGranted, setPermGranted] = useState(false);
  const [dismissed, setDismissed] = useState(false);
  const [used, setUsed] = useState(false);

  useEffect(() => {
    const debug = typeof window !== 'undefined' &&
                  new URLSearchParams(window.location.search).get('debug') === '1';
    if (!supported) {
      if (debug) console.log('fileHandles autoResume diag', {
        stage: 'unsupported',
        note: 'File System Access API not available in this browser',
      });
      return;
    }
    if (!recentFilesSig) {
      if (debug) console.log('fileHandles autoResume diag', {
        stage: 'no-sig',
        note: 'no recent-files signature yet — open a log to establish one',
      });
      setAvailableHandles(null);
      setPermGranted(false);
      return;
    }
    let cancelled = false;
    loadHandles(recentFilesSig).then(async h => {
      if (cancelled) return;
      setAvailableHandles(h);
      if (!h) {
        if (debug) console.log('fileHandles autoResume diag', {
          stage: 'no-handles',
          sig: recentFilesSig,
          note: 'no stored handles for this log signature — open files manually first',
        });
        setPermGranted(false);
        return;
      }
      // queryPermission does not require a user gesture, so it is safe
      // to call here from the mount-time effect.
      let ok = false;
      try {
        if (debug) {
          const perSlot = await queryPermissionPerSlot(h);
          ok = perSlot.every(s => s.result === 'granted');
          // eslint-disable-next-line no-console
          console.log('fileHandles autoResume diag', {
            stage: 'queried', sig: recentFilesSig, perSlot, ok,
          });
        } else {
          ok = await queryPermissionForHandles(h);
        }
      } catch (e) {
        if (debug) console.log('fileHandles autoResume diag', {
          stage: 'query-error', err: String(e),
        });
        ok = false;
      }
      if (!cancelled) setPermGranted(ok);
    }).catch((e) => {
      if (debug) console.log('fileHandles autoResume diag', {
        stage: 'load-error', err: String(e),
      });
      if (!cancelled) { setAvailableHandles(null); setPermGranted(false); }
    });
    return () => { cancelled = true; };
  }, [supported, recentFilesSig]);

  // Dismiss hides the resume UI for the rest of this session. We
  // intentionally do NOT clearHandles() here — file handles are the
  // auto-resume backbone, and the recent-files banner that triggers
  // this dismiss is a separate concern (visual decluttering). Wiping
  // handles on dismiss strands users who dismiss the banner once and
  // then never see their files come back automatically.
  const dismiss = useCallback(() => {
    setDismissed(true);
  }, []);

  const markUsed = useCallback(() => {
    setUsed(true);
  }, []);

  const resumeReady = !!(availableHandles &&
                         availableHandles.video &&
                         availableHandles.log) &&
                      !dismissed &&
                      !used;

  const autoResumeReady = resumeReady && permGranted;

  return {
    supported,
    availableHandles,
    resumeReady,
    autoResumeReady,
    dismiss,
    markUsed,
  };
}

// ---------------------------------------------------------------------
// ReplayResumeBanner — renders the "Resume last session?" UI when the
// hook signals resumeReady. The Resume button click is the user-gesture
// site that triggers requestPermissionForHandles.
//
// Props:
//   info       — banner metadata (filenames + sizes, from persistence)
//   onResume() — handler invoked synchronously inside the Resume
//                click. Caller must call requestPermissionForHandles
//                inside the same handler (no awaits before it) to
//                preserve the user-gesture token.
//   onDismiss() — handler for the dismiss (×) button.
// ---------------------------------------------------------------------

function ReplayResumeBanner({ info, onResume, onDismiss }) {
  if (!info) return null;
  const parts = [];
  if (info.video && info.video.name) parts.push(info.video.name);
  if (info.log   && info.log.name)   parts.push(info.log.name);
  if (info.cfg   && info.cfg.name)   parts.push(info.cfg.name);
  const label = parts.join(' + ') || 'previous session files';
  return html`
    <div class="replay-recent-banner">
      <span class="replay-recent-text">
        Resume last session: ${label}?
      </span>
      <button class="replay-recent-resume"
              type="button"
              onClick=${onResume}>Resume</button>
      <button class="replay-recent-dismiss"
              type="button"
              onClick=${onDismiss}
              title="Dismiss">×</button>
    </div>
  `;
}

// === docs/site/docs/data-and-logs/replay/lib/replay/logReplayTask.js ===
// logReplayTask.js — JS wrapper around the LogReplayTask WASM binding.
//
// Single-source CSV-row → wire-bytes pipeline (issue #514). Wraps the
// C++ LogReplayTask in onspeed_core/src/replay/LogReplayTask.{h,cpp}
// and exposes a simple JS API: construct, processRow, flush, reset,
// delete.
//
// Used by the M5-accurate replay path's "C++ engine" toggle to drive
// wire bytes from a single C++ entry point — no JS-side rowObjAt or
// buildDisplayInputs hand-derivation. See the retro at
// docs/superpowers/plans/2026-05-09-replay-retro.md for why the
// hand-derivations are drift seams.


class LogReplayTask {
  // Static factory — constructs a task with the given parsed cfg and
  // log metadata. Throws if the WASM binding isn't available (rebuild
  // via software/Libraries/onspeed_core/wasm/build_wasm.sh).
  static async create(cfg, logSampleRateHz, flapsRawAdcAvailable) {
    const Module = await getWasmCore();
    if (typeof Module.LogReplayTask !== 'function') {
      throw new Error(
        'LogReplayTask: WASM binding not available — rebuild via ' +
        'software/Libraries/onspeed_core/wasm/build_wasm.sh');
    }
    const handle = new Module.LogReplayTask(
      cfg, logSampleRateHz, flapsRawAdcAvailable);
    return new LogReplayTask(handle);
  }

  constructor(handle) {
    this._handle = handle;
  }

  // Process one parsed row. Returns a Uint8Array of length 77 (the
  // v4.23 wire frame the M5 firmware would have received), or an
  // empty Uint8Array when the synth-path is buffering (engine returns
  // null during the kSynthHalfWindowTicks lag period). Caller should
  // skip injecting empty arrays.
  //
  // The row shape mirrors LogReplayEngine.step's input: see
  // bindings.cpp::LogRowFromVal for the canonical field list.
  processRow(rowObj) {
    return this._handle.processRow(rowObj);
  }

  // Drain the synth circular buffer at end-of-log. Returns an Array
  // of Uint8Array frames in arrival order. Empty Array when the log
  // had flapsRawAdcAvailable=true (no buffering). Caller injects each
  // tail frame in order.
  flush() {
    return this._handle.flush();
  }

  // Reset state (engine EMA filters, synth buffer, iasAlive). Call on
  // backward scrub or replay re-init.
  reset() {
    this._handle.reset();
  }

  // Diagnostic accessor: the engine's most recent ReplayStepResult as
  // a plain JS object. Valid only after a processRow that returned a
  // non-empty Uint8Array (during synth lag the engine has no result
  // to report; older calls' state is whatever the default-constructed
  // ReplayStepResult held — do not rely on the values then).
  lastStep() {
    return this._handle.lastStep();
  }

  // Diagnostic: the iDegrees of every flap detent in the C++ task's
  // cfg, in storage order. Verifies the cfg round-trip preserved
  // detent ordering.
  cfgFlapsDegrees() {
    return this._handle.cfgFlapsDegrees();
  }

  // Free the WASM-side handle. Required to release WASM heap memory
  // when the task is no longer needed.
  delete() {
    if (this._handle) {
      this._handle.delete();
      this._handle = null;
    }
  }
}

// === docs/site/docs/data-and-logs/replay/lib/replay/buildWireFrames.js ===
// buildWireFrames.js — pre-pass a parsed log through the LogReplayTask
// and return a per-row array of 77-byte wire frames.
//
// The single-source C++ pipeline (issue #514) handles iasAlive
// hysteresis, engine smoothing, anchors, percent-lift, and wire
// encoding internally. JS callers just feed parsed LogRow shapes in
// row order and inject the resulting bytes into the M5 sim.
//
// This is the C++-engine arm of the M5-accurate path's A/B toggle.
// The JS-engine arm uses replayCtx.results[] + buildWireFrame from
// wireBridge.js. Both paths feed sim.injectBytes — the M5 firmware
// decode is unchanged.




// Build a plain JS row object from the columnar log at index i.
// Mirrors rowObjAt in ReplayPage.js minus the iasValid threading —
// the C++ task IGNORES row.iasValid and re-derives it hysteretically
// (closes Bug 1 from the trial-run retro by construction).
function rowAt(log, i) {
  const g  = (arr) => (arr ? arr[i] : NaN);
  const gi = (arr) => (arr ? arr[i] : 0);
  // DataMark per firmware (Switch.cpp:61) is a monotonically-
  // incrementing int that the M5 wire/panel display mod-100. Some
  // real-world SD logs contain misaligned CSV rows where the
  // DataMark cell holds a timestamp, pressure reading, etc. Those
  // values were leaking into the wire frame and producing garbage
  // overlay digits. Cap at 9999 to filter the torn-row signature
  // without rejecting legitimate high-counter presses on long flights
  // (the firmware-side `% 100` will still reduce ≥100 values to a
  // two-digit display).
  const gMark = (arr) => {
    if (!arr) return 0;
    const v = arr[i];
    if (Number.isInteger(v) && v >= 0 && v <= 9999) return v;
    return 0;
  };
  return {
    pfwdSmoothed:    g(log.PfwdSmoothed),
    p45Smoothed:     g(log.P45Smoothed),
    pStaticMbar:     g(log.PStatic),
    paltFt:          g(log.Palt),
    iasKt:           g(log.IAS),
    iasValid:        false,                  // task overrides via UpdateIasAlive
    flapsPos:        gi(log.flapsPos),
    flapsRawAdc:     gi(log.flapsRawADC),
    flapsRawAdcPresent: !!(log.flapsRawADC),
    imuVerticalG:    g(log.VerticalG),
    imuLateralG:     g(log.LateralG),
    imuForwardG:     g(log.ForwardG),
    imuRollRateDps:  g(log.RollRate),
    imuPitchRateDps: g(log.PitchRate),
    imuYawRateDps:   g(log.YawRate),
    pitchDeg:        g(log.Pitch),
    rollDeg:         g(log.Roll),
    flightPathDeg:   g(log.FlightPath),
    vsiFpm:          g(log.VSI),
    dataMark:        gMark(log.DataMark),
    oatCelsius:      g(log.OAT),
  };
}

// Pre-pass the log through a fresh LogReplayTask and return a
// per-row array of Uint8Arrays. The result has length = log.Length;
// each entry is either a 77-byte frame or null (synth-path lag).
//
// Synth-path lag handling: the task returns empty arrays during the
// first ~kSynthHalfWindowTicks rows and at end-of-log returns the
// trailing rows via flush(). reassembleResults aligns these with
// original log indices so we can index by row directly.
//
// Returns { frames, engineResults } where engineResults[i] is the
// C++ engine's ReplayStepResult at row i (or null on synth lag).
// engineResults is provided so the diagnostic mode can compare the
// C++ engine's per-row aoa against the JS engine's per-row aoaDeg.
async function buildWireFramesFromTask(log, cfg, onProgress, isCancelled) {
  if (!log || !cfg) return null;

  const sampleRateHz = detectLogSampleRate(log);
  const hasPot       = hasFlapsRawAdc(log);
  const N            = log.Length;

  const task = await LogReplayTask.create(cfg, sampleRateHz, hasPot);
  // Snapshot the cfg's flap detent order as the C++ task internally
  // sees it. Diagnostic only — verifies the cfg round-trip didn't
  // shuffle flap entries.
  let cfgFlapsDeg = null;
  try { cfgFlapsDeg = task.cfgFlapsDegrees(); } catch (_) { /* binding may be missing */ }
  // eslint-disable-next-line no-console
  console.log('LogReplayTask cfg.aFlaps[*].iDegrees =', cfgFlapsDeg,
              ' hasPot=', hasPot, ' sampleRateHz=', sampleRateHz);

  let frames;
  let engineResults;
  try {
    const immediates = [];
    const engImmediates = [];
    const CHUNK = 5000;
    for (let start = 0; start < N; start += CHUNK) {
      if (isCancelled && isCancelled()) return null;
      const end = Math.min(start + CHUNK, N);
      for (let i = start; i < end; i++) {
        const bytes = task.processRow(rowAt(log, i));
        if (bytes.length > 0) {
          immediates.push(bytes);
          // Capture the engine result that produced these bytes.
          engImmediates.push(task.lastStep());
        } else {
          immediates.push(null);
          engImmediates.push(null);
        }
      }
      if (onProgress) onProgress(end / N);
      await new Promise(r => setTimeout(r, 0));
    }
    const tail = task.flush();   // Array<Uint8Array>; non-77-length impossible
    // For synth-path tail rows we don't have engine results captured
    // (flush doesn't yield them through the binding today). Pad with
    // null; the diagnostic just won't have engineResults for the
    // last ~kSynthHalfWindowTicks rows of an old-style log.
    const tailEng = new Array(tail.length).fill(null);
    frames = reassembleResults(immediates, tail, N, hasPot);
    engineResults = reassembleResults(engImmediates, tailEng, N, hasPot);
  } finally {
    task.delete();
  }

  return { frames, engineResults };
}

// === packages/ui-core/core/colors.js ===
// M5GFX color tokens, indexed by their TFT_* names.
// Values are CSS variable names so the active theme controls the actual color.
// The hex values defined in style.css under :root and [data-theme="light"]
// are tuned to match the M5GFX constants closely enough that the rendered
// output at panel-mount distance is indistinguishable from the hardware.
const colors = Object.freeze({
  TFT_BLACK:      'var(--panel-bg)',
  TFT_WHITE:      'var(--white)',
  TFT_GREEN:      'var(--green)',
  TFT_YELLOW:     'var(--yellow)',
  TFT_RED:        'var(--red)',
  TFT_GREY:       'var(--grey)',
  TFT_DARKGREY:   'var(--dark-grey)',
  TFT_LIGHTGREY:  'var(--light-grey)',
  TFT_CYAN:       'var(--sky)',
  TFT_BROWN:      'var(--ground)',
  TFT_MAGENTA:    'var(--magenta)',
  TFT_ORANGE:     'var(--orange)',
  TFT_BLUE:       'var(--blue)',
});

// === packages/ui-core/core/format.js ===
// Centralized number-formatter that kills negative zero.
//
// `Number(-0.001).toFixed(2)` returns "-0.00", which renders as "-0.0g"
// when concatenated with " G" or "g".  parseFloat("-0.00") === 0, so
// the guard tests the parsed result and re-formats with Math.abs() if
// it rounds to zero.  Returns "—" for non-finite inputs (undefined,
// null, NaN, Infinity) so callers don't have to repeat that ceremony.
function fmt(v, d) {
  if (v === undefined || v === null || Number.isNaN(v)) return '—';
  const n = Number(v);
  if (!Number.isFinite(n)) return '—';
  const s = n.toFixed(d);
  if (parseFloat(s) === 0) return Math.abs(n).toFixed(d);
  return s;
}

// Signed variant: prefixes a '+' for non-negative values and runs
// values that round to zero through `fmt` so '-0.0' never appears.
// '+0.0' is the canonical zero rendering.
function fmtSigned(v, d) {
  const base = fmt(v, d);
  if (base === '—') return base;
  return base.startsWith('-') ? base : '+' + base;
}

// === packages/ui-core/core/pct2y.js ===
// Port of mapPct2Display() from software/OnSpeed-M5-Display/src/main.cpp.
// Maps a percent-lift value (0.0..99.9) to a y-coordinate within the
// indexer widget (1..192).  The y-coordinate is in the M5's native
// 320×240 panel space; the SVG viewBox matches, so this y is also
// the SVG y.
//
// `anchors` is the same 8-element array the C++ uses (PctAnchors), where:
//   anchors[0] = 0  (alpha_0 floor; always zero in percent space)
//   anchors[2] = tonesOnPctLift   (operational; chevron + audio gate)
//   anchors[3] = onSpeedFastPctLift  (donut bottom edge)
//   anchors[4] = onSpeedSlowPctLift  (donut top edge / top-chevron lower gate)
//   anchors[6] = pipPctLift          (visual L/Dmax pip)
//   anchors[7] = stallWarnPctLift    (top-chevron flash threshold; color only)
// Slots 1 and 5 are unused.
//
// Y values: 192 = bottom of widget, 1 = top.  The upper ramp tops out
// at percent_lift = 99 — the lift-envelope ceiling — independent of
// the active detent's stall-warn percent.  Stall-warn drives chevron
// flash-red color logic in chevronColors(); it does not gate Y here.
//
// Two variants:
//   * `mapPct2Display` — returns a fractional y (no rounding).  Use
//     this for SVG, which renders fractional pixel coordinates with
//     subpixel anti-aliasing — the LiveView gets visibly smoother bar
//     motion than the M5 hardware (which has to round to integer
//     pixels because M5GFX::fillRect only accepts ints).
//   * `mapPct2DisplayInt` — returns the rounded y, matching the C++
//     M5 firmware's `mapPct2Display(int aoaPct, ...)` exactly.  Used
//     by the geometry-invariant tests and any M5-parity check.
function mapPct2Display(aoaPct, anchors) {
  if      (aoaPct <= anchors[0])                              return 192;
  else if (aoaPct >  anchors[0] && aoaPct <= anchors[3])      return mapFloat(aoaPct, anchors[0], anchors[3], 192, 115);
  else if (aoaPct >  anchors[3] && aoaPct <= anchors[4])      return mapFloat(aoaPct, anchors[3], anchors[4], 115,  78);
  else if (aoaPct >  anchors[4] && aoaPct <= 99)              return mapFloat(aoaPct, anchors[4], 99,          78,  1);
  else                                                         return 1;
}

function mapPct2DisplayInt(aoaPct, anchors) {
  const y = mapPct2Display(aoaPct, anchors);
  return Math.round(y);
}

// Linear interpolation. Returns a float; the caller decides whether
// to round (SVG benefits from fractional, M5GFX doesn't).
function mapFloat(x, inLow, inHigh, outLow, outHigh) {
  if (inHigh === inLow) return outLow;
  return (x - inLow) * (outHigh - outLow) / (inHigh - inLow) + outLow;
}

// === packages/ui-core/core/chevronColors.js ===

// Chevron color decisions for the M5 indexer.
// Returns { top, bottom } where each is one of TFT_DARKGREY / TFT_YELLOW /
// TFT_RED / TFT_GREEN.
//
// Both chevron halves on a row share the same color (same gate fires for
// both). Source: drawAOA() in main.cpp:905-1003.
function chevronColors({ percentLift, anchors, flashFlag }) {
  const onSpeedSlow = anchors[4];
  const stallWarn   = anchors[7];
  const tonesOn     = anchors[2];
  // Match M5's integer divide (main.cpp::drawAOA) so the yellow→red boundary
  // lines up bit-for-bit with the M5 hardware. For odd (stallWarn − onSpeedSlow)
  // spans the M5's int truncation puts the boundary 0.5% lower than a float
  // midpoint would; honor that.
  const chevMid     = onSpeedSlow + Math.floor((stallWarn - onSpeedSlow) / 2);

  // Top chevron — escalates yellow → red as AOA approaches stall.
  let top = colors.TFT_DARKGREY;
  if      (percentLift > onSpeedSlow && percentLift <= chevMid)   top = colors.TFT_YELLOW;
  else if (percentLift > chevMid     && percentLift <= stallWarn) top = colors.TFT_RED;
  else if (percentLift > stallWarn   && !flashFlag)               top = colors.TFT_RED;
  // else (above stallWarn AND flashing) → stays DARKGREY (the "off" half of the flash).

  // Bottom chevron — green when audio low tone is playing (in [tonesOn, onSpeedSlow)).
  let bottom = colors.TFT_DARKGREY;
  if (percentLift >= tonesOn && percentLift < onSpeedSlow) bottom = colors.TFT_GREEN;

  return { top, bottom };
}

// === packages/ui-core/core/donutColors.js ===

// Donut segment colors. Three independent segments per drawAOA() :1011-1031.
// Returns { topArc, bottomArc, dot }, each TFT_GREEN or TFT_DARKGREY.
//
// Range gates inside the OnSpeed band [fast, slow]:
//   bottom arc: [fast, fast + 0.75 × range]    — lower 75%
//   top arc:    [fast + 0.25 × range, slow]    — upper 75%
//   center dot: [fast + 0.25 × range, slow - 0.25 × range]  — middle 50%
// (range = slow - fast)
function donutColors({ percentLift, anchors }) {
  const fast = anchors[3];
  const slow = anchors[4];
  const range = slow - fast;

  // Degenerate band (no anchors yet, e.g. WebSocket connecting state
  // where every wire field is 0): the [fast, slow] window collapses to
  // a single point, and percentLift=0 ≥ 0 && ≤ 0 would otherwise paint
  // every segment green.  Stay grey until real anchors arrive.
  if (range <= 0) {
    return {
      topArc:    colors.TFT_DARKGREY,
      bottomArc: colors.TFT_DARKGREY,
      dot:       colors.TFT_DARKGREY,
    };
  }

  const bottomArc = (percentLift >= fast && percentLift <= fast + 0.75 * range)
    ? colors.TFT_GREEN : colors.TFT_DARKGREY;
  const topArc = (percentLift >= fast + 0.25 * range && percentLift <= slow)
    ? colors.TFT_GREEN : colors.TFT_DARKGREY;
  const dot = (percentLift >= fast + 0.25 * range && percentLift <= slow - 0.25 * range)
    ? colors.TFT_GREEN : colors.TFT_DARKGREY;

  return { topArc, bottomArc, dot };
}

// === packages/ui-core/core/slipBall.js ===


// JSON ships body-frame lateral G (positive = right); the slip ball
// wants ball-frame (positive = left), so negate.  Full physics +
// the parallel wire-format negation are documented at
// proto/DisplaySerial.h::DisplayBuildInputs::lateralG.
// Scale 850 = 34/0.04 (M5 SerialRead.cpp).  Clamped to ±99.
function slipFromLateralG(lateralG) {
  const v = Math.round(-lateralG * 850);
  return Math.max(-99, Math.min(99, v));
}

// Ball position (SVG cx) and fill color.
// Flash logic (drawSlip :1069-1071): when high-AOA AND high-slip, alternate
// between black and red with the chevron's flashFlag cadence.
function slipBall({ slip, percentLift, stallWarn, flashFlag }) {
  // Position: drawSlip() draws ball at CenterX + slipValue × (W-H-1) / 99 / 2.
  const cx = SLIP_CENTER_X + slip * SLIP_BALL_X_RANGE / 99;
  const cy = SLIP_CENTER_Y;

  let fill = colors.TFT_GREEN;
  if (Math.abs(slip) >= 30 && percentLift >= stallWarn) {
    fill = flashFlag ? colors.TFT_BLACK : colors.TFT_RED;
  }
  return { cx, cy, fill };
}

// === packages/ui-core/core/flapWidget.js ===
// Port of onspeed::gauges::FlapWidgetFrac from
// software/Libraries/onspeed_core/src/gauges/FlapWidgetMath.h.
//
// Maps a current flap deg (`flapPos`) and the configured min/max range
// to a fraction in [0, 1] suitable for visual widget arc sweep. Handles:
//   - Reflex flaps (negative `flapsMin`): clamp at 0 below min, at 1 above max.
//   - Degenerate `flapsMax <= flapsMin` (single-position aircraft or
//     misconfigured): return 0.5 so the widget parks mid-arc rather
//     than NaN-ing or pinning to an endpoint.
function flapWidgetFrac(flapPos, flapsMin, flapsMax) {
  const span = flapsMax - flapsMin;
  if (span <= 0) return 0.5;
  const fracRaw = (flapPos - flapsMin) / span;
  return Math.max(0, Math.min(1, fracRaw));
}

// Convert frac → SVG transform value for the rotating triangle.
// drawAOA() :797-:805 uses kFlapArcDeg = 40°, so frac × 40° is the angle.
function flapTriangleTransform(frac) {
  // SVG rotates clockwise about the circle center (FLAP_CX, FLAP_CY).
  // Caller composes the full transform; this just returns degrees.
  return frac * 40;
}

// === packages/ui-core/components/svg/index.js ===
// Shared Preact components for OnSpeed LiveView.
//
// Each component is a pure function of props. The five mode files in
// m5modes/ compose these components against a canonical M5State (see
// packages/ui-core/state-shape.js). Both the live firmware /indexer
// page and the docs-site /data-and-logs/replay/ render through the
// same m5modes/ family — see adapters/wsRecordToState.js for the
// live-page input shape conversion. Layout constants come from the
// framework-free helpers in ../../core/.










// Three ASCII dashes mark a 3-digit field with no live data — IAS is
// always a 3-digit display ("000" max), so one dash per missing digit.
// The percent-lift number uses two dashes to match its 2-digit field.
// Mirrors the M5 firmware's snprintf("---") / "--" choice.
const IAS_DASHES = '---';
const PCT_DASHES = '--';

// SVG arc path helper — circle arc from start to end angle (radians).
const arcPath = (cx, cy, r, startRad, endRad) => {
  const x1 = cx + r * Math.cos(startRad), y1 = cy + r * Math.sin(startRad);
  const x2 = cx + r * Math.cos(endRad),   y2 = cy + r * Math.sin(endRad);
  const large = (endRad - startRad) > Math.PI ? 1 : 0;
  return `M ${x1} ${y1} A ${r} ${r} 0 ${large} 1 ${x2} ${y2}`;
};

// Chevron half — rotated rect.
const Chevron = ({ cx, cy, signRad, fill }) => html`
  <rect x=${cx - __NS_packages_ui_core_core_geometry.CHEVRON_HALF_W} y=${cy - __NS_packages_ui_core_core_geometry.CHEVRON_HALF_H}
        width=${__NS_packages_ui_core_core_geometry.CHEVRON_HALF_W * 2} height=${__NS_packages_ui_core_core_geometry.CHEVRON_HALF_H * 2}
        transform="rotate(${signRad * 180 / Math.PI} ${cx} ${cy})"
        fill=${fill} shape-rendering="crispEdges" />`;

// AOA indexer: bounding rect + 4 chevrons + donut + index bar + L/Dmax pips.
// Index bar hidden when aoaIsValid is false (matches legacy /live's gate).
const Indexer = ({ percentLift, anchors, flashFlag, aoaIsValid }) => {
  const c = chevronColors({ percentLift, anchors, flashFlag });
  const d = donutColors({ percentLift, anchors });
  const indexY = mapPct2Display(percentLift, anchors);
  const ldmaxY = mapPct2Display(anchors[6], anchors);
  return html`
    <g data-widget="indexer">
      <rect x=${__NS_packages_ui_core_core_geometry.INDEXER_X} y=${__NS_packages_ui_core_core_geometry.INDEXER_Y}
            width=${__NS_packages_ui_core_core_geometry.INDEXER_WIDTH} height=${__NS_packages_ui_core_core_geometry.INDEXER_HEIGHT}
            rx=${__NS_packages_ui_core_core_geometry.INDEXER_BOX_RADIUS}
            fill="none" stroke=${colors.TFT_DARKGREY} stroke-width="2" />
      <${Chevron} cx=${__NS_packages_ui_core_core_geometry.CHEVRON_TOP_LEFT_CX}     cy=${__NS_packages_ui_core_core_geometry.CHEVRON_TOP_LEFT_CY}    signRad=${-__NS_packages_ui_core_core_geometry.CHEVRON_ROTATION_RAD} fill=${c.top} />
      <${Chevron} cx=${__NS_packages_ui_core_core_geometry.CHEVRON_TOP_RIGHT_CX}    cy=${__NS_packages_ui_core_core_geometry.CHEVRON_TOP_RIGHT_CY}   signRad=${__NS_packages_ui_core_core_geometry.CHEVRON_ROTATION_RAD}  fill=${c.top} />
      <${Chevron} cx=${__NS_packages_ui_core_core_geometry.CHEVRON_BOTTOM_LEFT_CX}  cy=${__NS_packages_ui_core_core_geometry.CHEVRON_BOTTOM_LEFT_CY} signRad=${__NS_packages_ui_core_core_geometry.CHEVRON_ROTATION_RAD}  fill=${c.bottom} />
      <${Chevron} cx=${__NS_packages_ui_core_core_geometry.CHEVRON_BOTTOM_RIGHT_CX} cy=${__NS_packages_ui_core_core_geometry.CHEVRON_BOTTOM_RIGHT_CY} signRad=${-__NS_packages_ui_core_core_geometry.CHEVRON_ROTATION_RAD} fill=${c.bottom} />
      <circle cx=${__NS_packages_ui_core_core_geometry.INDEXER_CX} cy=${__NS_packages_ui_core_core_geometry.INDEXER_CY} r=${__NS_packages_ui_core_core_geometry.DONUT_BLACK_R} fill=${colors.TFT_BLACK} />
      <path d=${arcPath(__NS_packages_ui_core_core_geometry.INDEXER_CX, __NS_packages_ui_core_core_geometry.INDEXER_CY, __NS_packages_ui_core_core_geometry.DONUT_ARC_R, 0, Math.PI)}
            fill="none" stroke=${d.bottomArc} stroke-width=${__NS_packages_ui_core_core_geometry.DONUT_ARC_LINEWIDTH} />
      <path d=${arcPath(__NS_packages_ui_core_core_geometry.INDEXER_CX, __NS_packages_ui_core_core_geometry.INDEXER_CY, __NS_packages_ui_core_core_geometry.DONUT_ARC_R, Math.PI, 2 * Math.PI)}
            fill="none" stroke=${d.topArc} stroke-width=${__NS_packages_ui_core_core_geometry.DONUT_ARC_LINEWIDTH} />
      <rect x=${__NS_packages_ui_core_core_geometry.DONUT_GAP_X} y=${__NS_packages_ui_core_core_geometry.DONUT_GAP_Y}
            width=${__NS_packages_ui_core_core_geometry.DONUT_GAP_W} height=${__NS_packages_ui_core_core_geometry.DONUT_GAP_H} fill=${colors.TFT_BLACK} />
      <circle cx=${__NS_packages_ui_core_core_geometry.INDEXER_CX} cy=${__NS_packages_ui_core_core_geometry.INDEXER_CY} r=${__NS_packages_ui_core_core_geometry.DONUT_DOT_R} fill=${d.dot} />
      ${aoaIsValid && html`
        <rect x=${__NS_packages_ui_core_core_geometry.INDEX_BAR_X} y=${indexY}
              width=${__NS_packages_ui_core_core_geometry.INDEX_BAR_W} height=${__NS_packages_ui_core_core_geometry.INDEX_BAR_H}
              fill=${colors.TFT_WHITE} stroke=${colors.TFT_BLACK}
              stroke-width="1" shape-rendering="crispEdges" />`}
      <circle cx=${__NS_packages_ui_core_core_geometry.PIP_LEFT_CX}  cy=${ldmaxY} r=${__NS_packages_ui_core_core_geometry.PIP_HALO_R}  fill=${colors.TFT_BLACK} />
      <circle cx=${__NS_packages_ui_core_core_geometry.PIP_LEFT_CX}  cy=${ldmaxY} r=${__NS_packages_ui_core_core_geometry.PIP_INNER_R} fill=${colors.TFT_WHITE} />
      <circle cx=${__NS_packages_ui_core_core_geometry.PIP_RIGHT_CX} cy=${ldmaxY} r=${__NS_packages_ui_core_core_geometry.PIP_HALO_R}  fill=${colors.TFT_BLACK} />
      <circle cx=${__NS_packages_ui_core_core_geometry.PIP_RIGHT_CX} cy=${ldmaxY} r=${__NS_packages_ui_core_core_geometry.PIP_INNER_R} fill=${colors.TFT_WHITE} />
    </g>`;
};

const PercentLiftNumber = ({ percent, aoaIsValid }) => {
  // Truncate (NOT round) and clamp to [0, 99] so the digit stays in
  // lockstep with the chevron color comparisons, which use the raw
  // float percent against integer anchors (e.g. `percent >= tonesOn`
  // flips at exactly percent == 33, not at percent == 32.5).  Match
  // the M5 firmware's `displayPercentLift` snapshot in main.cpp.
  // The 99-clamp also keeps a saturated 99.9 from rendering as "100".
  // When AOA validity is false, render two ASCII dashes centered on
  // the same anchor — same convention as the M5 firmware in main.cpp.
  let s;
  if (!aoaIsValid) {
    s = PCT_DASHES;
  } else {
    const truncated = Math.min(99, Math.max(0, Math.trunc(percent)));
    s = String(truncated).padStart(2, '0');
  }
  return html`
    <g data-widget="percent-lift-number">
      <text x=${__NS_packages_ui_core_core_geometry.PCT_LIFT_X} y=${__NS_packages_ui_core_core_geometry.PCT_LIFT_Y}
            font-family="Helvetica, Arial, sans-serif" font-weight="bold"
            font-size=${__NS_packages_ui_core_core_geometry.PCT_LIFT_FONT_SIZE} fill="none"
            stroke=${colors.TFT_BLACK} stroke-width=${__NS_packages_ui_core_core_geometry.PCT_LIFT_OUTLINE_PX * 2}
            stroke-linejoin="round" text-anchor="middle">${s}</text>
      <text x=${__NS_packages_ui_core_core_geometry.PCT_LIFT_X} y=${__NS_packages_ui_core_core_geometry.PCT_LIFT_Y}
            font-family="Helvetica, Arial, sans-serif" font-weight="bold"
            font-size=${__NS_packages_ui_core_core_geometry.PCT_LIFT_FONT_SIZE} fill=${colors.TFT_WHITE}
            text-anchor="middle">${s}</text>
    </g>`;
};

// CornerReadout renders a label + value stacked vertically.  When
// `value` is the dashes placeholder (`IAS_DASHES` / `PCT_DASHES`) and
// `anchor` is "start" (left-side readout), the dashes right-align to
// the right edge of the label above so the placeholder visually sits
// under the label rather than the live-digit column.  Right-anchored
// readouts already share the label's right edge by construction, so
// no measurement is needed there.
const CornerReadout = ({ label, value,
                                 labelX, labelY, numX, numY,
                                 anchor = 'start',
                                 labelColor = colors.TFT_GREEN,
                                 numColor = colors.TFT_WHITE,
                                 labelFontSize = __NS_packages_ui_core_core_geometry.CORNER_LABEL_FONT_SIZE,
                                 numFontSize = __NS_packages_ui_core_core_geometry.CORNER_NUM_FONT_SIZE,
                                 numBaseline = 'alphabetic' }) => {
  const isDashes = (value === IAS_DASHES || value === PCT_DASHES);
  const alignDashesToLabel = isDashes && anchor === 'start';

  // Measure the label's rendered width so dashes can right-align to
  // its right edge.  Re-measures whenever the label string or font
  // size changes.  No-op for non-dashes paths.
  const labelRef = useRef(null);
  const [labelWidth, setLabelWidth] = useState(null);
  useLayoutEffect(() => {
    if (!alignDashesToLabel) return;
    const el = labelRef.current;
    if (el && typeof el.getComputedTextLength === 'function') {
      setLabelWidth(el.getComputedTextLength());
    }
  }, [label, labelFontSize, alignDashesToLabel]);

  // getComputedTextLength returns the advance width, which includes
  // the trailing side-bearing past the visible right edge of the last
  // glyph (e.g. the 'S' in "IAS").  Pull the right edge in by ~10% of
  // the label font size so the rightmost dash visually lines up with
  // the last glyph's stroke instead of the advance-width column.
  const DASH_RIGHT_NUDGE_FRAC = 0.1;
  const valueAnchor = alignDashesToLabel ? 'end' : anchor;
  // Right-anchored dashes (e.g. Kt/s on Mode 3) sit one px past the
  // live-digit column without an explicit nudge, since textWidth's
  // trailing bearing puts the rightmost hyphen tip slightly outside
  // the right anchor.  Pull in 1 px to land cleanly under the label.
  const rightDashNudge = (isDashes && anchor === 'end') ? 1 : 0;
  const valueX      = alignDashesToLabel && labelWidth != null
                      ? labelX + labelWidth - DASH_RIGHT_NUDGE_FRAC * labelFontSize
                      : numX - rightDashNudge;

  return html`
  <g data-widget="corner">
    <text ref=${labelRef} x=${labelX} y=${labelY}
          font-family="Helvetica, Arial, sans-serif"
          font-size=${labelFontSize} fill=${labelColor}
          text-anchor=${anchor}>${label}</text>
    <text x=${valueX} y=${numY}
          font-family="Helvetica, Arial, sans-serif" font-weight="bold"
          font-size=${numFontSize} fill=${numColor}
          text-anchor=${valueAnchor} dominant-baseline=${numBaseline}>${value}</text>
  </g>`;
};

// DataMark counter readout — top-left, modes 0 + 2. The wire field is
// already mod-100 from the firmware (Switch.cpp long-press → offset 69
// in the display frame), so a 2-digit zero-padded format mirrors the
// M5's `printf("%02d", DataMark)`.
const DataMark = ({ value }) => {
  const v = (value == null || Number.isNaN(value)) ? 0 : value;
  const padded = String(v).padStart(2, '0');
  return html`
    <text x=${__NS_packages_ui_core_core_geometry.DATAMARK_X} y=${__NS_packages_ui_core_core_geometry.DATAMARK_Y}
          font-family="Helvetica, Arial, sans-serif"
          font-size=${__NS_packages_ui_core_core_geometry.DATAMARK_FONT_SIZE}
          fill=${colors.TFT_WHITE}>${padded}</text>`;
};

const FlapCircle = ({ flapPos, flapsMin, flapsMax }) => {
  const frac = flapWidgetFrac(flapPos, flapsMin, flapsMax);
  const a = flapTriangleTransform(frac) * Math.PI / 180;
  const apexX = __NS_packages_ui_core_core_geometry.FLAP_CX + Math.cos(a) * __NS_packages_ui_core_core_geometry.FLAP_TRIANGLE_TIP_R;
  const apexY = __NS_packages_ui_core_core_geometry.FLAP_CY + Math.sin(a) * __NS_packages_ui_core_core_geometry.FLAP_TRIANGLE_TIP_R;
  const topX  = __NS_packages_ui_core_core_geometry.FLAP_CX + Math.sin(a) * __NS_packages_ui_core_core_geometry.FLAP_R;
  const topY  = __NS_packages_ui_core_core_geometry.FLAP_CY - Math.cos(a) * __NS_packages_ui_core_core_geometry.FLAP_R;
  const botX  = __NS_packages_ui_core_core_geometry.FLAP_CX - Math.sin(a) * __NS_packages_ui_core_core_geometry.FLAP_R;
  const botY  = __NS_packages_ui_core_core_geometry.FLAP_CY + Math.cos(a) * __NS_packages_ui_core_core_geometry.FLAP_R;
  return html`
    <g data-widget="flap-circle">
      <circle cx=${__NS_packages_ui_core_core_geometry.FLAP_CX} cy=${__NS_packages_ui_core_core_geometry.FLAP_CY} r=${__NS_packages_ui_core_core_geometry.FLAP_R} fill=${colors.TFT_DARKGREY} />
      <path fill=${colors.TFT_DARKGREY} shape-rendering="crispEdges"
            d="M ${topX} ${topY} L ${apexX} ${apexY} L ${botX} ${botY} Z" />
      <circle cx=${__NS_packages_ui_core_core_geometry.FLAP_CX + __NS_packages_ui_core_core_geometry.FLAP_STOP_R} cy=${__NS_packages_ui_core_core_geometry.FLAP_CY}
              r="1" fill=${colors.TFT_WHITE} />
      <circle cx=${__NS_packages_ui_core_core_geometry.FLAP_CX + Math.cos(__NS_packages_ui_core_core_geometry.FLAP_ARC_RAD) * __NS_packages_ui_core_core_geometry.FLAP_STOP_R}
              cy=${__NS_packages_ui_core_core_geometry.FLAP_CY + Math.sin(__NS_packages_ui_core_core_geometry.FLAP_ARC_RAD) * __NS_packages_ui_core_core_geometry.FLAP_STOP_R}
              r="1" fill=${colors.TFT_WHITE} />
      <text x=${__NS_packages_ui_core_core_geometry.FLAP_CX} y=${__NS_packages_ui_core_core_geometry.FLAP_CY}
            font-family="Helvetica, Arial, sans-serif"
            font-size=${__NS_packages_ui_core_core_geometry.FLAP_LABEL_FONT_SIZE} fill=${colors.TFT_WHITE}
            text-anchor="middle" dominant-baseline="central">${flapPos ?? '—'}</text>
    </g>`;
};

// Slip ball — left/right frame brackets + ball.
// drawSlip() at main.cpp:1048-1077 draws each bracket as a 10-px-wide
// black bar + a 6-px-wide white inner bar, both spanning the full
// slip-ball height. The brackets sit ±h/2 from the slip-ball
// centerline, with the inner WHITE bar offset 2 px inward of the
// outer BLACK bar. Mode 0 calls drawSlip(80, 204, 160, 34) — wide
// frame; Mode 1/3 call drawSlip(80, 204|215, 160, 20) — same widths,
// shorter height.
//
// Frame geometry (from main.cpp:1048-1057):
//   black left bracket : x = cx - h/2 - 9, width 10
//   white left bracket : x = cx - h/2 - 7, width 6
//   black right bracket: x = cx + h/2,     width 10
//   white right bracket: x = cx + h/2 + 2, width 6
const SLIP_FRAME_OUTER_W = 10;
const SLIP_FRAME_INNER_W = 6;
const SLIP_FRAME_OUTER_OFFSET = 9;  // outer-edge offset from h/2
const SLIP_FRAME_INNER_OFFSET = 7;  // inner-edge offset from h/2
const SLIP_FRAME_RIGHT_GAP = 2;     // right-side white-bar gap from h/2

const SlipBall = ({ lateralG, percentLift, stallWarn, flashFlag,
                            x = __NS_packages_ui_core_core_geometry.SLIP_X, y = __NS_packages_ui_core_core_geometry.SLIP_Y,
                            width = __NS_packages_ui_core_core_geometry.SLIP_W, height = __NS_packages_ui_core_core_geometry.SLIP_H }) => {
  const slip = slipFromLateralG(lateralG);
  // Per drawSlip() main.cpp:1064-1071: ball.cx = centerX +
  // slip * (W - H - 1) / 99 / 2. Range gates and color follow the
  // chevron's flashFlag for high-AOA + high-slip stall warning.
  const cx = x + width / 2 + slip * (width - height - 1) / 99 / 2;
  const cy = y + height / 2;
  const r = height / 2 - 1;
  let fill = colors.TFT_GREEN;
  if (Math.abs(slip) >= 30 && percentLift >= stallWarn) {
    fill = flashFlag ? colors.TFT_BLACK : colors.TFT_RED;
  }
  const cxMid = x + width / 2;
  return html`
    <g data-widget="slip">
      <rect x=${cxMid - height/2 - SLIP_FRAME_OUTER_OFFSET} y=${y}
            width=${SLIP_FRAME_OUTER_W} height=${height} fill=${colors.TFT_BLACK} />
      <rect x=${cxMid - height/2 - SLIP_FRAME_INNER_OFFSET} y=${y}
            width=${SLIP_FRAME_INNER_W} height=${height} fill=${colors.TFT_WHITE} />
      <rect x=${cxMid + height/2} y=${y}
            width=${SLIP_FRAME_OUTER_W} height=${height} fill=${colors.TFT_BLACK} />
      <rect x=${cxMid + height/2 + SLIP_FRAME_RIGHT_GAP} y=${y}
            width=${SLIP_FRAME_INNER_W} height=${height} fill=${colors.TFT_WHITE} />
      <circle cx=${cx} cy=${cy} r=${r} fill=${fill} />
    </g>`;
};

// Right-edge tape — bar grows up/down from zeroY by `value * heightScale`.
// Used by Mode 0 (gOnset, yellow) and Modes 1/3 (VSI, white).
const EdgeTape = ({
  value,
  barX = __NS_packages_ui_core_core_geometry.GONSET_BAR_X, barW = __NS_packages_ui_core_core_geometry.GONSET_BAR_W,
  barColor = colors.TFT_YELLOW,
  zeroY = __NS_packages_ui_core_core_geometry.GONSET_ZERO_Y,
  heightScale = __NS_packages_ui_core_core_geometry.GONSET_HEIGHT_SCALE,
  heightMax = __NS_packages_ui_core_core_geometry.GONSET_HEIGHT_MAX,
  tickX1 = __NS_packages_ui_core_core_geometry.GONSET_TICK_X1, tickX2 = __NS_packages_ui_core_core_geometry.GONSET_TICK_X2,
  tickFirstY = __NS_packages_ui_core_core_geometry.GONSET_TICK_FIRST_Y,
  tickLastY = __NS_packages_ui_core_core_geometry.GONSET_TICK_LAST_Y,
  tickStep = __NS_packages_ui_core_core_geometry.GONSET_TICK_STEP,
  pipX1 = __NS_packages_ui_core_core_geometry.GONSET_PIP_X1, pipX2 = __NS_packages_ui_core_core_geometry.GONSET_PIP_X2,
  pipYs = [__NS_packages_ui_core_core_geometry.GONSET_PIP_Y_TOP, __NS_packages_ui_core_core_geometry.GONSET_PIP_Y_MIDDLE, __NS_packages_ui_core_core_geometry.GONSET_PIP_Y_BOT],
  tickColor = colors.TFT_GREY, pipColor = colors.TFT_GREY,
}) => {
  const h = Math.min(heightMax, Math.abs(value * heightScale));
  const top = value > 0 ? zeroY - h : zeroY;
  const ticks = [];
  for (let y = tickFirstY; y <= tickLastY; y += tickStep) {
    ticks.push(html`<line x1=${tickX1} y1=${y} x2=${tickX2} y2=${y}
                          stroke=${tickColor} stroke-width="1" />`);
  }
  return html`
    <g data-widget="edge-tape">
      <rect x=${barX} y=${top} width=${barW} height=${h} fill=${barColor} />
      ${ticks}
      ${pipYs.map(y => html`
        <line x1=${pipX1} y1=${y} x2=${pipX2} y2=${y}
              stroke=${pipColor} stroke-width="1" />`)}
    </g>`;
};

// Mode 1 horizon — sky/ground polygon driven by pitch+roll. Mirrors
// AiGraph() at main.cpp:1085-1122. Sky is a full-panel cyan rect,
// ground is a wide rotated polygon whose top edge is the horizon line.
const HALF_PI = Math.PI / 2;
const Horizon = ({ pitchDeg, rollDeg }) => {
  const cx = __NS_packages_ui_core_core_geometry.MODE1_HORIZON_CX, cy = __NS_packages_ui_core_core_geometry.MODE1_HORIZON_CY;
  const panelW = __NS_packages_ui_core_core_geometry.M5_PANEL_W, panelH = __NS_packages_ui_core_core_geometry.M5_PANEL_H;
  const r = rollDeg * Math.PI / 180;
  const sinR = Math.sin(r), cosR = Math.cos(r);
  const pxc = cx + pitchDeg * __NS_packages_ui_core_core_geometry.MODE1_PITCH_HEIGHT_SCALE * sinR;
  const pyc = cy + pitchDeg * __NS_packages_ui_core_core_geometry.MODE1_PITCH_HEIGHT_SCALE * cosR;
  const xRot = 2 * panelW * cosR, yRot = 2 * panelW * sinR;
  const px1 = pxc - xRot, py1 = pyc + yRot;
  const px2 = pxc + xRot, py2 = pyc - yRot;
  const px3 = px1 + 3 * panelH * Math.cos( r - HALF_PI);
  const py3 = py1 - 3 * panelH * Math.sin(-r - HALF_PI);
  const px4 = px2 - 3 * panelH * Math.cos( r + HALF_PI);
  const py4 = py2 + 3 * panelH * Math.sin( r + HALF_PI);
  return html`
    <g data-widget="horizon">
      <rect x="0" y="0" width=${panelW} height=${panelH} fill=${colors.TFT_CYAN} />
      <polygon points="${px1},${py1} ${px2},${py2} ${px4},${py4} ${px3},${py3}"
               fill=${colors.TFT_BROWN} />
      <line x1=${px1} y1=${py1} x2=${px2} y2=${py2}
            stroke=${colors.TFT_BLACK} stroke-width="1" />
      <line x1=${px3} y1=${py3} x2=${px4} y2=${py4}
            stroke=${colors.TFT_BLUE} stroke-width="1" />
      <circle cx=${pxc} cy=${pyc} r="3" fill=${colors.TFT_BLACK} />
    </g>`;
};

// Mode 1 pitch ladder — tick marks every 10° from -90..+90 plus numeric
// labels on the long ticks. Mirrors pitchGraph() at main.cpp:1284-1345.
// Two passes: short ticks at half-width 0.10×g_arcSize, long ticks at
// half-width 0.20×g_arcSize plus numeric labels offset along the
// rolled axis.
const PitchLadder = ({ pitchDeg, rollDeg }) => {
  const cx = __NS_packages_ui_core_core_geometry.MODE1_HORIZON_CX, cy = __NS_packages_ui_core_core_geometry.MODE1_HORIZON_CY;
  const pitchScale = __NS_packages_ui_core_core_geometry.MODE1_PITCH_HEIGHT_SCALE;
  const r = rollDeg * Math.PI / 180;
  const sinR = Math.sin(r), cosR = Math.cos(r);
  const pxc = cx + pitchDeg * pitchScale * sinR;
  const pyc = cy + pitchDeg * pitchScale * cosR;

  const tick = (i, halfW) => {
    const ax = pxc - i * pitchScale * sinR;
    const ay = pyc - i * pitchScale * cosR;
    const dx = halfW * cosR, dy = halfW * sinR;
    return html`<line x1=${ax - dx} y1=${ay + dy} x2=${ax + dx} y2=${ay - dy}
                       stroke=${colors.TFT_BLACK} stroke-width="1" />`;
  };
  const label = (i) => {
    const ax = pxc - i * pitchScale * sinR;
    const ay = pyc - i * pitchScale * cosR;
    const lx = ax + (__NS_packages_ui_core_core_geometry.MODE1_LADDER_LONG_HALF_W + __NS_packages_ui_core_core_geometry.MODE1_LADDER_LABEL_OFFSET) * cosR;
    const ly = ay - (__NS_packages_ui_core_core_geometry.MODE1_LADDER_LONG_HALF_W + __NS_packages_ui_core_core_geometry.MODE1_LADDER_LABEL_OFFSET) * sinR;
    return html`<text x=${lx} y=${ly}
                       font-family="'B612', 'Helvetica Neue', Arial, sans-serif"
                       font-size=${__NS_packages_ui_core_core_geometry.MODE1_LADDER_FONT_SIZE} fill=${colors.TFT_BLACK}
                       text-anchor="start" dominant-baseline="central">${i}°</text>`;
  };

  const shorts = [];
  for (let i = -__NS_packages_ui_core_core_geometry.MODE1_LADDER_SHORT_RANGE; i <= __NS_packages_ui_core_core_geometry.MODE1_LADDER_SHORT_RANGE; i += __NS_packages_ui_core_core_geometry.MODE1_LADDER_STEP_DEG) {
    shorts.push(tick(i, __NS_packages_ui_core_core_geometry.MODE1_LADDER_SHORT_HALF_W));
  }
  const longs = [];
  for (let i = -__NS_packages_ui_core_core_geometry.MODE1_LADDER_LONG_RANGE; i <= __NS_packages_ui_core_core_geometry.MODE1_LADDER_LONG_RANGE; i += __NS_packages_ui_core_core_geometry.MODE1_LADDER_STEP_DEG) {
    longs.push(tick(i, __NS_packages_ui_core_core_geometry.MODE1_LADDER_LONG_HALF_W));
    longs.push(label(i));
  }
  return html`<g data-widget="pitch-ladder">${shorts}${longs}</g>`;
};

// Mode 1 bank arc — long bars at every 30°, short bars at ±10°/±20°,
// dots at ±45°, yellow ARROW_OUT pointer at top (rotates with -roll).
const BankArc = ({ rollDeg }) => {
  const cx = __NS_packages_ui_core_core_geometry.MODE1_HORIZON_CX, cy = __NS_packages_ui_core_core_geometry.MODE1_HORIZON_CY;
  const ARC_R = 115, ARC_W = 15;
  const LONG_INNER = ARC_R - 1.25 * ARC_W, LONG_OUTER = ARC_R + 0.25 * ARC_W, LONG_THICK = 0.25 * ARC_W;
  const SHORT_INNER = ARC_R - 0.875 * ARC_W, SHORT_OUTER = ARC_R - 0.125 * ARC_W, SHORT_THICK = 0.24 * ARC_W;
  const DEG = Math.PI / 180;
  const BAR_EDGE = '#9f9f9f';

  const radialBar = (deg, innerR, outerR, thickness, edge = BAR_EDGE) => {
    const a = deg * DEG;
    const cosA = Math.cos(a), sinA = Math.sin(a);
    const half = (thickness - 1.75) / 2;
    const ix = cx + innerR * cosA, iy = cy + innerR * sinA;
    const ox = cx + outerR * cosA, oy = cy + outerR * sinA;
    const ilx = ix + half *  sinA, ily = iy + half * -cosA;
    const olx = ox + half *  sinA, oly = oy + half * -cosA;
    const orx = ox + half * -sinA, ory = oy + half *  cosA;
    const irx = ix + half * -sinA, iry = iy + half *  cosA;
    return html`<polygon points="${ilx},${ily} ${olx},${oly} ${orx},${ory} ${irx},${iry}"
                          fill=${colors.TFT_WHITE} stroke=${edge} stroke-width="1"
                          stroke-linejoin="miter" shape-rendering="crispEdges" />`;
  };
  const dot = (deg) => {
    const a = deg * DEG;
    const r = ARC_R - 0.5 * ARC_W;
    return html`<circle cx=${cx + r * Math.cos(a)} cy=${cy + r * Math.sin(a)}
                         r=${0.25 * ARC_W} fill=${colors.TFT_WHITE}
                         stroke=${colors.TFT_BLACK} stroke-width="1" />`;
  };
  const arrow = (deg, color) => {
    const a = deg * DEG;
    const tipR = ARC_R - 0.5 * ARC_W;
    const baseR = ARC_R + 0.5 * ARC_W;
    const half = 0.33 * ARC_W;
    const cosA = Math.cos(a), sinA = Math.sin(a);
    const p4x = cx + tipR  * cosA, p4y = cy + tipR  * sinA;
    const p1x = cx + baseR * cosA, p1y = cy + baseR * sinA;
    const p2x = p1x + half *  sinA, p2y = p1y + half * -cosA;
    const p3x = p1x + half * -sinA, p3y = p1y + half *  cosA;
    return html`<polygon points="${p4x},${p4y} ${p3x},${p3y} ${p2x},${p2y}"
                          fill=${color} stroke=${colors.TFT_BLACK} stroke-width="1"
                          stroke-linejoin="miter" />`;
  };

  return html`
    <g data-widget="bank-arc" transform="rotate(${-rollDeg} ${cx} ${cy})">
      ${[0, 180, 210, 240, 300, 330].map(d => radialBar(d, LONG_INNER, LONG_OUTER, LONG_THICK))}
      ${arrow(270, colors.TFT_YELLOW)}
      ${[250, 260, 280, 290].map(d => radialBar(d, SHORT_INNER, SHORT_OUTER, SHORT_THICK))}
      ${[225, 315].map(d => dot(d))}
    </g>`;
};

// Mode 1 static aircraft reference symbol — yellow chevron with droops.
