// M5-style stale-data overlay: red X across panel + black "NO DATA" pill.
// Mounted last on each mode SVG so it paints on top when visible.
//
// Each diagonal is built from a band of 9 parallel 1px lines (offset
// -4..+4) so the X reads as a thick stroke without relying on
// stroke-width which would foreshorten near the corners.  The previous
// implementation moved only one endpoint of the bottom-left → top-right
// diagonal per offset, fanning the band out from the corners and
// rendering visibly thinner than its mirror; both diagonals now offset
// both endpoints symmetrically for a uniform-thickness X.
const StaleOverlay = ({ stale }) => {
  if (!stale) return null;
  const lines = [];
  for (let off = -4; off <= 4; ++off) {
    // Top-left → bottom-right diagonal.  Positive off shifts the band
    // down-right, negative shifts up-left.
    const tlbr_pos = Math.max(0, off);
    const tlbr_neg = -Math.min(0, off);
    lines.push(html`
      <line x1=${tlbr_pos}       y1=${tlbr_neg}
            x2=${319 - tlbr_neg} y2=${239 - tlbr_pos}
            stroke=${colors.TFT_RED} stroke-width="1" />`);
    // Top-right → bottom-left diagonal.  Mirror of the above so the
    // band has matching thickness.
    lines.push(html`
      <line x1=${319 - tlbr_pos} y1=${tlbr_neg}
            x2=${tlbr_neg}       y2=${239 - tlbr_pos}
            stroke=${colors.TFT_RED} stroke-width="1" />`);
  }
  return html`
    <g data-widget="stale-overlay">
      <rect x="0" y="0" width="320" height="240" fill=${colors.TFT_BLACK} />
      ${lines}
      <rect x="100" y="100" width="120" height="40" fill=${colors.TFT_BLACK} />
      <text x="160" y="120"
            font-family="Helvetica, Arial, sans-serif" font-weight="bold"
            font-size="24" fill=${colors.TFT_WHITE}
            text-anchor="middle" dominant-baseline="central">NO DATA</text>
    </g>`;
};

// === packages/ui-core/components/svg/m5modes/helpers.js ===
// helpers.js — formatters shared across the M5-mode SVG renderers.
//
// Each mode component (Energy/Attitude/Indexer/Decel/HistoricG) needs
// the same handful of small helpers — IAS dashes, padded altitude,
// flash cadence. These live here rather than per-component so the
// bundler doesn't see duplicate top-level identifiers across the
// m5modes/ files.


// 4 Hz visual flash (same cadence the M5 firmware uses for indexer
// color toggles). Reads the wall clock — the M5 panel does too — so
// the JS-side flash and the M5's flash run roughly in phase as long
// as JS hasn't been backgrounded.
const m5FlashFlagNow = () =>
  (Math.floor(performance.now() / 250) % 2) === 1;

// IAS placeholder when invalid: 3 dashes, matching the firmware's
// `snprintf("---")` for the 3-digit IAS field.
const m5FmtIasKt = (v, valid) => {
  if (!valid) return IAS_DASHES;
  if (v === undefined || v === null || Number.isNaN(v)) return IAS_DASHES;
  const n = Number(v);
  if (!Number.isFinite(n)) return IAS_DASHES;
  return n.toFixed(0);
};

// 5-digit space-padded altitude (e.g. "  500", "12345"). Matches the
// firmware's `snprintf("%5.0f", displayPalt)`.
const m5FmtPalt = (v) => {
  if (v === undefined || v === null || Number.isNaN(v)) return '—';
  return String(Math.round(v)).padStart(5, ' ');
};

// === packages/ui-core/components/svg/m5modes/EnergyMode.js ===
// EnergyMode.js — Mode 0 renderer driven by M5 firmware sim state.
//
// PR 2 of Project B2. The M5 firmware (compiled to WASM) decides what
// numbers to display; this component just lays them out as SVG. There
// is no rendering math here beyond "read M5 state var, position SVG
// element."
//
// State source: `state` is the frozen object returned by
// `tools/web/lib/replay/m5sim/m5sim.js::M5Sim.read()`. Every value
// reflects the firmware's own snapshots:
//   - displayIAS / displayPalt / displayPercentLift / displayVerticalG
//     update every 500 ms (matches the M5 panel's text cadence).
//   - PercentLift / Slip / gOnsetRate / FlapPos update on each wire
//     frame (~20 Hz) — these drive the indexer/ball/edge-tape geometry.
//   - The anchor pcts (TonesOnPctLift, OnSpeedFastPctLift, etc.) are
//     wire-derived and update with each frame; the indexer maps
//     PercentLift through these anchors.
//
// SlipBall accepts body-frame lateralG directly (positive = airframe
// accelerating rightward). state.LateralG flows from the wire frame
// via m5sim.read() and is optionally smoothed by renderSmooth() before
// reaching here. SlipBall internally maps lateralG to a clamped slip
// integer for ball positioning — clamping at the rendering site means
// the upstream PresentationFilter can smooth in continuous-G space at
// all magnitudes without a saturation dead-zone.







// Build the per-frame anchors array the existing Indexer expects.
//
// Layout: [0, 0, tonesOn, fastOnSpd, slowOnSpd, 0, pip, stallWarn].
// Mirrors the M5 firmware's main.cpp anchor packing for displayAOA().
const anchorsFromState = (state) => [
  0, 0,
  state.TonesOnPctLift,
  state.OnSpeedFastPctLift,
  state.OnSpeedSlowPctLift,
  0,
  state.PipPctLift,
  state.StallWarnPctLift,
];

// EnergyMode (Mode 0) — indexer + corners + flap + slip + edge tape +
// percent number + datamark.
//
// numericDisplay gates the "outer numerics" — corners, flap circle. With
// it false, the renderer matches Mode 2 (indexer-only). The pattern
// mirrors main.cpp:701-708 / 842-851 where the same `displayAOA()`
// produces both modes via the `numericDisplay` flag.
const EnergyMode = ({ state, stale = false, numericDisplay = true }) => {
  const flashFlag = m5FlashFlagNow();
  const aoaIsValid = state.IasIsValid !== false;
  const anchors = anchorsFromState(state);

  // PercentLift digit comes from `displayPercentLift` (the firmware's
  // 500 ms snapshot); chevron color comparisons use `PercentLift`
  // (every-frame). This matches the M5 panel's behavior — the digit
  // updates twice a second while the chevrons track the wire rate.
  // PercentLiftNumber accepts a percent that it truncates internally.

  return html`
    <svg viewBox="0 0 ${__NS_packages_ui_core_core_geometry.M5_PANEL_W} ${__NS_packages_ui_core_core_geometry.M5_PANEL_H}"
         xmlns="http://www.w3.org/2000/svg"
         style="background: ${colors.TFT_BLACK}; width: 100%; height: 100%;">
      <${Indexer} percentLift=${state.PercentLift} anchors=${anchors}
                  flashFlag=${flashFlag} aoaIsValid=${aoaIsValid} />
      ${numericDisplay && html`
        <${CornerReadout} label="IAS"
            value=${m5FmtIasKt(state.displayIAS, aoaIsValid)}
            labelX=${__NS_packages_ui_core_core_geometry.CORNER_LEFT_X} labelY=${__NS_packages_ui_core_core_geometry.CORNER_LABEL_Y}
            numX=${__NS_packages_ui_core_core_geometry.CORNER_LEFT_X + 2} numY=${__NS_packages_ui_core_core_geometry.CORNER_NUM_Y} />
        <${CornerReadout} label="G"
            value=${fmtSigned(state.displayVerticalG, 1)}
            labelX=${__NS_packages_ui_core_core_geometry.CORNER_RIGHT_X} labelY=${__NS_packages_ui_core_core_geometry.CORNER_LABEL_Y}
            numX=${__NS_packages_ui_core_core_geometry.CORNER_RIGHT_X} numY=${__NS_packages_ui_core_core_geometry.CORNER_NUM_Y} anchor="end" />
        <${FlapCircle} flapPos=${state.FlapPos}
            flapsMin=${state.FlapsMinDeg} flapsMax=${state.FlapsMaxDeg} />`}
      <${SlipBall} lateralG=${state.LateralG}
                   percentLift=${state.PercentLift}
                   stallWarn=${state.StallWarnPctLift}
                   flashFlag=${flashFlag} />
      <${EdgeTape} value=${state.gOnsetRate} />
      <${PercentLiftNumber} percent=${state.displayPercentLift}
                            aoaIsValid=${aoaIsValid} />
      <${DataMark} value=${state.DataMark} />
    </svg>`;
};

