  const [exportingClipIdx, setExportingClipIdx] = useState(null);
  const [mp4ExportProgress, setMp4ExportProgress] = useState(0);
  const [mp4ExportLabel, setMp4ExportLabel] = useState('');
  const mp4AbortRef = useRef(null);
